                            value={cs.percentage}
                            className="h-2"
                            style={
                              {
                                "--progress-background": category.color,
                              } as React.CSSProperties
                            }
                          />
                          <div className="flex justify-between text-xs text-gray-400">
                            <span>
                              ${(cs.totalAmount / cs.transactionCount).toFixed(2)} avg/txn
                            </span>
                            <span>of total budget</span>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  );
                })}
            </div>
          )}
        </div>

        {/* Top Spending Day */}
        {dailySpending.length > 0 && (
          <Card className="border-0 shadow-sm bg-amber-50 border-amber-100">
            <CardContent className="p-4">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-amber-100 flex items-center justify-center text-lg">
                  📅
                </div>
                <div className="flex-1">
                  <p className="text-sm font-semibold text-amber-900">Peak Spending Day</p>
                  <p className="text-xs text-amber-700 mt-0.5">
                    {(() => {
                      const peak = [...dailySpending].sort(
                        (a, b) => b.totalAmount - a.totalAmount
                      )[0];
                      return `${new Date(peak.date).toLocaleDateString("en-US", {
                        weekday: "long",
                        month: "short",
                        day: "numeric",
                      })} — $${peak.totalAmount.toFixed(2)} across ${peak.transactionCount} transactions`;
                    })()}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Footer spacing */}
        <div className="h-4" />
      </div>
    </div>
  );
};

export default SpendingInsightsPage;
