function getTrendIcon(current: number, previous: number): { icon: string; label: string; positive: boolean } {
  const diff = ((current - previous) / previous) * 100;
  if (diff > 5) return { icon: "↑", label: `+${diff.toFixed(1)}%`, positive: false };
  if (diff < -5) return { icon: "↓", label: `${diff.toFixed(1)}%`, positive: true };
  return { icon: "→", label: "Stable", positive: true };
}

// --- Sparkline Component ---
function Sparkline({ data, color }: { data: DailySpending[]; color: string }) {
  const max = Math.max(...data.map((d) => d.totalAmount));
  const width = 80;
  const height = 32;
  const points = data.map((d, i) => {
    const x = (i / (data.length - 1)) * width;
    const y = height - (d.totalAmount / max) * height;
    return `${x},${y}`;
  });

  return (
    <svg width={width} height={height} className="overflow-visible">
      <polyline
        points={points.join(" ")}
        fill="none"
        stroke={color}
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

