            </CardContent>
          </Card>
          <Card className="border-0 shadow-sm bg-white">
            <CardContent className="pt-5 pb-4">
              <p className="text-xs text-gray-500 uppercase tracking-wide font-medium">Daily Average</p>
              <p className="text-2xl font-bold text-gray-900 mt-1">{formatCurrency(avgDailySpending)}</p>
              <p className="text-xs text-gray-400 mt-0.5">Per day</p>
            </CardContent>
          </Card>
        </div>

        {/* Daily Spending Sparkline */}
        <Card className="border-0 shadow-sm bg-white">
          <CardHeader className="pb-2 pt-5">
            <CardTitle className="text-sm font-semibold text-gray-700">Daily Spending (Last 7 Days)</CardTitle>
          </CardHeader>
          <CardContent className="pb-5">
            <div className="flex items-end gap-2 h-20">
              {DAILY_SPENDING.map((day) => {
                const maxAmount = Math.max(...DAILY_SPENDING.map((d) => d.totalAmount));
                const heightPct = (day.totalAmount / maxAmount) * 100;
                const dateLabel = new Date(day.date).toLocaleDateString("en-US", { weekday: "short" });
                return (
                  <div key={day.date} className="flex flex-col items-center gap-1 flex-1">
                    <span className="text-xs text-gray-400 font-medium">
                      {formatCurrency(day.totalAmount).replace("$", "$")}
                    </span>
                    <div className="w-full flex items-end justify-center" style={{ height: 48 }}>
                      <div
                        className="w-full rounded-t-md bg-indigo-500 opacity-80 transition-all"
                        style={{ height: `${heightPct}%`, minHeight: 4 }}
                      />
                    </div>
                    <span className="text-xs text-gray-400">{dateLabel}</span>
                  </div>
                );
              })}
            </div>
          </CardContent>
        </Card>

        {/* Category Filter Chips */}
        <div>
          <p className="text-xs text-gray-500 uppercase tracking-wide font-medium mb-2">Filter by Category</p>
          <div className="flex gap-2 flex-wrap">
            <button
              onClick={() => setSelectedCategory(null)}
              className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
                selectedCategory === null
                  ? "bg-gray-900 text-white border-gray-900"
                  : "bg-white text-gray-600 border-gray-300 hover:border-gray-400"
              }`}
            >
              All
            </button>
            {spendingData.map((s) => {
              const cat = getCategoryById(s.categoryId);
              if (!cat) return null;
              const isSelected = selectedCategory === s.categoryId;
              return (
                <button
                  key={s.categoryId}
                  onClick={() =>
                    setSelectedCategory(isSelected ? null : s.categoryId)
                  }
                  className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
                    isSelected
                      ? "text-white border-transparent"
                      : "bg-white text-gray-600 border-gray-300 hover:border-gray-400"
                  }`}
                  style={isSelected ? { backgroundColor: cat.color, borderColor: cat.color } : {}}
                >
                  <span
                    className="w-2 h-2 rounded-full flex-shrink-0"
                    style={{ backgroundColor: cat.color }}
                  />
                  {cat.name}
                </button>
              );
            })}
          </div>
        </div>

        {/* Category Spending List */}
        <Card className="border-0 shadow-sm bg-white">
          <CardHeader className="pb-2 pt-5">
            <CardTitle className="text-sm font-semibold text-gray-700">
              Spending by Category
              {selectedCategory && (
                <span className="ml-2 text-indigo-600 font-normal">
                  — {getCategoryById(selectedCategory)?.name}
                </span>
              )}
            </CardTitle>
          </CardHeader>
          <CardContent className="pb-4">
            {filteredData.length === 0 ? (
              <div className="text-center py-10 text-gray-400 text-sm">No spending data for this selection.</div>
            ) : (
              <div className="space-y-4">
                {filteredData
                  .sort((a, b) => b.totalAmount - a.totalAmount)
                  .map((spending, idx) => {
                    const cat = getCategoryById(spending.categoryId);
                    if (!cat) return null;
                    const trend = getTrendData(spending.categoryId, timeRange);
                    return (
                      <div key={spending.categoryId} className="group">
                        <div className="flex items-center gap-3">
                          {/* Rank */}
                          <span className="text-xs text-gray-300 font-bold w-4 text-right flex-shrink-0">
                            {idx + 1}
                          </span>

                          {/* Icon */}
                          <div
                            className="w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0"
                            style={{ backgroundColor: `${cat.color}18` }}
                          >
                            <span style={{ color: cat.color }}>
                              {getCategoryIcon(cat.icon)}
                            </span>
                          </div>

                          {/* Info */}
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between mb-1">
                              <div className="flex items-center gap-2 min-w-0">
                                <span className="text-sm font-semibold text-gray-800 truncate">
                                  {cat.name}
                                </span>
                                <Badge
                                  variant="secondary"
                                  className="text-xs px-1.5 py-0 h-4 bg-gray-100 text-gray-500 font-normal flex-shrink-0"
                                >
                                  {spending.transactionCount} txn{spending.transactionCount !== 1 ? "s" : ""}
                                </Badge>
                              </div>
                              <div className="flex items-center gap-3 flex-shrink-0 ml-2">
                                <TrendIndicator value={trend} />
                                <span className="text-sm font-bold text-gray-900">
                                  {formatCurrency(spending.totalAmount)}
                                </span>
                              </div>
                            </div>
                            <div className="flex items-center gap-2">
                              <Progress
                                value={spending.percentage}
                                className="h-1.5 flex-1"
                                style={
                                  {
                                    "--progress-color": cat.color,
                                  } as React.CSSProperties
                                }
                              />
                              <span className="text-xs text-gray-400 w-10 text-right flex-shrink-0">
                                {spending.percentage.toFixed(1)}%
                              </span>
                            </div>
                          </div>
                        </div>
                      </div>
                    );
                  })}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Donut-style Legend Summary */}
        <Card className="border-0 shadow-sm bg-white">
          <CardHeader className="pb-2 pt-5">
            <CardTitle className="text-sm font-semibold text-gray-700">Spending Distribution</CardTitle>
          </CardHeader>
          <CardContent className="pb-5">
            <div className="flex flex-wrap gap-3">
              {spendingData
                .sort((a, b) => b.percentage - a.percentage)
                .map((spending) => {
                  const cat = getCategoryById(spending.categoryId);
                  if (!cat) return null;
                  return (
                    <div
                      key={spending.categoryId}
                      className="flex items-center gap-1.5 bg-gray-50 rounded-lg px-3 py-2"
                    >
                      <span
                        className="w-2.5 h-2.5 rounded-full flex-shrink-0"
                        style={{ backgroundColor: cat.color }}
                      />
                      <span className="text-xs text-gray-600 font-medium">{cat.name}</span>
                      <span className="text-xs text-gray-400">{spending.percentage.toFixed(1)}%</span>
                    </div>
                  );
                })}
            </div>
            {/* Stacked bar */}
            <div className="mt-4 flex rounded-full overflow-hidden h-3 gap-px">
              {spendingData
                .sort((a, b) => b.percentage - a.percentage)
                .map((spending) => {
                  const cat = getCategoryById(spending.categoryId);
                  if (!cat) return null;
                  return (
                    <div
                      key={spending.categoryId}
                      title={`${cat.name}: ${spending.percentage.toFixed(1)}%`}
                      style={{
                        width: `${spending.percentage}%`,
                        backgroundColor: cat.color,
                        minWidth: spending.percentage > 1 ? 2 : 0,
                      }}
                    />
                  );
                })}
            </div>
          </CardContent>
        </Card>

        {/* Footer */}
        <p className="text-center text-xs text-gray-400 pb-4">
          Data shown for {timeRangeLabel.toLowerCase()} · CashPulse Insights
        </p>
      </div>
    </div>
  );
};

export default SpendingInsightsPage;
