```tsx
import React, { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Separator } from "@/components/ui/separator";

// --- Types ---

type Currency = "USD" | "EUR" | "GBP" | "JPY" | "CAD" | "AUD";

interface UserSettings {
  id: string;
  currency: Currency;
  defaultMonthlyBudget: number;
}

interface Category {
  id: string;
  name: string;
  color: string;
  icon: string;
  isDefault: boolean;
}

// --- Constants ---

const CURRENCIES: Currency[] = ["USD", "EUR", "GBP", "JPY", "CAD", "AUD"];

const CURRENCY_SYMBOLS: Record<Currency, string> = {
  USD: "$",
  EUR: "€",
  GBP: "£",
  JPY: "¥",
  CAD: "CA$",
  AUD: "A$",
};

const ICON_OPTIONS = [
  "🍔", "🚗", "🏠", "💊", "🎮", "✈️", "📚", "👗",
  "💡", "🎵", "🏋️", "🐾", "🛒", "💼", "🎁", "📱",
];

const COLOR_OPTIONS = [
  "#ef4444", "#f97316", "#eab308", "#22c55e",
  "#06b6d4", "#3b82f6", "#8b5cf6", "#ec4899",
  "#14b8a6", "#f43f5e", "#a855f7", "#84cc16",
];

// --- Initial Data ---

const initialSettings: UserSettings = {
  id: "settings-1",
  currency: "USD",
  defaultMonthlyBudget: 2000,
};

const initialCategories: Category[] = [
  { id: "cat-1", name: "Food & Dining", color: "#ef4444", icon: "🍔", isDefault: true },
  { id: "cat-2", name: "Transportation", color: "#f97316", icon: "🚗", isDefault: true },
  { id: "cat-3", name: "Housing", color: "#3b82f6", icon: "🏠", isDefault: true },
  { id: "cat-4", name: "Entertainment", color: "#8b5cf6", icon: "🎮", isDefault: false },
];

// --- Category Dialog ---

interface CategoryDialogProps {
  open: boolean;
  category: Partial<Category> | null;
  onClose: () => void;
  onSave: (category: Omit<Category, "id"> & { id?: string }) => void;
}

const CategoryDialog: React.FC<CategoryDialogProps> = ({ open, category, onClose, onSave }) => {
  const [name, setName] = useState(category?.name ?? "");
  const [color, setColor] = useState(category?.color ?? COLOR_OPTIONS[0]);
  const [icon, setIcon] = useState(category?.icon ?? ICON_OPTIONS[0]);
  const [isDefault, setIsDefault] = useState(category?.isDefault ?? false);

  React.useEffect(() => {
    setName(category?.name ?? "");
    setColor(category?.color ?? COLOR_OPTIONS[0]);
    setIcon(category?.icon ?? ICON_OPTIONS[0]);
    setIsDefault(category?.isDefault ?? false);
  }, [category, open]);

  const handleSave = () => {
    if (!name.trim()) return;
    onSave({ id: category?.id, name: name.trim(), color, icon, isDefault });
    onClose();
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>{category?.id ? "Edit Category" : "Add Category"}</DialogTitle>
        </DialogHeader>
        <div className="space-y-4 py-2">
          {/* Name */}
          <div className="space-y-1">
            <Label htmlFor="cat-name">Category Name</Label>
            <Input
              id="cat-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g. Groceries"
            />
          </div>

          {/* Icon */}
          <div className="space-y-1">
            <Label>Icon</Label>
            <div className="flex flex-wrap gap-2">
              {ICON_OPTIONS.map((ic) => (
                <button
                  key={ic}
                  type="button"
                  onClick={() => setIcon(ic)}
                  className={`text-xl p-1.5 rounded border-2 transition-all ${
                    icon === ic ? "border-blue-500 bg-blue-50" : "border-transparent hover:border-gray-300"
                  }`}
                >
                  {ic}
                </button>
              ))}
            </div>
          </div>

          {/* Color */}
          <div className="space-y-1">
            <Label>Color</Label>
            <div className="flex flex-wrap gap-2">
              {COLOR_OPTIONS.map((c) => (
                <button
                  key={c}
                  type="button"
                  onClick={() => setColor(c)}
                  className={`w-7 h-7 rounded-full border-2 transition-all ${
                    color === c ? "border-gray-800 scale-110" : "border-transparent hover:scale-105"
                  }`}
                  style={{ backgroundColor: c }}
                />
              ))}
            </div>
          </div>

          {/* Preview */}
          <div className="space-y-1">
            <Label>Preview</Label>
            <div className="flex items-center gap-2">
              <span
                className="w-8 h-8 rounded-full flex items-center justify-center text-sm"
                style={{ backgroundColor: color + "33" }}
              >
                {icon}
              </span>
              <span className="font-medium text-sm">{name || "Category Name"}</span>
              <span
                className="ml-1 text-xs px-2 py-0.5 rounded-full font-medium"
                style={{ backgroundColor: color + "22", color }}
              >
                {isDefault ? "Default" : "Custom"}
              </span>
            </div>
          </div>

          {/* isDefault toggle */}
          <div className="flex items-center gap-2">
            <input
              id="is-default"
              type="checkbox"
              checked={isDefault}
              onChange={(e) => setIsDefault(e.target.checked)}
              className="w-4 h-4 accent-blue-600"
            />
            <Label htmlFor="is-default" className="cursor-pointer">
              Mark as default category
            </Label>
          </div>
        </div>
        <DialogFooter>
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button onClick={handleSave} disabled={!name.trim()}>
            {category?.id ? "Save Changes" : "Add Category"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

// --- Main Settings Form ---

const SettingsForm: React.FC = () => {
  const [settings, setSettings] = useState<UserSettings>(initialSettings);
  const [categories, setCategories] = useState<Category[]>(initialCategories);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingCategory, setEditingCategory] = useState<Partial<Category> | null>(null);
  const [savedBanner, setSavedBanner] = useState(false);
  const [budgetInput, setBudgetInput] = useState(String(initialSettings.defaultMonthlyBudget));

  const handleOpenAdd = () => {
    setEditingCategory({});
    setDialogOpen(true);
  };

  const handleOpenEdit = (cat: Category) => {
    setEditingCategory(cat);
    setDialogOpen(true);
  };

  const handleDialogClose = () => {
    setDialogOpen(false);
    setEditingCategory(null);
  };

  const handleSaveCategory = (cat: Omit<Category, "id"> & { id?: string }) => {
    if (cat.id) {
      setCategories((prev) =>
        prev.map((c) => (c.id === cat.id ? { ...c, ...cat, id: c.id } : c))
      );
    } else {
      const newCat: Category = {
        ...cat,
        id: `cat-${Date.now()}`,
      };
      setCategories((prev) => [...prev, newCat]);
    }
  };

  const handleDeleteCategory = (id: string) => {
    setCategories((prev) => prev.filter((c) => c.id !== id));
  };

  const handleSaveSettings = () => {
    const parsed = parseFloat(budgetInput);
    if (!isNaN(parsed) && parsed >= 0) {
      setSettings((prev) => ({ ...prev, defaultMonthlyBudget: parsed }));
    }
    setSavedBanner(true);
    setTimeout(() => setSavedBanner(false), 3000);
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8 px-4">
      <div className="max-w-2xl mx-auto space-y-6">
        {/* Header */}
        <div>
          <h1 className="text-2xl font-bold text-gray-900">⚙️ Settings</h1>
          <p className="text-sm text-gray-500 mt-1">
            Configure your CashPulse preferences and expense categories.
          </p>
        </div>

        {/* Success Banner */}
        {savedBanner && (
          <div className="bg-green-50 border border-green-200 text-green-800 rounded-lg px-4 py-3 text-sm font-medium flex items-center gap-2">
            ✅ Settings saved successfully!
          </div>
        )}

        {/* General Settings Card */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">General Settings</CardTitle>
          </CardHeader>
          <CardContent className="space-y-5">
            {/* Currency */}
            <div className="space-y-1.5">
              <Label htmlFor="currency">Default Currency</Label>
              <Select
                value={settings.currency}
                onValueChange={(val) =>
                  setSettings((prev) => ({ ...prev, currency: val as Currency }))
                }
              >
                <SelectTrigger id="currency" className="w-full">
                  <SelectValue placeholder="Select currency" />
                </SelectTrigger>
                <SelectContent>
                  {CURRENCIES.map((c) => (
                    <SelectItem key={c} value={c}>
                      <span className="font-mono mr-2">{CURRENCY_SYMBOLS[c]}</span>
                      {c}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <p className="text-xs text-gray-400">
                This currency will be used across all budgets and expenses.
              </p>
            </div>

            <Separator />

            {/* Monthly Budget */}
            <div className="space-y-1.5">
              <Label htmlFor="monthly-budget">Default Monthly Budget Limit</Label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 font-medium text-sm">
                  {CURRENCY_SYMBOLS[settings.currency]}
                </span>
                <Input
                  id="monthly-budget"
                  type="number"
                  min={0}
                  step={50}
                  value={budgetInput}
                  onChange={(e) => setBudgetInput(e.target.value)}
                  className="pl-8"
                  placeholder="2000"
                />
              </div>
              <p className="text-xs text-gray-400">
                This limit will be applied to new monthly budgets by default.
              </p>
            </div>

            {/* Summary */}
            <div className="bg-blue-50 rounded-lg p-3 text-sm text-blue-800 flex items-center gap-2">
              <span>💡</span>
              <span>
                Current settings: <strong>{settings.currency}</strong> with a monthly limit of{" "}
                <strong>
                  {CURRENCY_SYMBOLS[settings.currency]}
                  {parseFloat(budgetInput || "0").toLocaleString()}
                </strong>
              </span>
            </div>
          </CardContent>
        </Card>

        {/* Categories Card */}
        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="text-base">Expense Categories</CardTitle>
              <Button size="sm" onClick={handleOpenAdd}>
                + Add Category
              </Button>
            </div>
          </CardHeader>
          <CardContent>
            {categories.length === 0 ? (
              <div className="text-center py-8 text-gray-400 text-sm">
                No categories yet. Add one to get started.
              </div>
            ) : (
              <div className="space-y-2">
                {categories.map((cat) => (
                  <div
                    key={cat.id}
                    className="flex items-center justify-between p-3 rounded-lg border bg-white hover:bg-gray-50 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      {/* Color + Icon */}
                      <span
                        className="w-9 h-9 rounded-full flex items-center justify-center text-base flex-shrink-0"
                        style={{ backgroundColor: cat.color + "22" }}
                      >
                        {cat.icon}
                      </span>
                      <div>
                        <div className="flex items-center gap-2">
                          <span className="font-medium text-sm text-gray-900">{cat.name}</span>
                          {cat.isDefault && (
                            <Badge
                              variant="secondary"
                              className="text-xs px-1.5 py-0"
                            >
                              Default
                            </Badge>
                          )}
                        </div>
                        <div className="flex items-center gap-1 mt-0.5">
                          <span
                            className="w-3 h-3 rounded-full inline-block"
                            style={{ backgroundColor: cat.color }}
                          />
                          <span className="text-xs text-gray-400 font-mono">{cat.color}</span>
                        </div>
                      </div>
                    </div>
                    <div className="flex items-center gap-1">
                      <Button
                        size="sm"
                        variant="ghost"
                        className="h-8 px-2 text-gray-500 hover:text-blue-600"
                        onClick={() => handleOpenEdit(cat)}
                      >
                        ✏️
                      </Button>
                      <Button
                        size="sm"
                        variant="ghost"
                        className="h-8 px-2 text-gray-500 hover:text-red-600"
                        onClick={() => handleDeleteCategory(cat.id)}
                      >
                        🗑️
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
            <p className="text-xs text-gray-400 mt-3">
              {categories.length} categor{categories.length === 1 ? "y" : "ies"} ·{" "}
              {categories.filter((c) => c.isDefault).length} default
            </p>
          </CardContent>
        </Card>

        {/* Save Button */}
        <div className="flex justify-end gap-3">
          <Button
            variant="outline"
            onClick={() => {
              setSettings(initialSettings);
              setBudgetInput(String(initialSettings.defaultMonthlyBudget));
              setCategories(initialCategories);
            }}
          >
            Reset to Defaults
          </Button>
          <Button onClick={handleSaveSettings} className="px-6">
            Save Settings
          </Button>
        </div>
      </div>

      {/* Category Dialog */}
      <CategoryDialog
        open={dialogOpen}
        category={editingCategory}
        onClose={handleDialogClose}
        onSave={handleSaveCategory}
      />
    </div>
  );
};

export default SettingsForm;
