const ICON_OPTIONS = [
  "🍔", "🚗", "🏠", "💊", "🎮", "✈️", "📚", "👗", "💡", "🛒",
  "🎵", "🏋️", "🐾", "🎁", "💼", "🍷", "☕", "🔧", "📱", "💰",
];

const COLOR_OPTIONS = [
  "#ef4444", "#f97316", "#eab308", "#22c55e", "#14b8a6",
  "#3b82f6", "#8b5cf6", "#ec4899", "#6b7280", "#0ea5e9",
];

const DEFAULT_CATEGORIES: Category[] = [
  { id: "1", name: "Food & Dining", color: "#ef4444", icon: "🍔", isDefault: true },
  { id: "2", name: "Transport", color: "#f97316", icon: "🚗", isDefault: true },
  { id: "3", name: "Housing", color: "#3b82f6", icon: "🏠", isDefault: true },
  { id: "4", name: "Health", color: "#22c55e", icon: "💊", isDefault: true },
  { id: "5", name: "Entertainment", color: "#8b5cf6", icon: "🎮", isDefault: false },
];

const DEFAULT_SETTINGS: UserSettings = {
  id: "user-1",
  currency: "USD",
  defaultMonthlyBudget: 3000,
};

// --- Helpers ---
function generateId(): string {
  return Math.random().toString(36).substring(2, 10);
}

// --- Category Dialog ---
interface CategoryDialogProps {
  open: boolean;
  category: Partial<Category> | null;
  onClose: () => void;
  onSave: (category: Category) => void;
}

function CategoryDialog({ open, category, onClose, onSave }: CategoryDialogProps) {
  const [name, setName] = useState(category?.name ?? "");
  const [color, setColor] = useState(category?.color ?? COLOR_OPTIONS[0]);
  const [icon, setIcon] = useState(category?.icon ?? ICON_OPTIONS[0]);

  React.useEffect(() => {
    setName(category?.name ?? "");
    setColor(category?.color ?? COLOR_OPTIONS[0]);
    setIcon(category?.icon ?? ICON_OPTIONS[0]);
  }, [category, open]);

  const handleSave = () => {
    if (!name.trim()) return;
    onSave({
      id: category?.id ?? generateId(),
      name: name.trim(),
      color,
      icon,
      isDefault: category?.isDefault ?? false,
    });
  };

  return (
    <Dialog open={open} onOpenChange={(v) => !v && onClose()}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>{category?.id ? "Edit Category" : "Add Category"}</DialogTitle>
        </DialogHeader>

        <div className="space-y-4 py-2">
          {/* Name */}
          <div className="space-y-1">
            <Label htmlFor="cat-name">Category Name</Label>
            <Input
              id="cat-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g. Groceries"
            />
          </div>

          {/* Icon */}
          <div className="space-y-1">
            <Label>Icon</Label>
            <div className="flex flex-wrap gap-2">
              {ICON_OPTIONS.map((ic) => (
                <button
