        {/* General Settings Card */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">General Preferences</CardTitle>
          </CardHeader>
          <CardContent className="space-y-5">
            {/* Currency */}
            <div className="space-y-1.5">
              <Label htmlFor="currency">Default Currency</Label>
              <Select value={settings.currency} onValueChange={handleCurrencyChange}>
                <SelectTrigger id="currency" className="w-full">
                  <SelectValue placeholder="Select currency" />
                </SelectTrigger>
                <SelectContent>
                  {CURRENCIES.map((c) => (
                    <SelectItem key={c} value={c}>
                      {c}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <p className="text-xs text-gray-400">
                Used as the default currency for new budgets and expenses.
              </p>
            </div>

            <Separator />

            {/* Monthly Budget */}
            <div className="space-y-1.5">
              <Label htmlFor="budget">Default Monthly Budget Limit</Label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm font-medium">
                  {settings.currency}
                </span>
                <Input
                  id="budget"
                  type="number"
                  min={0}
                  step={50}
                  value={settings.defaultMonthlyBudget}
                  onChange={handleBudgetChange}
