// --- Helpers ---
const formatCurrency = (amount: number): string =>
  new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" }).format(amount);

const formatDate = (date: Date): string =>
  new Intl.DateTimeFormat("en-US", { month: "short", day: "numeric", year: "numeric" }).format(date);

const getDaysUntil = (date: Date): number => {
  const now = new Date();
  const diff = date.getTime() - now.getTime();
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
};

const frequencyLabel: Record<Frequency, string> = {
  daily: "Daily",
  weekly: "Weekly",
  biweekly: "Bi-weekly",
  monthly: "Monthly",
  quarterly: "Quarterly",
  yearly: "Yearly",
};

const frequencyColor: Record<Frequency, string> = {
  daily: "bg-red-100 text-red-700 border-red-200",
  weekly: "bg-orange-100 text-orange-700 border-orange-200",
  biweekly: "bg-amber-100 text-amber-700 border-amber-200",
  monthly: "bg-blue-100 text-blue-700 border-blue-200",
  quarterly: "bg-purple-100 text-purple-700 border-purple-200",
  yearly: "bg-green-100 text-green-700 border-green-200",
};

const getMerchantIcon = (merchantName: string) => {
  const name = merchantName.toLowerCase();
  if (name.includes("coffee") || name.includes("cafe")) return <Coffee className="h-4 w-4" />;
  if (name.includes("electric") || name.includes("power") || name.includes("utility")) return <Zap className="h-4 w-4" />;
  if (name.includes("apartment") || name.includes("rent") || name.includes("housing")) return <Home className="h-4 w-4" />;
  if (name.includes("transit") || name.includes("gas") || name.includes("metro")) return <Car className="h-4 w-4" />;
  return <ShoppingCart className="h-4 w-4" />;
};

