interface UpcomingRecurringCardProps {
  templates: RecurringTemplate[];
  onViewDetail: (id: string) => void;
}

const UpcomingRecurringCard: React.FC<UpcomingRecurringCardProps> = ({ templates, onViewDetail }) => {
  const upcoming = templates
    .filter((t) => t.status === "active")
    .sort((a, b) => a.nextOccurrence.getTime() - b.nextOccurrence.getTime())
    .slice(0, 5);

  return (
    <Card className="shadow-sm border border-gray-100">
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="p-1.5 bg-violet-100 rounded-lg">
              <RefreshCw className="h-4 w-4 text-violet-600" />
            </div>
            <CardTitle className="text-base font-semibold text-gray-800">
              Upcoming Recurring Expenses
            </CardTitle>
          </div>
          <Button
            variant="ghost"
            size="sm"
            className="text-xs text-violet-600 hover:text-violet-700 hover:bg-violet-50 h-7 px-2"
            onClick={() => onViewDetail("all")}
          >
            View all
            <ChevronRight className="h-3 w-3 ml-1" />
          </Button>
        </div>
      </CardHeader>
      <CardContent className="pt-0">
        {upcoming.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-8 text-gray-400">
            <RefreshCw className="h-8 w-8 mb-2 opacity-40" />
            <p className="text-sm">No upcoming recurring expenses</p>
          </div>
        ) : (
          <div className="space-y-2">
            {upcoming.map((template, index) => {
              const daysUntil = getDaysUntil(template.nextOccurrence);
              const isUrgent = daysUntil <= 3;
              const isSoon = daysUntil <= 7;

              return (
                <button
                  key={template.id}
                  onClick={() => onViewDetail(template.id)}
                  className="w-full text-left group"
                >
                  <div
                    className={`flex items-center gap-3 p-3 rounded-xl border transition-all duration-150 hover:shadow-sm hover:border-violet-200 hover:bg-violet-50/30 ${
                      isUrgent
                        ? "border-red-100 bg-red-50/30"
                        : isSoon
                        ? "border-amber-100 bg-amber-50/20"
                        : "border-gray-100 bg-gray-50/50"
                    }`}
                  >
                    {/* Icon */}
                    <div
                      className={`flex-shrink-0 w-9 h-9 rounded-xl flex items-center justify-center ${
                        categoryColors[template.categoryId] ?? "bg-gray-100 text-gray-600"
                      }`}
                    >
                      {getMerchantIcon(template.merchantName)}
                    </div>

                    {/* Merchant & Date */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-0.5">
                        <span className="text-sm font-medium text-gray-800 truncate group-hover:text-violet-700 transition-colors">
                          {template.merchantName}
                        </span>
                        <Badge
                          variant="outline"
                          className={`text-[10px] font-medium px-1.5 py-0 h-4 flex-shrink-0 border ${
                            frequencyColor[template.frequency]
                          }`}
                        >
                          {frequencyLabel[template.frequency]}
                        </Badge>
                      </div>
                      <div className="flex items-center gap-1.5">
                        <Calendar className="h-3 w-3 text-gray-400 flex-shrink-0" />
                        <span className="text-xs text-gray-500">
                          {formatDate(template.nextOccurrence)}
                        </span>
                        <span
                          className={`text-xs font-medium ${
                            isUrgent
                              ? "text-red-600"
                              : isSoon
                              ? "text-amber-600"
                              : "text-gray-400"
                          }`}
                        >
                          {daysUntil === 0
                            ? "· Today"
                            : daysUntil === 1
                            ? "· Tomorrow"
                            : `· In ${daysUntil} days`}
                        </span>
                      </div>
                    </div>

                    {/* Amount & Arrow */}
                    <div className="flex items-center gap-1.5 flex-shrink-0">
                      <span className="text-sm font-semibold text-gray-900">
                        {formatCurrency(template.amount)}
                      </span>
                      <ChevronRight className="h-3.5 w-3.5 text-gray-300 group-hover:text-violet-400 transition-colors" />
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        )}

        {/* Total upcoming */}
        {upcoming.length > 0 && (
          <div className="mt-3 pt-3 border-t border-gray-100 flex items-center justify-between">
            <span className="text-xs text-gray-500">
              Total upcoming ({upcoming.length} expenses)
            </span>
            <span className="text-sm font-semibold text-gray-800">
              {formatCurrency(upcoming.reduce((sum, t) => sum + t.amount, 0))}
            </span>
          </div>
        )}
      </CardContent>
    </Card>
  );
};

