// --- Helper Functions ---
const formatCurrency = (amount: number): string => {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(amount);
};

const formatDate = (dateStr: string): string => {
  const date = new Date(dateStr);
  return date.toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });
};

const getDaysUntil = (dateStr: string): number => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const target = new Date(dateStr);
  target.setHours(0, 0, 0, 0);
  const diff = target.getTime() - today.getTime();
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
};

const getFrequencyLabel = (frequency: Frequency): string => {
  const labels: Record<Frequency, string> = {
    daily: "Daily",
    weekly: "Weekly",
    biweekly: "Bi-weekly",
    monthly: "Monthly",
    yearly: "Yearly",
  };
  return labels[frequency];
};

const getFrequencyVariant = (
  frequency: Frequency
): "default" | "secondary" | "outline" => {
  if (frequency === "daily" || frequency === "weekly") return "default";
  if (frequency === "monthly") return "secondary";
  return "outline";
};

const getCategoryById = (id: string): Category | undefined => {
  return mockCategories.find((c) => c.id === id);
};

const getUpcomingRecurring = (
  templates: RecurringTemplate[],
  count: number = 5
): RecurringTemplate[] => {
  return templates
    .filter((t) => t.status === "active")
    .sort(
      (a, b) =>
        new Date(a.nextOccurrence).getTime() -
        new Date(b.nextOccurrence).getTime()
    )
    .slice(0, count);
};

