import { CalendarIcon, RefreshCw, DollarSign, CreditCard, FileText, Tag } from "lucide-react";

type PaymentMethod = "cash" | "credit_card" | "debit_card" | "bank_transfer" | "other";
type Frequency = "weekly" | "monthly" | "yearly";
type RecurringStatus = "active" | "paused" | "ended";

interface Category {
  id: string;
  name: string;
  color: string;
}

interface ExpenseFormData {
  amount: string;
  categoryId: string;
  merchantName: string;
  date: string;
  paymentMethod: PaymentMethod | "";
  note: string;
  recurringTemplateId?: string;
}

interface RecurringTemplateFormData {
  frequency: Frequency | "";
  startDate: string;
  endDate: string;
}

const MOCK_CATEGORIES: Category[] = [
  { id: "cat_1", name: "Food & Dining", color: "#f97316" },
  { id: "cat_2", name: "Transportation", color: "#3b82f6" },
  { id: "cat_3", name: "Shopping", color: "#8b5cf6" },
  { id: "cat_4", name: "Entertainment", color: "#ec4899" },
  { id: "cat_5", name: "Bills & Utilities", color: "#10b981" },
  { id: "cat_6", name: "Healthcare", color: "#ef4444" },
  { id: "cat_7", name: "Other", color: "#6b7280" },
];

const PAYMENT_METHODS: { value: PaymentMethod; label: string }[] = [
  { value: "cash", label: "Cash" },
  { value: "credit_card", label: "Credit Card" },
  { value: "debit_card", label: "Debit Card" },
  { value: "bank_transfer", label: "Bank Transfer" },
  { value: "other", label: "Other" },
];

const FREQUENCIES: { value: Frequency; label: string; description: string }[] = [
  { value: "weekly", label: "Weekly", description: "Repeats every week" },
  { value: "monthly", label: "Monthly", description: "Repeats every month" },
  { value: "yearly", label: "Yearly", description: "Repeats every year" },
];

export default function AddExpenseForm() {
  const today = new Date().toISOString().split("T")[0];

  const [expenseForm, setExpenseForm] = useState<ExpenseFormData>({
    amount: "",
    categoryId: "",
    merchantName: "",
    date: today,
    paymentMethod: "",
    note: "",
  });

  const [isRecurring, setIsRecurring] = useState(false);

  const [recurringForm, setRecurringForm] = useState<RecurringTemplateFormData>({
    frequency: "",
    startDate: today,
    endDate: "",
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const selectedCategory = MOCK_CATEGORIES.find((c) => c.id === expenseForm.categoryId);

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!expenseForm.amount || isNaN(Number(expenseForm.amount)) || Number(expenseForm.amount) <= 0) {
      newErrors.amount = "Please enter a valid amount greater than 0";
    }

    if (!expenseForm.categoryId) {
      newErrors.categoryId = "Please select a category";
    }

    if (!expenseForm.date) {
      newErrors.date = "Please select a date";
    }

    if (!expenseForm.paymentMethod) {
      newErrors.paymentMethod = "Please select a payment method";
    }

    if (isRecurring) {
      if (!recurringForm.frequency) {
        newErrors.frequency = "Please select a frequency";
      }

      if (!recurringForm.startDate) {
        newErrors.startDate = "Please select a start date";
      }

      if (recurringForm.endDate && recurringForm.startDate && recurringForm.endDate < recurringForm.startDate) {
        newErrors.endDate = "End date must be after start date";
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validate()) return;

    setIsSubmitting(true);

    await new Promise((resolve) => setTimeout(resolve, 1200));

    const expensePayload = {
      id: `exp_${Date.now()}`,
      amount: Number(expenseForm.amount),
      categoryId: expenseForm.categoryId,
      merchantName: expenseForm.merchantName,
      date: expenseForm.date,
      paymentMethod: expenseForm.paymentMethod,
      note: expenseForm.note,
      ...(isRecurring && {
        recurringTemplateId: `rt_${Date.now()}`,
      }),
    };

    const recurringPayload = isRecurring
      ? {
          id: `rt_${Date.now()}`,
          amount: Number(expenseForm.amount),
          categoryId: expenseForm.categoryId,
          merchantName: expenseForm.merchantName,
          frequency: recurringForm.frequency,
          startDate: recurringForm.startDate,
          endDate: recurringForm.endDate || null,
          nextOccurrence: recurringForm.startDate,
          paymentMethod: expenseForm.paymentMethod,
          note: expenseForm.note,
          status: "active" as RecurringStatus,
          createdAt: new Date().toISOString(),
        }
      : null;

    console.log("Expense payload:", expensePayload);
    if (recurringPayload) {
      console.log("RecurringTemplate payload:", recurringPayload);
    }

    setIsSubmitting(false);
    setSubmitted(true);
  };

  const handleReset = () => {
    setExpenseForm({
      amount: "",
      categoryId: "",
      merchantName: "",
      date: today,
      paymentMethod: "",
      note: "",
    });
    setIsRecurring(false);
    setRecurringForm({
      frequency: "",
      startDate: today,
      endDate: "",
    });
    setErrors({});
    setSubmitted(false);
  };

  const updateExpenseField = <K extends keyof ExpenseFormData>(
    field: K,
    value: ExpenseFormData[K]
  ) => {
    setExpenseForm((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => ({ ...prev, [field]: "" }));
    }
  };

  const updateRecurringField = <K extends keyof RecurringTemplateFormData>(
    field: K,
    value: RecurringTemplateFormData[K]
  ) => {
    setRecurringForm((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => ({ ...prev, [field]: "" }));
    }
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 flex items-center justify-center p-4">
        <Card className="w-full max-w-md shadow-lg">
          <CardContent className="pt-8 pb-8 text-center">
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Expense Added!</h2>
            <p className="text-slate-500 mb-2">
              ${Number(expenseForm.amount).toFixed(2)} has been recorded successfully.
            </p>
            {isRecurring && (
              <div className="flex items-center justify-center gap-2 mb-6">
                <Badge variant="secondary" className="bg-violet-100 text-violet-700 border-violet-200">
                  <RefreshCw className="w-3 h-3 mr-1" />
                  Recurring {recurringForm.frequency}
                </Badge>
              </div>
            )}
            <Button onClick={handleReset} className="w-full bg-violet-600 hover:bg-violet-700 text-white">
              Add Another Expense
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 flex items-center justify-center p-4">
      <div className="w-full max-w-lg">
        {/* Header */}
        <div className="mb-6 text-center">
          <div className="inline-flex items-center gap-2 bg-violet-600 text-white px-4 py-1.5 rounded-full text-sm font-medium mb-3">
            <DollarSign className="w-4 h-4" />
            CashPulse
          </div>
          <h1 className="text-3xl font-bold text-slate-800">Add Expense</h1>
          <p className="text-slate-500 mt-1">Track your spending with ease</p>
        </div>

        <Card className="shadow-lg border-0 bg-white">
          <CardContent className="p-6">
            <form onSubmit={handleSubmit} className="space-y-5">

              {/* Amount */}
              <div className="space-y-1.5">
                <Label htmlFor="amount" className="text-sm font-semibold text-slate-700 flex items-center gap-1.5">
                  <DollarSign className="w-4 h-4 text-violet-500" />
                  Amount <span className="text-red-500">*</span>
                </Label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 font-medium">$</span>
                  <Input
                    id="amount"
                    type="number"
                    step="0.01"
                    min="0"
                    placeholder="0.00"
                    value={expenseForm.amount}
                    onChange={(e) => updateExpenseField("amount", e.target.value)}
                    className={`pl-7 text-lg font-semibold h-12 ${errors.amount ? "border-red-400 focus-visible:ring-red-400" : "border-slate-200 focus-visible:ring-violet-400"}`}
                  />
                </div>
                {errors.amount && <p className="text-xs text-red-500 mt-1">{errors.amount}</p>}
              </div>

              {/* Merchant Name */}
              <div className="space-y-1.5">
                <Label htmlFor="merchantName" className="text-sm font-semibold text-slate-700">
                  Merchant / Payee
                </Label>
                <Input
                  id="merchantName"
                  type="text"
                  placeholder="e.g. Starbucks, Amazon..."
                  value={expenseForm.merchantName}
                  onChange={(e) => updateExpenseField("merchantName", e.target.value)}
                  className="border-slate-200 focus-visible:ring-violet-400"
                />
              </div>

              {/* Category */}
              <div className="space-y-1.5">
                <Label className="text-sm font-semibold text-slate-700 flex items-center gap-1.5">
                  <Tag className="w-4 h-4 text-violet-500" />
                  Category <span className="text-red-500">*</span>
                </Label>
                <div className="grid grid-cols-2 gap-2">
                  {MOCK_CATEGORIES.map((category) => (
                    <button
                      key={category.id}
                      type="button"
                      onClick={() => updateExpenseField("categoryId", category.id)}
                      className={`flex items-center gap-2 px-3 py-2.5 rounded-lg border text-sm font-medium transition-all ${
                        expenseForm.categoryId === category.id
                          ? "border-violet-500 bg-violet-50 text-violet-700 shadow-sm"
                          : "border-slate-200 bg-white text-slate-600 hover:border-slate-300 hover:bg-slate-50"
                      }`}
                    >
                      <span
                        className="w-2.5 h-2.5 rounded-full flex-shrink-0"
                        style={{ backgroundColor: category.color }}
                      />
                      <span className="truncate">{category.name}</span>
                    </button>
                  ))}
                </div>
                {errors.categoryId && <p className="text-xs text-red-500 mt-1">{errors.categoryId}</p>}
                {selectedCategory && (
                  <div className="flex items-center gap-1.5 mt-1">
                    <span className="text-xs text-slate-500">Selected:</span>
                    <Badge
                      variant="secondary"
                      className="text-xs px-2 py-0.5"
                      style={{
                        backgroundColor: `${selectedCategory.color}20`,
                        color: selectedCategory.color,
                        borderColor: `${selectedCategory.color}40`,
                      }}
                    >
                      {selectedCategory.name}
                    </Badge>
                  </div>
                )}
              </div>

              {/* Date */}
              <div className="space-y-1.5">
                <Label htmlFor="date" className="text-sm font-semibold text-slate-700 flex items-center gap-1.5">
                  <CalendarIcon className="w-4 h-4 text-violet-500" />
                  Date <span className="text-red-500">*</span>
                </Label>
                <Input
                  id="date"
                  type="date"
                  value={expenseForm.date}
                  onChange={(e) => updateExpenseField("date", e.target.value)}
                  className={`border-slate-200 focus-visible:ring-violet-400 ${errors.date ? "border-red-400" : ""}`}
                />
                {errors.date && <p className="text-xs text-red-500 mt-1">{errors.date}</p>}
              </div>

              {/* Payment Method */}
              <div className="space-y-1.5">
                <Label className="text-sm font-semibold text-slate-700 flex items-center gap-1.5">
                  <CreditCard className="w-4 h-4 text-violet-500" />
                  Payment Method <span className="text-red-500">*</span>
                </Label>
                <Select
                  value={expenseForm.paymentMethod}
                  onValueChange={(value) => updateExpenseField("paymentMethod", value as PaymentMethod)}
                >
                  <SelectTrigger className={`border-slate-200 focus:ring-violet-400 ${errors.paymentMethod ? "border-red-400" : ""}`}>
                    <SelectValue placeholder="Select payment method" />
                  </SelectTrigger>
                  <SelectContent>
                    {PAYMENT_METHODS.map((method) => (
                      <SelectItem key={method.value} value={method.value}>
                        {method.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {errors.paymentMethod && <p className="text-xs text-red-500 mt-1">{errors.paymentMethod}</p>}
              </div>

              {/* Note */}
              <div className="space-y-1.5">
                <Label htmlFor="note" className="text-sm font-semibold text-slate-700 flex items-center gap-1.5">
                  <FileText className="w-4 h-4 text-violet-500" />
                  Note
                </Label>
                <Textarea
                  id="note"
                  placeholder="Add a note (optional)..."
                  value={expenseForm.note}
                  onChange={(e) => updateExpenseField("note", e.target.value)}
                  rows={2}
                  className="border-slate-200 focus-visible:ring-violet-400 resize-none"
                />
              </div>

              <Separator className="my-2" />

              {/* Recurring Toggle */}
              <div className="space-y-4">
                <div className="flex items-center justify-between p-4 rounded-xl border border-slate-200 bg-slate-50 hover:bg-slate-100 transition-colors">
                  <div className="flex items-center gap-3">
                    <div className={`w-9 h-9 rounded-lg flex items-center justify-center transition-colors ${isRecurring ? "bg-violet-100" : "bg-slate-200"}`}>
                      <RefreshCw className={`w-4 h-4 transition-colors ${isRecurring ? "text-violet-600" : "text-slate-400"}`} />
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-slate-700">Make this recurring</p>
                      <p className="text-xs text-slate-500">Automatically track repeating expenses</p>
                    </div>
                  </div>
                  <Switch
                    checked={isRecurring}
                    onCheckedChange={(checked) => {
                      setIsRecurring(checked);
                      if (!checked) {
                        setErrors((prev) => {
                          const next = { ...prev };
                          delete next.frequency;
                          delete next.startDate;
                          delete next.endDate;
                          return next;
                        });
                      }
                    }}
                    className="data-[state=checked]:bg-violet-600"
                  />
                </div>

                {/* Recurring Configuration Panel */}
                {isRecurring && (
                  <div className="rounded-xl border border-violet-200 bg-violet-50/50 p-4 space-y-4 animate-in slide-in-from-top-2 duration-200">
                    <div className="flex items-center gap-2 mb-1">
                      <RefreshCw className="w-4 h-4 text-violet-600" />
                      <span className="text-sm font-semibold text-violet-700">Recurrence Settings</span>
                      <Badge variant="secondary" className="bg-violet-100 text-violet-600 border-violet-200 text-xs ml-auto">
                        RecurringTemplate
                      </Badge>
                    </div>

                    {/* Frequency Picker */}
                    <div className="space-y-1.5">
                      <Label className="text-sm font-semibold text-slate-700">
                        Frequency <span className="text-red-500">*</span>
                      </Label>
                      <div className="grid grid-cols-3 gap-2">
                        {FREQUENCIES.map((freq) => (
                          <button
                            key={freq.value}
                            type="button"
                            onClick={() => updateRecurringField("frequency", freq.value)}
                            className={`flex flex-col items-center gap-1 px-3 py-3 rounded-lg border text-sm font-medium transition-all ${
                              recurringForm.frequency === freq.value
                                ? "border-violet-500 bg-violet-100 text-violet-700 shadow-sm"
                                : "border-slate-200 bg-white text-slate-600 hover:border-violet-300 hover:bg-violet-50"
                            }`}
                          >
                            <span className="font-semibold">{freq.label}</span>
                            <span className={`text-xs font-normal ${recurringForm.frequency === freq.value ? "text-violet-500" : "text-slate-400"}`}>
                              {freq.description}
                            </span>
                          </button>
                        ))}
                      </div>
                      {errors.frequency && <p className="text-xs text-red-500 mt-1">{errors.frequency}</p>}
                    </div>

                    {/* Start Date */}
                    <div className="space-y-1.5">
                      <Label htmlFor="startDate" className="text-sm font-semibold text-slate-700 flex items-center gap-1.5">
                        <CalendarIcon className="w-3.5 h-3.5 text-violet-500" />
                        Start Date <span className="text-red-500">*</span>
                      </Label>
                      <Input
                        id="startDate"
                        type="date"
                        value={recurringForm.startDate}
                        onChange={(e) => updateRecurringField("startDate", e.target.value)}
                        className={`bg-white border-slate-200 focus-visible:ring-violet-400 ${errors.startDate ? "border-red-400" : ""}`}
                      />
                      {errors.startDate && <p className="text-xs text-red-500 mt-1">{errors.startDate}</p>}
                    </div>

                    {/* End Date (Optional) */}
                    <div className="space-y-1.5">
                      <Label htmlFor="endDate" className="text-sm font-semibold text-slate-700 flex items-center gap-1.5">
                        <CalendarIcon className="w-3.5 h-3.5 text-violet-500" />
                        End Date
                        <span className="text-xs font-normal text-slate-400 ml-1">(optional)</span>
                      </Label>
                      <Input
                        id="endDate"
                        type="date"
                        value={recurringForm.endDate}
                        min={recurringForm.startDate}
                        onChange={(e) => updateRecurringField("endDate", e.target.value)}
                        className={`bg-white border-slate-200 focus-visible:ring-violet-400 ${errors.endDate ? "border-red-400" : ""}`}
                      />
                      {errors.endDate ? (
                        <p className="text-xs text-red-500 mt-1">{errors.endDate}</p>
                      ) : (
                        <p className="text-xs text-slate-400">Leave empty for an ongoing recurring expense</p>
                      )}
                    </div>

                    {/* Summary Preview */}
                    {recurringForm.frequency && recurringForm.startDate && (
                      <div className="bg-white rounded-lg border border-violet-200 p-3">
                        <p className="text-xs font-semibold text-violet-700 mb-1">Summary</p>
                        <p className="text-xs text-slate-600">
                          This expense will repeat{" "}
                          <span className="font-semibold text-violet-600">{recurringForm.frequency}</span>{" "}
                          starting{" "}
                          <span className="font-semibold text-slate-700">
                            {new Date(recurringForm.startDate + "T00:00:00").toLocaleDateString("en-US", {
                              month: "long",
                              day: "numeric",
                              year: "numeric",
                            })}
                          </span>
                          {recurringForm.endDate ? (
                            <>
                              {" "}until{" "}
                              <span className="font-semibold text-slate-700">
                                {new Date(recurringForm.endDate + "T00:00:00").toLocaleDateString("en-US", {
                                  month: "long",
                                  day: "numeric",
                                  year: "numeric",
                                })}
                              </span>
                            </>
                          ) : (
                            " with no end date"
                          )}
                          .
                        </p>
                      </div>
                    )}
                  </div>
                )}
              </div>

              {/* Submit Button */}
              <div className="pt-2 space-y-2">
                <Button
                  type="submit"
                  disabled={isSubmitting}
                  className="w-full h-12 bg-violet-600 hover:bg-violet-700 text-white font-semibold text-base shadow-md shadow-violet-200 transition-all"
                >
                  {isSubmitting ? (
                    <span className="flex items-center gap-2">
                      <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
                      </svg>
                      Saving...
                    </span>
                  ) : (
                    <span className="flex items-center gap-2">
                      <DollarSign className="w-4 h-4" />
                      {isRecurring ? "Add Recurring Expense" : "Add Expense"}
                    </span>
                  )}
                </Button>
                <Button
                  type="button"
                  variant="ghost"
                  onClick={handleReset}
                  className="w-full text-slate-500 hover:text-slate-700"
                >
                  Clear Form
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>

        <p className="text-center text-xs text-slate-400 mt-4">
          CashPulse — Smart expense tracking
        </p>
      </div>
    </div>
  );
}
