  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Separator } from "@/components/ui/separator";
import { CalendarIcon, RefreshCw, DollarSign, CreditCard, FileText, Tag } from "lucide-react";

type PaymentMethod = "cash" | "credit_card" | "debit_card" | "bank_transfer" | "digital_wallet";
type RecurringFrequency = "weekly" | "monthly" | "yearly";
type RecurringStatus = "active" | "paused" | "completed";

interface Category {
  id: string;
  name: string;
  color: string;
}

interface ExpenseFormData {
  amount: string;
  categoryId: string;
  merchantName: string;
  date: string;
  paymentMethod: PaymentMethod | "";
  note: string;
  recurringTemplateId?: string;
}

interface RecurringTemplateData {
  frequency: RecurringFrequency | "";
  startDate: string;
  endDate: string;
  status: RecurringStatus;
}

const MOCK_CATEGORIES: Category[] = [
  { id: "cat_1", name: "Food & Dining", color: "#f97316" },
  { id: "cat_2", name: "Transportation", color: "#3b82f6" },
  { id: "cat_3", name: "Shopping", color: "#8b5cf6" },
  { id: "cat_4", name: "Entertainment", color: "#ec4899" },
  { id: "cat_5", name: "Bills & Utilities", color: "#14b8a6" },
  { id: "cat_6", name: "Healthcare", color: "#ef4444" },
  { id: "cat_7", name: "Travel", color: "#f59e0b" },
  { id: "cat_8", name: "Other", color: "#6b7280" },
];

const PAYMENT_METHODS: { value: PaymentMethod; label: string }[] = [
  { value: "cash", label: "Cash" },
  { value: "credit_card", label: "Credit Card" },
  { value: "debit_card", label: "Debit Card" },
  { value: "bank_transfer", label: "Bank Transfer" },
  { value: "digital_wallet", label: "Digital Wallet" },
];

const FREQUENCIES: { value: RecurringFrequency; label: string; description: string }[] = [
  { value: "weekly", label: "Weekly", description: "Repeats every week" },
  { value: "monthly", label: "Monthly", description: "Repeats every month" },
  { value: "yearly", label: "Yearly", description: "Repeats every year" },
];

const AddExpenseForm: React.FC = () => {
  const today = new Date().toISOString().split("T")[0];

  const [expenseForm, setExpenseForm] = useState<ExpenseFormData>({
    amount: "",
    categoryId: "",
    merchantName: "",
    date: today,
    paymentMethod: "",
    note: "",
  });

  const [isRecurring, setIsRecurring] = useState(false);

  const [recurringForm, setRecurringForm] = useState<RecurringTemplateData>({
    frequency: "",
    startDate: today,
    endDate: "",
    status: "active",
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);

  const handleExpenseChange = (field: keyof ExpenseFormData, value: string) => {
    setExpenseForm((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => {
        const next = { ...prev };
        delete next[field];
        return next;
      });
    }
  };

  const handleRecurringChange = (field: keyof RecurringTemplateData, value: string) => {
    setRecurringForm((prev) => ({ ...prev, [field]: value }));
    if (errors[`recurring_${field}`]) {
      setErrors((prev) => {
        const next = { ...prev };
        delete next[`recurring_${field}`];
        return next;
      });
    }
  };

  const handleRecurringToggle = (checked: boolean) => {
    setIsRecurring(checked);
    if (!checked) {
      setErrors((prev) => {
        const next = { ...prev };
        Object.keys(next).forEach((key) => {
          if (key.startsWith("recurring_")) delete next[key];
        });
        return next;
      });
    }
  };

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!expenseForm.amount || isNaN(Number(expenseForm.amount)) || Number(expenseForm.amount) <= 0) {
      newErrors.amount = "Please enter a valid amount greater than 0";
    }
    if (!expenseForm.categoryId) {
      newErrors.categoryId = "Please select a category";
    }
    if (!expenseForm.date) {
      newErrors.date = "Please select a date";
    }
    if (!expenseForm.paymentMethod) {
      newErrors.paymentMethod = "Please select a payment method";
    }

    if (isRecurring) {
      if (!recurringForm.frequency) {
        newErrors.recurring_frequency = "Please select a frequency";
      }
      if (!recurringForm.startDate) {
        newErrors.recurring_startDate = "Please select a start date";
      }
      if (recurringForm.endDate && recurringForm.startDate && recurringForm.endDate < recurringForm.startDate) {
        newErrors.recurring_endDate = "End date must be after start date";
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setIsSubmitting(true);

    // Simulate API call
    await new Promise((resolve) => setTimeout(resolve, 1200));

    const expensePayload = {
      id: `exp_${Date.now()}`,
      amount: Number(expenseForm.amount),
      categoryId: expenseForm.categoryId,
      merchantName: expenseForm.merchantName,
      date: expenseForm.date,
      paymentMethod: expenseForm.paymentMethod,
      note: expenseForm.note,
      ...(isRecurring && { recurringTemplateId: `rt_${Date.now()}` }),
    };

    const recurringPayload = isRecurring
      ? {
          id: `rt_${Date.now()}`,
          amount: Number(expenseForm.amount),
          categoryId: expenseForm.categoryId,
          merchantName: expenseForm.merchantName,
          frequency: recurringForm.frequency,
          startDate: recurringForm.startDate,
          endDate: recurringForm.endDate || null,
          nextOccurrence: recurringForm.startDate,
          paymentMethod: expenseForm.paymentMethod,
          note: expenseForm.note,
          status: recurringForm.status,
          createdAt: new Date().toISOString(),
        }
      : null;

    console.log("Expense payload:", expensePayload);
    if (recurringPayload) console.log("RecurringTemplate payload:", recurringPayload);

    setIsSubmitting(false);
    setSubmitSuccess(true);

    setTimeout(() => {
      setSubmitSuccess(false);
      setExpenseForm({
        amount: "",
        categoryId: "",
        merchantName: "",
        date: today,
        paymentMethod: "",
        note: "",
      });
      setRecurringForm({
        frequency: "",
        startDate: today,
        endDate: "",
        status: "active",
      });
      setIsRecurring(false);
    }, 2000);
  };

  const selectedCategory = MOCK_CATEGORIES.find((c) => c.id === expenseForm.categoryId);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 p-4 md:p-8">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="mb-6">
          <div className="flex items-center gap-2 mb-1">
            <div className="w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center">
              <DollarSign className="w-4 h-4 text-white" />
            </div>
            <span className="text-sm font-semibold text-emerald-600 tracking-wide uppercase">CashPulse</span>
          </div>
          <h1 className="text-2xl font-bold text-slate-900">Add Expense</h1>
          <p className="text-slate-500 text-sm mt-1">Track your spending and set up recurring payments</p>
        </div>

        {submitSuccess && (
          <div className="mb-4 p-4 bg-emerald-50 border border-emerald-200 rounded-lg flex items-center gap-3">
            <div className="w-5 h-5 rounded-full bg-emerald-500 flex items-center justify-center flex-shrink-0">
              <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <p className="text-emerald-700 text-sm font-medium">
              Expense {isRecurring ? "and recurring template " : ""}saved successfully!
            </p>
          </div>
        )}

        <form onSubmit={handleSubmit} noValidate>
          {/* Main Expense Card */}
          <Card className="shadow-sm border-slate-200 mb-4">
            <CardHeader className="pb-4">
              <CardTitle className="text-base font-semibold text-slate-800 flex items-center gap-2">
                <FileText className="w-4 h-4 text-slate-500" />
                Expense Details
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-5">
              {/* Amount */}
              <div className="space-y-1.5">
                <Label htmlFor="amount" className="text-sm font-medium text-slate-700">
                  Amount <span className="text-red-500">*</span>
                </Label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 font-medium text-sm">$</span>
                  <Input
                    id="amount"
                    type="number"
                    step="0.01"
                    min="0"
                    placeholder="0.00"
                    value={expenseForm.amount}
                    onChange={(e) => handleExpenseChange("amount", e.target.value)}
                    className={`pl-7 text-lg font-semibold ${errors.amount ? "border-red-400 focus-visible:ring-red-400" : ""}`}
                  />
                </div>
                {errors.amount && <p className="text-xs text-red-500">{errors.amount}</p>}
              </div>

              {/* Merchant Name */}
              <div className="space-y-1.5">
                <Label htmlFor="merchantName" className="text-sm font-medium text-slate-700">
                  Merchant / Payee
                </Label>
                <Input
                  id="merchantName"
                  type="text"
                  placeholder="e.g. Starbucks, Netflix, Amazon..."
                  value={expenseForm.merchantName}
                  onChange={(e) => handleExpenseChange("merchantName", e.target.value)}
                />
              </div>

              {/* Category */}
              <div className="space-y-1.5">
                <Label className="text-sm font-medium text-slate-700 flex items-center gap-1.5">
                  <Tag className="w-3.5 h-3.5" />
                  Category <span className="text-red-500">*</span>
                </Label>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                  {MOCK_CATEGORIES.map((cat) => (
                    <button
                      key={cat.id}
                      type="button"
                      onClick={() => handleExpenseChange("categoryId", cat.id)}
                      className={`relative flex flex-col items-center gap-1.5 p-2.5 rounded-lg border-2 text-xs font-medium transition-all ${
                        expenseForm.categoryId === cat.id
                          ? "border-current shadow-sm"
                          : "border-slate-200 text-slate-600 hover:border-slate-300 hover:bg-slate-50"
                      }`}
                      style={
                        expenseForm.categoryId === cat.id
                          ? { borderColor: cat.color, color: cat.color, backgroundColor: `${cat.color}10` }
                          : {}
                      }
                    >
                      <div
                        className="w-3 h-3 rounded-full"
                        style={{ backgroundColor: cat.color }}
                      />
                      {cat.name}
                    </button>
                  ))}
                </div>
                {selectedCategory && (
                  <div className="flex items-center gap-1.5 mt-1">
                    <Badge
                      variant="secondary"
                      className="text-xs"
                      style={{ backgroundColor: `${selectedCategory.color}15`, color: selectedCategory.color }}
                    >
                      {selectedCategory.name} selected
                    </Badge>
                  </div>
                )}
                {errors.categoryId && <p className="text-xs text-red-500">{errors.categoryId}</p>}
              </div>

              {/* Date & Payment Method Row */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <Label htmlFor="date" className="text-sm font-medium text-slate-700 flex items-center gap-1.5">
                    <CalendarIcon className="w-3.5 h-3.5" />
                    Date <span className="text-red-500">*</span>
                  </Label>
                  <Input
                    id="date"
                    type="date"
                    value={expenseForm.date}
                    onChange={(e) => handleExpenseChange("date", e.target.value)}
                    className={errors.date ? "border-red-400 focus-visible:ring-red-400" : ""}
                  />
                  {errors.date && <p className="text-xs text-red-500">{errors.date}</p>}
                </div>

                <div className="space-y-1.5">
                  <Label className="text-sm font-medium text-slate-700 flex items-center gap-1.5">
                    <CreditCard className="w-3.5 h-3.5" />
                    Payment Method <span className="text-red-500">*</span>
                  </Label>
                  <Select
                    value={expenseForm.paymentMethod}
                    onValueChange={(val) => handleExpenseChange("paymentMethod", val)}
                  >
                    <SelectTrigger className={errors.paymentMethod ? "border-red-400 focus:ring-red-400" : ""}>
                      <SelectValue placeholder="Select method" />
                    </SelectTrigger>
                    <SelectContent>
                      {PAYMENT_METHODS.map((pm) => (
                        <SelectItem key={pm.value} value={pm.value}>
                          {pm.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {errors.paymentMethod && <p className="text-xs text-red-500">{errors.paymentMethod}</p>}
                </div>
              </div>

              {/* Note */}
              <div className="space-y-1.5">
                <Label htmlFor="note" className="text-sm font-medium text-slate-700">
                  Note <span className="text-slate-400 font-normal">(optional)</span>
                </Label>
                <Textarea
                  id="note"
                  placeholder="Add any additional details..."
                  value={expenseForm.note}
                  onChange={(e) => handleExpenseChange("note", e.target.value)}
                  rows={3}
                  className="resize-none"
                />
              </div>
            </CardContent>
          </Card>

          {/* Recurring Section */}
          <Card
            className={`shadow-sm border-2 transition-colors mb-6 ${
              isRecurring ? "border-violet-300 bg-violet-50/30" : "border-slate-200"
            }`}
          >
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div
                    className={`w-8 h-8 rounded-full flex items-center justify-center transition-colors ${
                      isRecurring ? "bg-violet-100" : "bg-slate-100"
                    }`}
                  >
                    <RefreshCw
                      className={`w-4 h-4 transition-colors ${isRecurring ? "text-violet-600" : "text-slate-400"}`}
                    />
                  </div>
                  <div>
                    <CardTitle
                      className={`text-base font-semibold transition-colors ${
                        isRecurring ? "text-violet-800" : "text-slate-700"
                      }`}
                    >
                      Make this recurring
                    </CardTitle>
                    <p className={`text-xs mt-0.5 transition-colors ${isRecurring ? "text-violet-600" : "text-slate-400"}`}>
                      Automatically track this expense on a schedule
                    </p>
                  </div>
                </div>
                <Switch
                  id="recurring-toggle"
                  checked={isRecurring}
                  onCheckedChange={handleRecurringToggle}
                  className="data-[state=checked]:bg-violet-600"
                />
              </div>
            </CardHeader>

            {isRecurring && (
              <>
                <Separator className="bg-violet-200" />
                <CardContent className="pt-5 space-y-5">
                  {/* Frequency Picker */}
                  <div className="space-y-2">
                    <Label className="text-sm font-medium text-violet-800">
                      Frequency <span className="text-red-500">*</span>
                    </Label>
                    <div className="grid grid-cols-3 gap-3">
                      {FREQUENCIES.map((freq) => (
                        <button
                          key={freq.value}
                          type="button"
                          onClick={() => handleRecurringChange("frequency", freq.value)}
                          className={`flex flex-col items-center gap-1 p-3 rounded-lg border-2 transition-all ${
                            recurringForm.frequency === freq.value
                              ? "border-violet-500 bg-violet-100 text-violet-700"
                              : "border-slate-200 bg-white text-slate-600 hover:border-violet-200 hover:bg-violet-50"
                          }`}
                        >
                          <span className="text-sm font-semibold">{freq.label}</span>
                          <span className="text-xs text-center leading-tight opacity-70">{freq.description}</span>
                        </button>
                      ))}
                    </div>
                    {errors.recurring_frequency && (
                      <p className="text-xs text-red-500">{errors.recurring_frequency}</p>
                    )}
                  </div>

                  {/* Start Date & End Date */}
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <Label htmlFor="startDate" className="text-sm font-medium text-violet-800 flex items-center gap-1.5">
                        <CalendarIcon className="w-3.5 h-3.5" />
                        Start Date <span className="text-red-500">*</span>
                      </Label>
                      <Input
                        id="startDate"
                        type="date"
                        value={recurringForm.startDate}
                        onChange={(e) => handleRecurringChange("startDate", e.target.value)}
                        className={`bg-white ${
                          errors.recurring_startDate ? "border-red-400 focus-visible:ring-red-400" : "border-violet-200 focus-visible:ring-violet-400"
                        }`}
                      />
                      {errors.recurring_startDate && (
                        <p className="text-xs text-red-500">{errors.recurring_startDate}</p>
                      )}
                    </div>

                    <div className="space-y-1.5">
                      <Label htmlFor="endDate" className="text-sm font-medium text-violet-800 flex items-center gap-1.5">
                        <CalendarIcon className="w-3.5 h-3.5" />
                        End Date{" "}
                        <span className="text-violet-400 font-normal text-xs">(optional)</span>
                      </Label>
                      <Input
                        id="endDate"
                        type="date"
                        value={recurringForm.endDate}
                        min={recurringForm.startDate}
                        onChange={(e) => handleRecurringChange("endDate", e.target.value)}
                        className={`bg-white ${
                          errors.recurring_endDate ? "border-red-400 focus-visible:ring-red-400" : "border-violet-200 focus-visible:ring-violet-400"
                        }`}
                      />
                      {errors.recurring_endDate ? (
                        <p className="text-xs text-red-500">{errors.recurring_endDate}</p>
                      ) : (
                        <p className="text-xs text-violet-500">Leave blank for no end date</p>
                      )}
                    </div>
                  </div>

                  {/* Summary Badge */}
                  {recurringForm.frequency && recurringForm.startDate && (
                    <div className="flex items-center gap-2 p-3 bg-violet-100 rounded-lg border border-violet-200">
                      <RefreshCw className="w-4 h-4 text-violet-600 flex-shrink-0" />
                      <p className="text-sm text-violet-700">
                        <span className="font-semibold">
                          {expenseForm.amount ? `$${Number(expenseForm.amount).toFixed(2)}` : "This expense"}
                        </span>{" "}
                        will repeat{" "}
                        <span className="font-semibold">{recurringForm.frequency}</span> starting{" "}
                        <span className="font-semibold">
                          {new Date(recurringForm.startDate + "T00:00:00").toLocaleDateString("en-US", {
                            month: "short",
                            day: "numeric",
                            year: "numeric",
                          })}
                        </span>
                        {recurringForm.endDate && (
                          <>
                            {" "}until{" "}
                            <span className="font-semibold">
                              {new Date(recurringForm.endDate + "T00:00:00").toLocaleDateString("en-US", {
                                month: "short",
                                day: "numeric",
                                year: "numeric",
                              })}
                            </span>
                          </>
                        )}
                        .
                      </p>
                    </div>
                  )}
                </CardContent>
              </>
            )}
          </Card>

          {/* Submit Actions */}
          <div className="flex flex-col sm:flex-row gap-3">
            <Button
              type="button"
              variant="outline"
              className="flex-1 sm:flex-none sm:w-32"
              onClick={() => {
                setExpenseForm({
                  amount: "",
                  categoryId: "",
                  merchantName: "",
                  date: today,
                  paymentMethod: "",
                  note: "",
                });
                setRecurringForm({ frequency: "", startDate: today, endDate: "", status: "active" });
                setIsRecurring(false);
                setErrors({});
              }}
            >
              Clear
            </Button>
            <Button
              type="submit"
              disabled={isSubmitting || submitSuccess}
              className={`flex-1 font-semibold transition-all ${
                isRecurring
                  ? "bg-violet-600 hover:bg-violet-700 text-white"
                  : "bg-emerald-600 hover:bg-emerald-700 text-white"
              }`}
            >
              {isSubmitting ? (
                <span className="flex items-center gap-2">
                  <svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
                  </svg>
                  Saving...
                </span>
              ) : submitSuccess ? (
                "Saved!"
              ) : isRecurring ? (
                <span className="flex items-center gap-2">
                  <RefreshCw className="w-4 h-4" />
                  Save Expense & Schedule
                </span>
              ) : (
                <span className="flex items-center gap-2">
                  <DollarSign className="w-4 h-4" />
                  Save Expense
                </span>
              )}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddExpenseForm;
