```tsx
import React, { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Separator } from "@/components/ui/separator";
import { CalendarIcon, RepeatIcon, DollarSignIcon, CreditCardIcon } from "lucide-react";

type PaymentMethod = "cash" | "credit_card" | "debit_card" | "bank_transfer" | "digital_wallet";
type Frequency = "weekly" | "monthly" | "yearly";
type RecurringStatus = "active" | "paused" | "ended";

interface Category {
  id: string;
  name: string;
  color: string;
}

interface ExpenseFormData {
  amount: string;
  categoryId: string;
  merchantName: string;
  date: string;
  paymentMethod: PaymentMethod | "";
  note: string;
  recurringTemplateId?: string;
}

interface RecurringTemplateData {
  frequency: Frequency | "";
  startDate: string;
  endDate: string;
  status: RecurringStatus;
}

const MOCK_CATEGORIES: Category[] = [
  { id: "cat_1", name: "Food & Dining", color: "#f97316" },
  { id: "cat_2", name: "Transportation", color: "#3b82f6" },
  { id: "cat_3", name: "Entertainment", color: "#8b5cf6" },
  { id: "cat_4", name: "Utilities", color: "#10b981" },
  { id: "cat_5", name: "Healthcare", color: "#ef4444" },
  { id: "cat_6", name: "Shopping", color: "#f59e0b" },
];

const PAYMENT_METHODS: { value: PaymentMethod; label: string }[] = [
  { value: "cash", label: "Cash" },
  { value: "credit_card", label: "Credit Card" },
  { value: "debit_card", label: "Debit Card" },
  { value: "bank_transfer", label: "Bank Transfer" },
  { value: "digital_wallet", label: "Digital Wallet" },
];

const FREQUENCIES: { value: Frequency; label: string; description: string }[] = [
  { value: "weekly", label: "Weekly", description: "Repeats every week" },
  { value: "monthly", label: "Monthly", description: "Repeats every month" },
  { value: "yearly", label: "Yearly", description: "Repeats every year" },
];

export default function AddExpenseForm() {
  const today = new Date().toISOString().split("T")[0];

  const [formData, setFormData] = useState<ExpenseFormData>({
    amount: "",
    categoryId: "",
    merchantName: "",
    date: today,
    paymentMethod: "",
    note: "",
  });

  const [isRecurring, setIsRecurring] = useState(false);

  const [recurringData, setRecurringData] = useState<RecurringTemplateData>({
    frequency: "",
    startDate: today,
    endDate: "",
    status: "active",
  });

  const [errors, setErrors] = useState<Partial<Record<string, string>>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleFormChange = (field: keyof ExpenseFormData, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => ({ ...prev, [field]: undefined }));
    }
  };

  const handleRecurringChange = (field: keyof RecurringTemplateData, value: string) => {
    setRecurringData((prev) => ({ ...prev, [field]: value }));
    if (errors[`recurring_${field}`]) {
      setErrors((prev) => ({ ...prev, [`recurring_${field}`]: undefined }));
    }
  };

  const validate = (): boolean => {
    const newErrors: Partial<Record<string, string>> = {};

    if (!formData.amount || isNaN(Number(formData.amount)) || Number(formData.amount) <= 0) {
      newErrors.amount = "Please enter a valid amount greater than 0";
    }
    if (!formData.categoryId) {
      newErrors.categoryId = "Please select a category";
    }
    if (!formData.date) {
      newErrors.date = "Please select a date";
    }
    if (!formData.paymentMethod) {
      newErrors.paymentMethod = "Please select a payment method";
    }

    if (isRecurring) {
      if (!recurringData.frequency) {
        newErrors.recurring_frequency = "Please select a frequency";
      }
      if (!recurringData.startDate) {
        newErrors.recurring_startDate = "Please select a start date";
      }
      if (recurringData.endDate && recurringData.startDate && recurringData.endDate < recurringData.startDate) {
        newErrors.recurring_endDate = "End date must be after start date";
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setIsSubmitting(true);

    // Simulate API call
    await new Promise((resolve) => setTimeout(resolve, 1200));

    const expensePayload = {
      id: `exp_${Date.now()}`,
      amount: Number(formData.amount),
      categoryId: formData.categoryId,
      merchantName: formData.merchantName,
      date: formData.date,
      paymentMethod: formData.paymentMethod,
