import React from "react";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";

type PaymentMethod = "cash" | "credit_card" | "debit_card" | "bank_transfer" | "other";
type RecurringFrequency = "weekly" | "monthly" | "yearly";
type RecurringStatus = "active" | "paused" | "cancelled";

interface RecurringTemplate {
  id: string;
  amount: number;
  categoryId: string;
  merchantName: string;
  frequency: RecurringFrequency;
  startDate: Date;
  endDate?: Date;
  nextOccurrence: Date;
  paymentMethod: PaymentMethod;
  note?: string;
  status: RecurringStatus;
  createdAt: Date;
}

interface Expense {
  id: string;
  amount: number;
  categoryId: string;
  merchantName: string;
  date: Date;
  paymentMethod: PaymentMethod;
  note?: string;
  recurringTemplateId?: string;
}

interface ExpenseListProps {
  expenses: Expense[];
  recurringTemplates: RecurringTemplate[];
  categories?: Record<string, string>;
}

const frequencyVariantMap: Record<RecurringFrequency, string> = {
  weekly: "bg-blue-100 text-blue-700 border-blue-200",
  monthly: "bg-purple-100 text-purple-700 border-purple-200",
  yearly: "bg-green-100 text-green-700 border-green-200",
};

const RecurringBadge: React.FC<{ frequency: RecurringFrequency }> = ({ frequency }) => {
  const colorClass = frequencyVariantMap[frequency] ?? "bg-gray-100 text-gray-700 border-gray-200";
  return (
    <span
      className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium border ${colorClass} capitalize`}
    >
      {frequency}
    </span>
  );
};

const formatCurrency = (amount: number): string =>
  new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" }).format(amount);

const formatDate = (date: Date): string =>
  new Intl.DateTimeFormat("en-US", { month: "short", day: "numeric", year: "numeric" }).format(
    new Date(date)
  );

const ExpenseList: React.FC<ExpenseListProps> = ({
  expenses,
  recurringTemplates,
  categories = {},
}) => {
  const templateMap = React.useMemo(() => {
    const map: Record<string, RecurringTemplate> = {};
    for (const template of recurringTemplates) {
      map[template.id] = template;
    }
    return map;
  }, [recurringTemplates]);

  return (
    <Card className="w-full">
      <CardHeader>
        <CardTitle className="text-lg font-semibold text-gray-900">Recent Expenses</CardTitle>
      </CardHeader>
      <CardContent className="p-0">
        {expenses.length === 0 ? (
          <div className="px-6 py-8 text-center text-sm text-gray-500">No expenses found.</div>
        ) : (
          <ul className="divide-y divide-gray-100">
            {expenses.map((expense) => {
              const template = expense.recurringTemplateId
                ? templateMap[expense.recurringTemplateId]
                : undefined;
              const categoryLabel = categories[expense.categoryId] ?? expense.categoryId;

              return (
                <li
                  key={expense.id}
                  className="flex items-center justify-between px-6 py-4 hover:bg-gray-50 transition-colors"
                >
                  {/* Left: description + category + date */}
                  <div className="flex flex-col gap-0.5 min-w-0">
                    <span className="text-sm font-medium text-gray-900 truncate">
                      {expense.merchantName}
                    </span>
                    <div className="flex items-center gap-2 flex-wrap">
                      <Badge variant="secondary" className="text-xs px-1.5 py-0 h-5">
                        {categoryLabel}
                      </Badge>
                      <span className="text-xs text-gray-400">{formatDate(expense.date)}</span>
                    </div>
                    {expense.note && (
                      <span className="text-xs text-gray-400 truncate max-w-xs">{expense.note}</span>
                    )}
                  </div>

                  {/* Right: amount + recurring badge */}
                  <div className="flex items-center gap-2 ml-4 shrink-0">
                    {template && <RecurringBadge frequency={template.frequency} />}
                    <span className="text-sm font-semibold text-gray-900 tabular-nums">
                      {formatCurrency(expense.amount)}
                    </span>
                  </div>
                </li>
              );
            })}
          </ul>
        )}
      </CardContent>
    </Card>
  );
};

