import React, { useEffect, useState } from "react";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";

// ── Types ────────────────────────────────────────────────────────────────────

type BudgetStatus = "On Track" | "Heads Up" | "Over Budget";

interface MonthSummary {
  id: string;
  month: string;
  totalSpent: number;
  transactionCount: number;
  dailyAverage: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
  remainingAmount: number;
  updatedAt: string;
}

interface BudgetSummaryCardProps {
  monthSummary: MonthSummary;
  currency?: string;
  animateOnMount?: boolean;
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function formatCurrency(amount: number, currency = "USD"): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency,
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(amount);
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

// ── Sub-components ───────────────────────────────────────────────────────────

interface StatusBadgeProps {
  status: BudgetStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const variantMap: Record<
    BudgetStatus,
    { bg: string; text: string; dot: string }
  > = {
    "On Track": {
      bg: "bg-blue-100",
      text: "text-blue-700",
      dot: "bg-blue-500",
    },
    "Heads Up": {
      bg: "bg-amber-100",
      text: "text-amber-700",
      dot: "bg-amber-500",
    },
    "Over Budget": {
      bg: "bg-red-100",
      text: "text-red-700",
      dot: "bg-red-500",
    },
  };

  const { bg, text, dot } = variantMap[status];

  return (
    <span
      className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${bg} ${text}`}
    >
      <span className={`w-1.5 h-1.5 rounded-full ${dot}`} />
      {status}
    </span>
  );
};

// ── Animated Counter ─────────────────────────────────────────────────────────

interface AnimatedAmountDisplayProps {
  amount: number;
  currency: string;
  label: string;
  animate: boolean;
}

const AnimatedAmountDisplay: React.FC<AnimatedAmountDisplayProps> = ({
  amount,
  currency,
  label,
  animate,
}) => {
  const [displayed, setDisplayed] = useState(animate ? 0 : amount);

  useEffect(() => {
    if (!animate) {
      setDisplayed(amount);
      return;
    }
    const duration = 900;
    const steps = 60;
    const stepDuration = duration / steps;
    let current = 0;
    const increment = amount / steps;

    const timer = setInterval(() => {
      current += increment;
      if (current >= amount) {
        setDisplayed(amount);
        clearInterval(timer);
      } else {
        setDisplayed(current);
      }
    }, stepDuration);

    return () => clearInterval(timer);
  }, [amount, animate]);

  return (
    <div className="flex flex-col gap-0.5">
      <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">
        {label}
      </p>
      <p
        className="text-4xl font-bold text-gray-900 tabular-nums font-[Inter,sans-serif] leading-tight"
        aria-live="polite"
      >
        {formatCurrency(displayed, currency)}
      </p>
    </div>
  );
};

// ── Progress Bar ─────────────────────────────────────────────────────────────

interface BudgetProgressBarProps {
  spentAmount: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
  animate: boolean;
}

const BudgetProgressBar: React.FC<BudgetProgressBarProps> = ({
  spentAmount,
  budgetLimit,
  budgetStatus,
  animate,
}) => {
  const rawPercentage =
    budgetLimit > 0 ? (spentAmount / budgetLimit) * 100 : 0;
  const displayPercentage = clamp(rawPercentage, 0, 100);

  const [width, setWidth] = useState(animate ? 0 : displayPercentage);

  useEffect(() => {
    if (!animate) {
      setWidth(displayPercentage);
      return;
    }
    const timeout = setTimeout(() => setWidth(displayPercentage), 100);
    return () => clearTimeout(timeout);
  }, [displayPercentage, animate]);

  const fillColor =
    budgetStatus === "Over Budget"
      ? "bg-red-500"
      : budgetStatus === "Heads Up"
      ? "bg-amber-500"
      : "bg-blue-600";

  return (
    <div className="flex flex-col gap-1.5">
      <div className="flex justify-between items-center">
        <span className="text-xs text-gray-500">Budget used</span>
        <span className="text-xs font-semibold text-gray-700 tabular-nums">
          {rawPercentage.toFixed(0)}%
        </span>
      </div>
      <div
        className="w-full h-2 bg-gray-200 rounded-full overflow-hidden"
        role="progressbar"
        aria-valuenow={Math.round(rawPercentage)}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label="Budget progress"
      >
        <div
          className={`h-full rounded-full transition-all duration-700 ease-out ${fillColor}`}
          style={{ width: `${width}%` }}
        />
      </div>
    </div>
  );
};

// ── Remaining Display ────────────────────────────────────────────────────────

interface BudgetRemainingDisplayProps {
  remainingAmount: number;
  currency: string;
  isOverBudget: boolean;
  dailyAverage: number;
  transactionCount: number;
  budgetLimit: number;
}

const BudgetRemainingDisplay: React.FC<BudgetRemainingDisplayProps> = ({
  remainingAmount,
  currency,
  isOverBudget,
  dailyAverage,
  transactionCount,
  budgetLimit,
}) => {
  const amountColor = isOverBudget ? "text-red-500" : "text-gray-700";
  const label = isOverBudget ? "Over budget by" : "Remaining";

  return (
    <div className="grid grid-cols-3 gap-3 pt-1">
      {/* Remaining */}
      <div className="flex flex-col gap-0.5">
        <p className="text-xs text-gray-500">{label}</p>
        <p
          className={`text-sm font-semibold tabular-nums font-[Inter,sans-serif] ${amountColor}`}
        >
          {formatCurrency(Math.abs(remainingAmount), currency)}
        </p>
      </div>

      {/* Daily Average */}
      <div className="flex flex-col gap-0.5">
        <p className="text-xs text-gray-500">Daily avg</p>
        <p className="text-sm font-semibold text-gray-700 tabular-nums font-[Inter,sans-serif]">
          {formatCurrency(dailyAverage, currency)}
        </p>
      </div>

      {/* Transactions */}
      <div className="flex flex-col gap-0.5">
        <p className="text-xs text-gray-500">Transactions</p>
        <p className="text-sm font-semibold text-gray-700 tabular-nums font-[Inter,sans-serif]">
          {transactionCount}
        </p>
      </div>
    </div>
  );
};

// ── Main Component ───────────────────────────────────────────────────────────

const BudgetSummaryCard: React.FC<BudgetSummaryCardProps> = ({
  monthSummary,
  currency = "USD",
  animateOnMount = true,
}) => {
  const {
    month,
    totalSpent,
    transactionCount,
    dailyAverage,
    budgetLimit,
    budgetStatus,
    remainingAmount,
  } = monthSummary;

  const isOverBudget = budgetStatus === "Over Budget";

  // Format month label e.g. "2024-05" → "May 2024"
  const monthLabel = (() => {
    try {
      const [year, monthNum] = month.split("-");
      const date = new Date(Number(year), Number(monthNum) - 1, 1);
      return date.toLocaleDateString("en-US", {
        month: "long",
        year: "numeric",
      });
    } catch {
      return month;
    }
  })();

  return (
    <Card className="w-full bg-white rounded-2xl shadow-md border-0">
      <CardHeader className="pb-3 px-6 pt-6">
        <div className="flex items-center justify-between">
          <div className="flex flex-col gap-0.5">
            <h2 className="text-base font-semibold text-gray-900 font-[Inter,sans-serif]">
              Monthly Summary
            </h2>
