import React, { useEffect, useState } from "react";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";

// --- Types ---

type BudgetStatus = "On Track" | "Heads Up" | "Over Budget";

interface MonthSummary {
  id: string;
  month: string;
  totalSpent: number;
  transactionCount: number;
  dailyAverage: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
  remainingAmount: number;
  updatedAt: string;
}

interface BudgetSummaryCardProps {
  monthSummary: MonthSummary;
  currency: string;
  animateOnMount?: boolean;
}

// --- Helpers ---

function formatCurrency(amount: number, currency: string): string {
  try {
    return new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: currency || "USD",
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(amount);
  } catch {
    return `${currency} ${amount.toFixed(2)}`;
  }
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

// --- Sub-components ---

interface StatusBadgeProps {
  status: BudgetStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const variantStyles: Record<BudgetStatus, { bg: string; text: string; dot: string }> = {
    "On Track": {
      bg: "bg-blue-100",
      text: "text-blue-700",
      dot: "bg-blue-500",
    },
    "Heads Up": {
      bg: "bg-amber-100",
      text: "text-amber-700",
      dot: "bg-amber-500",
    },
    "Over Budget": {
      bg: "bg-red-100",
      text: "text-red-700",
      dot: "bg-red-500",
    },
  };

  const styles = variantStyles[status];

  return (
    <span
      className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${styles.bg} ${styles.text}`}
      aria-label={`Budget status: ${status}`}
    >
      <span className={`w-1.5 h-1.5 rounded-full ${styles.dot}`} aria-hidden="true" />
      {status}
    </span>
  );
};

interface AnimatedAmountDisplayProps {
  amount: number;
  currency: string;
  label: string;
  animateCounter?: boolean;
}

const AnimatedAmountDisplay: React.FC<AnimatedAmountDisplayProps> = ({
  amount,
  currency,
  label,
  animateCounter = true,
}) => {
  const [displayAmount, setDisplayAmount] = useState(animateCounter ? 0 : amount);

  useEffect(() => {
    if (!animateCounter) {
      setDisplayAmount(amount);
      return;
    }

    const duration = 800;
    const steps = 40;
    const stepDuration = duration / steps;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      const progress = currentStep / steps;
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayAmount(amount * eased);

      if (currentStep >= steps) {
        clearInterval(timer);
        setDisplayAmount(amount);
      }
    }, stepDuration);

    return () => clearInterval(timer);
  }, [amount, animateCounter]);

  return (
    <div className="flex flex-col gap-1">
      <p className="text-sm font-medium text-gray-500">{label}</p>
      <p
        className="text-4xl font-bold text-gray-900 font-[Inter] tabular-nums tracking-tight"
        aria-label={`${label}: ${formatCurrency(amount, currency)}`}
      >
        {formatCurrency(displayAmount, currency)}
      </p>
    </div>
  );
};

interface BudgetProgressBarProps {
  spentAmount: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
}

const BudgetProgressBar: React.FC<BudgetProgressBarProps> = ({
  spentAmount,
  budgetLimit,
  budgetStatus,
}) => {
  const spendPercentage = budgetLimit > 0 ? (spentAmount / budgetLimit) * 100 : 0;
  const clampedPercentage = clamp(spendPercentage, 0, 100);

  const fillColorClass =
    budgetStatus === "Over Budget"
      ? "bg-red-500"
      : budgetStatus === "Heads Up"
      ? "bg-amber-500"
      : "bg-blue-600";

  return (
    <div className="flex flex-col gap-1.5">
      <div className="flex justify-between items-center text-xs text-gray-500">
        <span className="tabular-nums font-medium">
          {formatCurrency(spentAmount, "")} spent
        </span>
        <span className="tabular-nums font-medium">
          {Math.round(clampedPercentage)}% of budget
        </span>
      </div>
      <div
        className="w-full h-2 bg-gray-200 rounded-full overflow-hidden"
        role="progressbar"
        aria-valuenow={Math.round(clampedPercentage)}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label="Budget usage progress"
      >
        <div
          className={`h-full rounded-full transition-all duration-700 ease-out ${fillColorClass}`}
          style={{ width: `${clampedPercentage}%` }}
        />
      </div>
    </div>
  );
};

interface BudgetRemainingDisplayProps {
  remainingAmount: number;
  currency: string;
  isOverBudget: boolean;
}

const BudgetRemainingDisplay: React.FC<BudgetRemainingDisplayProps> = ({
  remainingAmount,
  currency,
  isOverBudget,
}) => {
  const textColorClass = isOverBudget ? "text-red-500" : "text-gray-600";
  const label = isOverBudget ? "Over budget by" : "Remaining";
  const displayAmount = Math.abs(remainingAmount);

  return (
    <div className="flex items-center justify-between py-2 border-t border-gray-100">
      <span className="text-sm text-gray-500 font-medium">{label}</span>
      <span
        className={`text-sm font-semibold tabular-nums font-[Inter] ${textColorClass}`}
        aria-label={`${label}: ${formatCurrency(displayAmount, currency)}`}
      >
        {isOverBudget ? "+" : ""}
        {formatCurrency(displayAmount, currency)}
      </span>
    </div>
  );
};

interface StatRowProps {
  label: string;
  value: string;
}

const StatRow: React.FC<StatRowProps> = ({ label, value }) => (
  <div className="flex items-center justify-between">
    <span className="text-sm text-gray-500">{label}</span>
    <span className="text-sm font-semibold text-gray-900 tabular-nums">{value}</span>
  </div>
);

// --- Main Component ---

