    } else if (s === "Heads Up") {
      setSummary({
        ...MOCK_MONTH_SUMMARY,
        totalSpent: 2150.0,
        remainingAmount: 350.0,
        budgetStatus: "Heads Up",
      });
    } else {
      setSummary({
        ...MOCK_MONTH_SUMMARY,
        totalSpent: 2780.0,
        remainingAmount: -280.0,
        budgetStatus: "Over Budget",
      });
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center justify-center p-8 gap-6">
      {/* Demo Controls */}
      <div className="flex gap-2">
        {(["On Track", "Heads Up", "Over Budget"] as BudgetStatus[]).map(
          (s) => (
            <button
              key={s}
              onClick={() => applyStatus(s)}
              className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-colors ${
                status === s
                  ? "bg-gray-900 text-white border-gray-900"
                  : "bg-white text-gray-600 border-gray-200 hover:border-gray-400"
              }`}
            >
              {s}
            </button>
          )
        )}
      </div>

      {/* Card */}
      <div className="w-[360px]">
        <BudgetSummaryCard
          monthSummary={summary}
          currency="USD"
          animateOnMount={true}
        />
      </div>
    </div>
  );
}

export { BudgetSummaryCard };
export type { BudgetSummaryCardProps, MonthSummary, BudgetStatus };
