// DailySpendingChart
interface DailySpendingChartProps {
  data: DailySpending[];
  mode: "bar" | "line";
  averageDaily: number;
  currency: string;
}

const DailySpendingChart: React.FC<DailySpendingChartProps> = ({ data, mode, averageDaily, currency }) => {
  const [tooltip, setTooltip] = useState<{ point: DailySpending; x: number; y: number } | null>(null);
  const svgRef = useRef<SVGSVGElement>(null);

  const W = 620;
  const H = 160;
  const PAD = { top: 16, right: 8, bottom: 28, left: 8 };
  const chartW = W - PAD.left - PAD.right;
  const chartH = H - PAD.top - PAD.bottom;

  const maxVal = Math.max(...data.map((d) => d.totalAmount), averageDaily, 1);
  const barW = chartW / data.length;

  const xPos = (i: number) => PAD.left + i * barW + barW / 2;
  const yPos = (v: number) => PAD.top + chartH - (v / maxVal) * chartH;

  const avgY = yPos(averageDaily);

  const linePath = data
    .map((d, i) => `${i === 0 ? "M" : "L"}${xPos(i)},${yPos(d.totalAmount)}`)
    .join(" ");

  const fillPath =
    linePath +
    ` L${xPos(data.length - 1)},${PAD.top + chartH} L${xPos(0)},${PAD.top + chartH} Z`;

  const handleMouseMove = (e: React.MouseEvent<SVGSVGElement>) => {
    if (!svgRef.current) return;
    const rect = svgRef.current.getBoundingClientRect();
    const relX = ((e.clientX - rect.left) / rect.width) * W;
    const idx = Math.min(Math.max(Math.floor((relX - PAD.left) / barW), 0), data.length - 1);
    const point = data[idx];
    setTooltip({ point, x: (xPos(idx) / W) * rect.width + rect.left - rect.left, y: (yPos(point.totalAmount) / H) * rect.height });
  };

  return (
    <div className="relative w-full">
      <svg
        ref={svgRef}
        viewBox={`0 0 ${W} ${H}`}
        className="w-full"
        aria-label="Daily spending chart"
        role="img"
        onMouseMove={handleMouseMove}
        onMouseLeave={() => setTooltip(null)}
      >
        {/* Average line */}
        <line
          x1={PAD.left}
          y1={avgY}
          x2={W - PAD.right}
          y2={avgY}
          stroke="#f59e0b"
          strokeWidth={1.5}
          strokeDasharray="4 3"
        />

        {mode === "bar" &&
          data.map((d, i) => {
            const barH = (d.totalAmount / maxVal) * chartH;
            const isHigh = d.totalAmount > averageDaily * 1.5;
            return (
              <rect
                key={d.date}
                x={PAD.left + i * barW + barW * 0.1}
                y={PAD.top + chartH - barH}
                width={barW * 0.8}
                height={barH}
                fill={isHigh ? "#ef4444" : "#2563eb"}
                rx={2}
                opacity={tooltip?.point.date === d.date ? 1 : 0.85}
              />
            );
          })}

        {mode === "line" && (
          <>
            <path d={fillPath} fill="#dbeafe" opacity={0.5} />
            <path d={linePath} fill="none" stroke="#2563eb" strokeWidth={2} strokeLinejoin="round" />
            {data.map((d, i) => (
              <circle
                key={d.date}
                cx={xPos(i)}
                cy={yPos(d.totalAmount)}
                r={tooltip?.point.date === d.date ? 4 : 2.5}
                fill="#2563eb"
              />
            ))}
          </>
        )}

        {/* X-axis labels (every 5 days) */}
        {data.map((d, i) =>
          i % 5 === 0 ? (
            <text
              key={d.date}
              x={xPos(i)}
              y={H - 6}
              textAnchor="middle"
              fontSize={9}
              fill="#9ca3af"
            >
              {getDayLabel(d.date)}
            </text>
          ) : null
        )}
      </svg>

      {tooltip && (
        <div
          className="absolute z-10 pointer-events-none bg-white rounded-lg shadow-lg border border-gray-100 p-2 text-xs text-gray-900 whitespace-nowrap"
          style={{
            left: `calc(${(tooltip.x / (svgRef.current?.clientWidth ?? 620)) * 100}% )`,
            top: `${(tooltip.y / (svgRef.current?.clientHeight ?? 160)) * 100}%`,
            transform: "translate(-50%, -120%)",
          }}
        >
          <div className="font-semibold">{formatDate(tooltip.point.date)}</div>
          <div className="tabular-nums">{formatCurrency(tooltip.point.totalAmount, currency)}</div>
          <div className="text-gray-500">{tooltip.point.transactionCount} txn{tooltip.point.transactionCount !== 1 ? "s" : ""}</div>
        </div>
      )}

      <div className="flex items-center gap-1 mt-1 text-xs text-amber-600">
        <span className="inline-block w-4 border-t-2 border-dashed border-amber-500" />
        <span>Avg {formatCurrency(averageDaily, currency)}/day</span>
      </div>
    </div>
  );
};

