// ─── Mock Data ────────────────────────────────────────────────────────────────

const MOCK_CATEGORIES: Category[] = [
  { id: "cat-1", name: "Food & Dining", color: "#f97316", icon: "🍔", isDefault: true },
  { id: "cat-2", name: "Transport", color: "#3b82f6", icon: "🚗", isDefault: true },
  { id: "cat-3", name: "Shopping", color: "#a855f7", icon: "🛍️", isDefault: true },
  { id: "cat-4", name: "Entertainment", color: "#ec4899", icon: "🎬", isDefault: true },
  { id: "cat-5", name: "Health", color: "#10b981", icon: "💊", isDefault: true },
];

function generateMockDailySpending(month: string): DailySpending[] {
  const [year, m] = month.split("-").map(Number);
  const daysInMonth = new Date(year, m, 0).getDate();
  return Array.from({ length: daysInMonth }, (_, i) => {
    const day = i + 1;
    const date = `${year}-${String(m).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
    const totalAmount = Math.round(Math.random() * 200 + 20);
    return {
      id: `ds-${date}`,
      date,
      totalAmount,
      transactionCount: Math.floor(Math.random() * 5) + 1,
      updatedAt: new Date().toISOString(),
    };
  });
}

function generateMockCategorySpending(month: string): CategorySpending[] {
  const amounts = [420, 180, 310, 95, 145];
  const total = amounts.reduce((a, b) => a + b, 0);
  return MOCK_CATEGORIES.map((cat, i) => ({
