// MonthNavigator
interface MonthNavigatorProps {
  selectedMonth: string;
  onMonthChange: (month: string) => void;
}

const MonthNavigator: React.FC<MonthNavigatorProps> = ({ selectedMonth, onMonthChange }) => {
  const handlePrev = () => {
    const [year, m] = selectedMonth.split("-").map(Number);
    const d = new Date(year, m - 2, 1);
    onMonthChange(`${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`);
  };
  const handleNext = () => {
    const [year, m] = selectedMonth.split("-").map(Number);
    const d = new Date(year, m, 1);
    const next = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
    if (next <= getCurrentMonth()) onMonthChange(next);
  };
  const isCurrentMonth = selectedMonth === getCurrentMonth();

  return (
    <div className="flex items-center gap-2">
      <button
        onClick={handlePrev}
        className="p-1.5 rounded-lg hover:bg-gray-100 transition-colors text-gray-600"
        aria-label="Previous month"
      >
        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
        </svg>
      </button>
      <span className="text-sm font-semibold text-gray-900 min-w-[120px] text-center">
        {formatMonth(selectedMonth)}
      </span>
      <button
        onClick={handleNext}
        disabled={isCurrentMonth}
        className="p-1.5 rounded-lg hover:bg-gray-100 transition-colors text-gray-600 disabled:opacity-30 disabled:cursor-not-allowed"
        aria-label="Next month"
      >
        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
        </svg>
      </button>
    </div>
  );
};

// StatCell
interface StatCellProps {
  label: string;
  value: string;
  trendDirection?: "up" | "down" | "same";
  trendPercentage?: number;
}

const StatCell: React.FC<StatCellProps> = ({ label, value, trendDirection, trendPercentage }) => {
  const trendColor =
    trendDirection === "up"
      ? "text-red-500"
      : trendDirection === "down"
      ? "text-emerald-500"
      : "text-gray-400";

  const trendIcon =
    trendDirection === "up" ? "↑" : trendDirection === "down" ? "↓" : "→";

  return (
    <div className="flex flex-col gap-1">
      <span className="text-xs text-gray-500 font-medium uppercase tracking-wide">{label}</span>
      <span className="text-xl font-bold text-gray-900 tabular-nums">{value}</span>
      {trendDirection && trendPercentage !== undefined && (
        <span className={`text-xs font-medium ${trendColor}`}>
          {trendIcon} {Math.abs(trendPercentage)}% vs last month
        </span>
      )}
    </div>
  );
};

// PeriodSummaryCard
interface PeriodSummaryCardProps {
  monthSummary: MonthSummary;
  previousSummary: MonthSummary | null;
  currency: string;
}

const PeriodSummaryCard: React.FC<PeriodSummaryCardProps> = ({
  monthSummary,
  previousSummary,
  currency,
}) => {
  const calcTrend = (
    current: number,
    previous: number | undefined
  ): { direction: "up" | "down" | "same"; pct: number } => {
    if (!previous || previous === 0) return { direction: "same", pct: 0 };
    const diff = ((current - previous) / previous) * 100;
    if (Math.abs(diff) < 0.5) return { direction: "same", pct: 0 };
    return { direction: diff > 0 ? "up" : "down", pct: Math.abs(Math.round(diff)) };
  };

  const spentTrend = calcTrend(monthSummary.totalSpent, previousSummary?.totalSpent);
  const avgTrend = calcTrend(monthSummary.dailyAverage, previousSummary?.dailyAverage);
  const txTrend = calcTrend(monthSummary.transactionCount, previousSummary?.transactionCount);

  return (
    <Card className="shadow-sm">
      <CardHeader className="pb-2">
        <CardTitle className="text-base font-semibold text-gray-800">Period Summary</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="grid grid-cols-3 gap-4 divide-x divide-gray-200">
          <StatCell
            label="Total Spent"
            value={formatCurrency(monthSummary.totalSpent, currency)}
            trendDirection={spentTrend.direction}
            trendPercentage={spentTrend.pct}
          />
          <div className="pl-4">
            <StatCell
              label="Daily Avg"
              value={formatCurrency(monthSummary.dailyAverage, currency)}
              trendDirection={avgTrend.direction}
              trendPercentage={avgTrend.pct}
            />
          </div>
          <div className="pl-4">
            <StatCell
              label="Transactions"
              value={String(monthSummary.transactionCount)}
              trendDirection={txTrend.direction}
              trendPercentage={txTrend.pct}
            />
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

