// DailySpendingChart
interface DailySpendingChartProps {
  data: DailySpending[];
  mode: "bar" | "line";
  averageDaily: number;
  currency: string;
  onDataPointFocus: (point: DailySpending | null) => void;
}

const DailySpendingChart: React.FC<DailySpendingChartProps> = ({
  data,
  mode,
  averageDaily,
  currency,
  onDataPointFocus,
}) => {
  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);
  const chartHeight = 120;

  if (mode === "bar") {
    return (
      <div
        className="flex items-end gap-0.5 w-full"
        style={{ height: chartHeight }}
        role="img"
        aria-label="Daily spending bar chart"
      >
        {data.map((d) => {
          const heightPct = (d.totalAmount / maxAmount) * 100;
          const isAboveAvg = d.totalAmount > averageDaily * 1.3;
          return (
            <div
              key={d.date}
              className="flex-1 flex flex-col justify-end cursor-pointer group relative"
              style={{ height: "100%" }}
              onMouseEnter={() => onDataPointFocus(d)}
              onMouseLeave={() => onDataPointFocus(null)}
            >
              <div
                className="rounded-t transition-opacity group-hover:opacity-80"
                style={{
                  height: `${heightPct}%`,
                  backgroundColor: isAboveAvg ? "#ef4444" : "#2563eb",
                  minHeight: 2,
                }}
              />
            </div>
          );
        })}
      </div>
    );
  }

  // Line chart using SVG
  const width = 600;
  const height = chartHeight;
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * width,
    y: height - (d.totalAmount / maxAmount) * height,
    ...d,
  }));

  const pathD = points
    .map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`)
    .join(" ");

  const fillD = `${pathD} L ${width} ${height} L 0 ${height} Z`;
  const avgY = height - (averageDaily / maxAmount) * height;

  return (
    <svg
      viewBox={`0 0 ${width} ${height}`}
      className="w-full"
      style={{ height: chartHeight }}
      role="img"
      aria-label="Daily spending line chart"
    >
      <defs>
        <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#bfdbfe" stopOpacity="0.8" />
          <stop offset="100%" stopColor="#bfdbfe" stopOpacity="0" />
        </linearGradient>
      </defs>
      <path d={fillD} fill="url(#lineGrad)" />
      <path d={pathD} fill="none" stroke="#2563eb" strokeWidth="2" strokeLinejoin="round" />
      <line
        x1={0}
        y1={avgY}
        x2={width}
        y2={avgY}
        stroke="#f59e0b"
        strokeWidth="1.5"
        strokeDasharray="4 4"
      />
      {points.map((p) => (
        <circle
          key={p.date}
          cx={p.x}
          cy={p.y}
          r={3}
          fill="#2563eb"
          className="cursor-pointer hover:r-5"
          onMouseEnter={() => onDataPointFocus(p)}
          onMouseLeave={() => onDataPointFocus(null)}
        />
      ))}
    </svg>
  );
};

