// ─── DailySpendingChart ───────────────────────────────────────────────────────

interface DailySpendingChartProps {
  data: DailySpending[];
  mode: "bar" | "line";
  averageDaily: number;
  currency: string;
  onDataPointFocus: (point: DailySpending | null) => void;
}

const DailySpendingChart: React.FC<DailySpendingChartProps> = ({
  data,
  mode,
  averageDaily,
  currency,
  onDataPointFocus,
}) => {
  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);
  const chartHeight = 120;
  const chartWidth = 600;
  const barWidth = chartWidth / data.length - 2;

  if (mode === "bar") {
    return (
      <div className="overflow-x-auto">
        <svg
          width="100%"
          viewBox={`0 0 ${chartWidth} ${chartHeight + 20}`}
          aria-label="Daily spending bar chart"
          role="img"
          className="w-full"
        >
          {/* Average line */}
          <line
            x1={0}
            y1={chartHeight - (averageDaily / maxAmount) * chartHeight}
            x2={chartWidth}
            y2={chartHeight - (averageDaily / maxAmount) * chartHeight}
            stroke="#f59e0b"
            strokeWidth={1.5}
            strokeDasharray="4 3"
          />
          {data.map((d, i) => {
            const barH = (d.totalAmount / maxAmount) * chartHeight;
            const x = i * (chartWidth / data.length) + 1;
            const isHigh = d.totalAmount > averageDaily * 1.5;
            return (
              <rect
                key={d.date}
                x={x}
                y={chartHeight - barH}
                width={barWidth}
                height={barH}
                fill={isHigh ? "#ef4444" : "#2563eb"}
                rx={2}
                className="cursor-pointer opacity-80 hover:opacity-100 transition-opacity"
                onMouseEnter={() => onDataPointFocus(d)}
                onMouseLeave={() => onDataPointFocus(null)}
              />
            );
          })}
          {/* X axis labels (every 5th) */}
          {data.map((d, i) =>
            i % 5 === 0 ? (
              <text
                key={d.date}
                x={i * (chartWidth / data.length) + barWidth / 2}
                y={chartHeight + 14}
                fontSize={9}
                fill="#9ca3af"
                textAnchor="middle"
              >
                {d.date.slice(8)}
              </text>
            ) : null
          )}
        </svg>
      </div>
    );
  }

  // Line chart
  const points = data.map((d, i) => {
    const x = (i / (data.length - 1)) * chartWidth;
    const y = chartHeight - (d.totalAmount / maxAmount) * chartHeight;
    return `${x},${y}`;
  });
  const polyline = points.join(" ");
  const areaPoints = [
    `0,${chartHeight}`,
    ...points,
    `${chartWidth},${chartHeight}`,
  ].join(" ");

  return (
    <div className="overflow-x-auto">
      <svg
        width="100%"
        viewBox={`0 0 ${chartWidth} ${chartHeight + 20}`}
        aria-label="Daily spending line chart"
        role="img"
        className="w-full"
      >
        <defs>
          <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#bfdbfe" stopOpacity={0.8} />
            <stop offset="100%" stopColor="#bfdbfe" stopOpacity={0} />
          </linearGradient>
        </defs>
        <polygon points={areaPoints} fill="url(#lineGrad)" />
        <polyline points={polyline} fill="none" stroke="#2563eb" strokeWidth={2} />
        {/* Average line */}
        <line
          x1={0}
          y1={chartHeight - (averageDaily / maxAmount) * chartHeight}
          x2={chartWidth}
          y2={chartHeight - (averageDaily / maxAmount) * chartHeight}
          stroke="#f59e0b"
          strokeWidth={1.5}
          strokeDasharray="4 3"
        />
        {data.map((d, i) => {
          const x = (i / (data.length - 1)) * chartWidth;
          const y = chartHeight - (d.totalAmount / maxAmount) * chartHeight;
          return (
            <circle
              key={d.date}
              cx={x}
              cy={y}
              r={3}
              fill="#2563eb"
              className="cursor-pointer"
              onMouseEnter={() => onDataPointFocus(d)}
              onMouseLeave={() => onDataPointFocus(null)}
            />
          );
        })}
        {data.map((d, i) =>
          i % 5 === 0 ? (
            <text
              key={d.date}
              x={(i / (data.length - 1)) * chartWidth}
              y={chartHeight + 14}
              fontSize={9}
              fill="#9ca3af"
              textAnchor="middle"
            >
              {d.date.slice(8)}
            </text>
          ) : null
        )}
      </svg>
    </div>
  );
};

