          inputMode="decimal"
          value={localValue}
          onChange={(e) => setLocalValue(e.target.value)}
          onBlur={handleBlur}
          className="pl-8 rounded-md border border-gray-200 text-gray-900 focus:ring-2 focus:ring-blue-600 font-mono tabular-nums"
