// ─── Main Settings Dialog ─────────────────────────────────────────────────────

const SettingsDialog: React.FC<SettingsDialogProps> = ({
  isOpen,
  onClose,
  settings,
  categories,
  onSettingsChange,
  onCategoryDelete,
  onCategoryAdd,
}) => {
  const [localCurrency, setLocalCurrency] = useState<Currency>(settings.currency);
  const [localBudget, setLocalBudget] = useState<number>(settings.defaultMonthlyBudget);

  // Sync local state when settings prop changes
  useEffect(() => {
    setLocalCurrency(settings.currency);
    setLocalBudget(settings.defaultMonthlyBudget);
  }, [settings.currency, settings.defaultMonthlyBudget]);

  const handleCurrencyChange = useCallback(
    (currency: Currency) => {
      setLocalCurrency(currency);
      onSettingsChange({ currency });
      toast({
        title: "Currency updated",
        description: `Default currency changed to ${currency}.`,
      });
    },
    [onSettingsChange]
  );

  const handleBudgetChange = useCallback(
    (value: number) => {
      setLocalBudget(value);
      onSettingsChange({ defaultMonthlyBudget: value });
    },
    [onSettingsChange]
  );

  const handleCategoryDelete = useCallback(
    (categoryId: string) => {
      onCategoryDelete(categoryId);
      toast({
        title: "Category deleted",
        description: "The category has been removed.",
        variant: "destructive",
      });
    },
    [onCategoryDelete]
  );

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent
        className="max-w-[420px] w-full rounded-xl bg-white shadow-xl p-6"
        onEscapeKeyDown={onClose}
        onInteractOutside={onClose}
      >
        {/* Hidden DialogTitle for accessibility */}
        <DialogHeader className="sr-only">
          <DialogTitle>Settings</DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Custom visible header */}
          <SettingsDialogHeader title="Settings" onClose={onClose} />

          {/* Currency Selector */}
          <CurrencySelector
            options={CURRENCY_OPTIONS}
            selectedCurrency={localCurrency}
            onSelect={handleCurrencyChange}
            label="Default Currency"
          />

          <Separator className="bg-gray-100" />

          {/* Budget Limit Input */}
          <BudgetLimitInput
            value={localBudget}
            onChange={handleBudgetChange}
            currency={localCurrency}
            label="Monthly Budget Limit"
          />

          <Separator className="bg-gray-100" />

          {/* Category Manager */}
          <CategoryManager
            categories={categories}
            onDelete={handleCategoryDelete}
            onAdd={onCategoryAdd}
            addLabel="Add category"
          />
        </div>
      </DialogContent>
    </Dialog>
  );
};

