        {categories.length === 0 ? (
          <p className="text-sm text-gray-400 py-4 text-center">No categories yet.</p>
        ) : (
          categories.map((cat) => (
            <CategoryManagerRow key={cat.id} category={cat} onDelete={onDelete} />
          ))
        )}
      </div>
    </div>
    <button
      onClick={onAdd}
      className="flex items-center gap-1.5 text-sm text-blue-600 hover:text-blue-700 font-medium mt-1 focus:outline-none focus:ring-2 focus:ring-blue-600 rounded-md px-1 py-0.5 transition-colors"
    >
      <Plus size={15} />
      {addLabel}
    </button>
  </div>
);

// ─── Toast ────────────────────────────────────────────────────────────────────

interface ToastState {
  message: string;
  visible: boolean;
}

// ─── Main Component ───────────────────────────────────────────────────────────

const SettingsDialog: React.FC<SettingsDialogProps> = ({
  isOpen,
  onClose,
  settings,
  categories,
  onSettingsChange,
  onCategoryDelete,
  onCategoryAdd,
}) => {
  const [toast, setToast] = useState<ToastState>({ message: "", visible: false });

  const showToast = useCallback((message: string) => {
    setToast({ message, visible: true });
    setTimeout(() => setToast({ message: "", visible: false }), 3000);
  }, []);

  // Close on Escape key
  useEffect(() => {
    if (!isOpen) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, onClose]);

  // Prevent body scroll when open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => {
      document.body.style.overflow = "";
    };
  }, [isOpen]);

  const handleCurrencyChange = (currency: Currency) => {
    onSettingsChange({ currency });
    showToast(`Currency changed to ${currency}`);
  };

  const handleBudgetChange = (defaultMonthlyBudget: number) => {
    onSettingsChange({ defaultMonthlyBudget });
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Scrim */}
      <div
        className="fixed inset-0 z-40"
        style={{ backgroundColor: "rgba(0,0,0,0.5)" }}
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Dialog */}
      <div
        role="dialog"
        aria-modal="true"
        aria-labelledby="settings-dialog-title"
        className="fixed inset-0 z-50 flex items-center justify-center p-4"
      >
        <div
          className="relative w-full bg-white rounded-2xl shadow-2xl flex flex-col"
          style={{ maxWidth: "420px" }}
          onClick={(e) => e.stopPropagation()}
        >
          <div className="p-6 space-y-6">
            <DialogHeader
              title="Settings"
              onClose={onClose}
            />

            <CurrencySelector
              options={CURRENCY_OPTIONS}
              selectedCurrency={settings.currency}
              onSelect={handleCurrencyChange}
              label="Default Currency"
            />

            <Separator />

            <BudgetLimitInput
              value={settings.defaultMonthlyBudget}
              onChange={handleBudgetChange}
              currency={settings.currency}
              label="Monthly Budget Limit"
            />

            <Separator />

            <CategoryManager
              categories={categories}
              onDelete={onCategoryDelete}
              onAdd={onCategoryAdd}
              addLabel="Add category"
            />
          </div>

          {/* Footer */}
          <div className="px-6 pb-6 pt-2 flex justify-end">
            <Button
              onClick={onClose}
              className="bg-blue-600 hover:bg-blue-700 text-white rounded-lg px-6"
            >
              Done
            </Button>
          </div>
        </div>
      </div>

      {/* Toast */}
      {toast.visible && (
        <div
          role="status"
          aria-live="polite"
          className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[60] bg-gray-900 text-white text-sm px-4 py-2.5 rounded-lg shadow-lg transition-all"
        >
          {toast.message}
        </div>
      )}
    </>
  );
};

// ─── Demo / Export ────────────────────────────────────────────────────────────

const DEMO_SETTINGS: UserSettings = {
  id: "settings-1",
  currency: "USD",
  defaultMonthlyBudget: 3000,
  updatedAt: new Date().toISOString(),
};

const DEMO_CATEGORIES: Category[] = [
  { id: "cat-1", name: "Food & Dining", color: "#f97316", icon: "🍔", isDefault: true, sortOrder: 1 },
