// Main Settings Form Component
const SettingsForm: React.FC<SettingsFormProps> = ({ isOpen, onClose }) => {
  const [settings, setSettings] = useState<UserSettings>(MOCK_SETTINGS);
  const [categories, setCategories] = useState<Category[]>(MOCK_CATEGORIES);
  const [isSaving, setIsSaving] = useState(false);

  // Simulate fetching settings from /api/settings
  useEffect(() => {
    if (isOpen) {
      // In a real app: fetch('/api/settings').then(...)
      setSettings(MOCK_SETTINGS);
      setCategories(MOCK_CATEGORIES);
    }
  }, [isOpen]);

  const handleCurrencyChange = useCallback(
    async (currency: Currency) => {
      const prev = settings.currency;
      setSettings((s) => ({ ...s, currency }));
      try {
        // PUT /api/settings
        await Promise.resolve(); // simulate API call
        toast({
          title: "Currency updated",
          description: `Default currency changed to ${currency}.`,
        });
      } catch {
        setSettings((s) => ({ ...s, currency: prev }));
        toast({
          title: "Error",
          description: "Failed to update currency.",
          variant: "destructive",
        });
      }
    },
    [settings.currency]
  );

  const handleBudgetChange = useCallback(async (value: number) => {
    setSettings((s) => ({ ...s, defaultMonthlyBudget: value }));
    try {
      // PUT /api/settings and PUT /api/budgets/{month}
      await Promise.resolve();
    } catch {
      toast({
        title: "Error",
        description: "Failed to update budget limit.",
        variant: "destructive",
      });
    }
  }, []);

  const handleSaveSettings = useCallback(async () => {
    setIsSaving(true);
    try {
      await Promise.resolve(); // simulate PUT /api/settings
      toast({
        title: "Settings saved",
        description: "Your preferences have been updated.",
      });
      onClose();
    } catch {
      toast({
        title: "Error",
        description: "Failed to save settings.",
        variant: "destructive",
      });
    } finally {
      setIsSaving(false);
    }
  }, [onClose]);

  const handleCategoryDelete = useCallback(async (categoryId: string) => {
    const target = categories.find((c) => c.id === categoryId);
    if (!target || target.isDefault) return;

    setCategories((prev) => prev.filter((c) => c.id !== categoryId));
    try {
      // DELETE /api/categories/{id}
      await Promise.resolve();
      toast({
        title: "Category deleted",
        description: `"${target.name}" has been removed.`,
      });
    } catch {
      setCategories((prev) => [...prev, target].sort((a, b) => a.sortOrder - b.sortOrder));
      toast({
        title: "Error",
        description: "Failed to delete category.",
        variant: "destructive",
      });
    }
  }, [categories]);

  const handleCategoryAdd = useCallback(() => {
    // Navigate to screen-002 (category add screen)
    toast({
      title: "Add Category",
      description: "Navigating to add category screen.",
    });
  }, []);

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent
        className="max-w-[420px] w-full bg-white rounded-2xl shadow-xl p-0 gap-0"
        onEscapeKeyDown={onClose}
        onInteractOutside={onClose}
      >
        <div className="p-6 space-y-6">
          {/* Header */}
          <SettingsDialogHeader title="Settings" onClose={onClose} />

          {/* Currency Selector */}
          <CurrencySelector
            options={CURRENCY_OPTIONS}
            selectedCurrency={settings.currency}
            onSelect={handleCurrencyChange}
            label="Default Currency"
          />

          {/* Budget Limit Input */}
          <BudgetLimitInput
            value={settings.defaultMonthlyBudget}
            onChange={handleBudgetChange}
            currency={settings.currency}
            label="Monthly Budget Limit"
          />

          {/* Category Manager */}
          <CategoryManager
            categories={categories}
            onDelete={handleCategoryDelete}
            onAdd={handleCategoryAdd}
            addLabel="Add category"
          />

          {/* Save Button */}
          <div className="flex justify-end gap-3 pt-2 border-t border-gray-100">
            <Button
              variant="outline"
              onClick={onClose}
              className="border-gray-200 text-gray-700 hover:bg-gray-50"
            >
              Cancel
            </Button>
            <Button
              onClick={handleSaveSettings}
              disabled={isSaving}
              className="bg-blue-600 hover:bg-blue-700 text-white focus:ring-2 focus:ring-blue-600"
            >
              {isSaving ? "Saving…" : "Save Settings"}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
};

// Demo wrapper to show the dialog
const SettingsFormDemo: React.FC = () => {
