        <Button
          onClick={() => setIsOpen(true)}
          className="bg-blue-600 hover:bg-blue-700 text-white"
        >
          Open Settings
        </Button>
      )}
      <SettingsForm isOpen={isOpen} onClose={() => setIsOpen(false)} />
    </div>
  );
};

export default SettingsFormDemo;
