// ─── Spending Summary Card ────────────────────────────────────────────────────

interface SpendingSummaryCardProps {
  summary: SpendingSummary;
  isLoading: boolean;
}

const SpendingSummaryCard: React.FC<SpendingSummaryCardProps> = ({
  summary,
  isLoading,
}) => {
  const changePercent =
    summary.totalLastMonth > 0
      ? (((summary.totalThisMonth - summary.totalLastMonth) / summary.totalLastMonth) * 100).toFixed(1)
      : "0.0";
  const isIncrease = summary.totalThisMonth > summary.totalLastMonth;

  return (
    <Card className="bg-white rounded-xl shadow-sm border border-gray-100">
      <CardHeader className="px-6 pt-5 pb-0">
        <h2 className="text-sm font-semibold text-gray-900 tracking-wide">
          Spending Summary
        </h2>
      </CardHeader>
      <CardContent className="px-6 pt-4 pb-5">
        {isLoading ? (
          <div className="space-y-3">
            <Skeleton className="h-8 w-36" />
            <Skeleton className="h-4 w-48" />
            <Skeleton className="h-4 w-40" />
          </div>
        ) : (
          <div className="space-y-4">
            <div>
              <p className="text-xs text-gray-500 mb-1">This Month</p>
              <p className="text-2xl font-bold text-gray-900">
                {formatCurrency(summary.totalThisMonth)}
              </p>
              <div className="flex items-center gap-1 mt-1">
                <TrendingDown
                  className={isIncrease ? "text-red-500 rotate-180" : "text-green-500"}
                  style={{ width: 14, height: 14 }}
                />
                <span
                  className={`text-xs font-medium ${
                    isIncrease ? "text-red-500" : "text-green-500"
                  }`}
                >
                  {isIncrease ? "+" : "-"}
                  {Math.abs(Number(changePercent))}% vs last month
                </span>
              </div>
            </div>

            <div className="border-t border-gray-100 pt-3 space-y-2">
              <div className="flex justify-between items-center">
                <span className="text-xs text-gray-500">Last Month</span>
                <span className="text-sm font-medium text-gray-700">
                  {formatCurrency(summary.totalLastMonth)}
                </span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-xs text-gray-500">Top Category</span>
                <div className="text-right">
                  <span className="text-sm font-medium text-gray-700">
                    {summary.topCategory}
                  </span>
                  <p className="text-xs text-gray-400">
                    {formatCurrency(summary.topCategoryAmount)}
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
};

