```tsx
import React, { useState, useEffect } from "react";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { RefreshCw, ArrowRight } from "lucide-react";

// ─── Types ────────────────────────────────────────────────────────────────────

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";
type TemplateStatus = "ACTIVE" | "PAUSED" | "CANCELLED";

interface RecurringTemplateItem {
  templateId: string;
  merchantName: string;
  amount: number;
  nextOccurrenceDate: string;
  frequency: Frequency;
  categoryId: string;
  status: TemplateStatus;
  categoryColor: string;
}

interface Expense {
  id: string;
  amount: number;
  categoryId: string;
  merchantName: string;
  date: string;
  paymentMethod: string;
  note: string;
  recurringTemplateId?: string;
  isRecurringInstance?: boolean;
}

// ─── Sub-components ───────────────────────────────────────────────────────────

const CategoryColorDot: React.FC<{ color: string }> = ({ color }) => (
  <span
    className="inline-block rounded-full flex-shrink-0"
    style={{
      width: "10px",
      height: "10px",
      backgroundColor: color || "#94a3b8",
    }}
  />
);

const frequencyLabel: Record<Frequency, string> = {
  WEEKLY: "Weekly",
  MONTHLY: "Monthly",
  YEARLY: "Yearly",
};

const RecurringFrequencyBadge: React.FC<{ frequency: Frequency }> = ({
  frequency,
}) => (
  <Badge
    className="text-xs font-medium px-2 py-0.5 rounded-full border-0"
    style={{
      backgroundColor: "#dbeafe",
      color: "#2563eb",
      fontSize: "11px",
    }}
  >
    {frequencyLabel[frequency] ?? frequency}
  </Badge>
);

const RecurringInlineIcon: React.FC = () => (
  <RefreshCw size={14} className="text-gray-400" />
);

const ExpenseRowRecurringBadge: React.FC<{ frequency: Frequency }> = ({
  frequency,
}) => (
  <span className="inline-flex items-center gap-1 text-xs text-gray-500">
    <RecurringInlineIcon />
    {frequencyLabel[frequency]}
  </span>
);

const UpcomingRecurringEmptyState: React.FC = () => (
  <div className="flex flex-col items-center justify-center py-6 gap-2">
    <RefreshCw size={32} className="text-gray-300" />
    <span className="text-sm text-gray-400">No recurring expenses</span>
  </div>
);

const UpcomingRecurringRow: React.FC<{
  item: RecurringTemplateItem;
  onClick: (templateId: string) => void;
}> = ({ item, onClick }) => {
  const formattedDate = (() => {
    try {
      return new Date(item.nextOccurrenceDate).toLocaleDateString("en-US", {
        month: "short",
        day: "numeric",
        year: "numeric",
      });
    } catch {
      return item.nextOccurrenceDate;
    }
  })();

  const formattedAmount = new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(item.amount);

  return (
    <button
      onClick={() => onClick(item.templateId)}
      className="w-full flex items-center gap-3 py-2.5 px-1 rounded-lg hover:bg-gray-50 transition-colors text-left group"
    >
      {/* Left: dot + merchant info */}
      <CategoryColorDot color={item.categoryColor} />
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 flex-wrap">
          <span className="text-sm font-medium text-gray-900 truncate">
            {item.merchantName}
          </span>
          <RecurringFrequencyBadge frequency={item.frequency} />
        </div>
        <span className="text-xs text-gray-500">{formattedDate}</span>
      </div>
      {/* Right: amount */}
      <span className="text-sm font-semibold text-gray-900 flex-shrink-0">
        {formattedAmount}
      </span>
    </button>
  );
};

const UpcomingRecurringRowListSkeleton: React.FC = () => (
  <div className="flex flex-col gap-2">
    {[1, 2, 3].map((i) => (
      <div key={i} className="flex items-center gap-3 py-2.5 px-1">
        <Skeleton className="w-2.5 h-2.5 rounded-full flex-shrink-0" />
        <div className="flex-1 space-y-1.5">
          <Skeleton className="h-3.5 w-32" />
          <Skeleton className="h-3 w-20" />
        </div>
        <Skeleton className="h-4 w-16" />
      </div>
    ))}
  </div>
);

// ─── Upcoming Recurring Card ──────────────────────────────────────────────────

interface UpcomingRecurringCardProps {
  items: RecurringTemplateItem[];
  isLoading: boolean;
  onViewAllClick: () => void;
  onRowClick?: (templateId: string) => void;
}

const UpcomingRecurringCard: React.FC<UpcomingRecurringCardProps> = ({
  items,
  isLoading,
  onViewAllClick,
  onRowClick,
}) => {
  const handleRowClick = (templateId: string) => {
    onRowClick?.(templateId);
  };

  return (
    <Card className="bg-white rounded-xl shadow-sm border border-gray-100">
      <CardHeader className="pb-2 pt-5 px-6">
        <div className="flex items-center justify-between">
          <h2 className="text-sm font-semibold text-gray-900 tracking-wide">
            Upcoming Recurring
          </h2>
          <button
            onClick={onViewAllClick}
            className="text-xs text-blue-600 hover:text-blue-700 font-medium flex items-center gap-1 transition-colors"
          >
            View All
            <ArrowRight size={12} />
          </button>
        </div>
      </CardHeader>
      <CardContent className="px-6 pb-5 pt-1">
        {isLoading ? (
          <UpcomingRecurringRowListSkeleton />
        ) : items.length === 0 ? (
          <UpcomingRecurringEmptyState />
        ) : (
          <div className="flex flex-col gap-0.5">
            {items.map((item) => (
              <UpcomingRecurringRow
                key={item.templateId}
                item={item}
                onClick={handleRowClick}
              />
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
};

