// ─── Types ────────────────────────────────────────────────────────────────────

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";
type EndDateMode = "NEVER" | "ON_DATE";
type PaymentMethod = "CASH" | "CREDIT_CARD" | "DEBIT_CARD" | "BANK_TRANSFER" | "OTHER";

interface ExpenseFormData {
  amount: string;
  categoryId: string;
  merchantName: string;
  date: string;
  paymentMethod: PaymentMethod | "";
  note: string;
}

interface RecurrenceData {
  isRecurring: boolean;
  frequency: Frequency;
