      min={minDate}
      placeholder={placeholder}
      className="mt-2 border-gray-200 rounded-md text-sm focus-visible:ring-blue-600 focus-visible:border-blue-600 px-3 py-2"
    />
  );
};

// ─── EndDateRow ───────────────────────────────────────────────────────────────

interface EndDateRowProps {
  endDateMode: EndDateMode;
