            <Label className="text-sm font-medium text-gray-700">Payment Method</Label>
            <div className="flex flex-wrap gap-2">
              {PAYMENT_METHODS.map((pm) => (
                <button
                  key={pm.value}
                  type="button"
                  onClick={() => handleExpenseChange("paymentMethod", pm.value)}
                  className={cn(
                    "px-3 py-1.5 rounded-full border text-sm font-medium transition-all duration-150 min-h-[36px] focus:outline-none focus:ring-2 focus:ring-blue-600 focus:ring-offset-2",
                    expenseForm.paymentMethod === pm.value
