              ))}
            </div>
          </div>

          {/* Note */}
          <div className="flex flex-col gap-1.5">
            <Label htmlFor="note" className="text-sm font-medium text-gray-700">
              Note
            </Label>
            <Textarea
              id="note"
              placeholder="Add a note (optional)..."
              value={expenseForm.note}
              onChange={(e) => handleExpenseChange("note", e.target.value)}
              rows={3}
              className="border-gray-200 focus:border-blue-600 focus:ring-blue-600 resize-none"
            />
          </div>

          {/* Divider */}
          <div className="border-t border-gray-100" />

          {/* Recurrence Config Section */}
          <RecurrenceConfigSection
            isRecurring={recurrence.isRecurring}
            frequency={recurrence.frequency}
            startDate={recurrence.startDate}
            endDateMode={recurrence.endDateMode}
            endDate={recurrence.endDate}
            onIsRecurringChange={(val) =>
              setRecurrence((prev) => ({ ...prev, isRecurring: val }))
            }
            onFrequencyChange={(val) =>
              setRecurrence((prev) => ({ ...prev, frequency: val }))
            }
            onStartDateChange={(val) =>
              setRecurrence((prev) => ({ ...prev, startDate: val }))
            }
            onEndDateModeChange={(val) =>
              setRecurrence((prev) => ({ ...prev, endDateMode: val }))
            }
            onEndDateChange={(val) =>
              setRecurrence((prev) => ({ ...prev, endDate: val }))
            }
            isEditingSeries={false}
          />

          {/* Recurring badge hint */}
          {recurrence.isRecurring && (
            <div className="flex items-center gap-2 px-3 py-2 bg-blue-50 rounded-lg border border-blue-100">
              <svg className="w-4 h-4 text-blue-600 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              <p className="text-xs text-blue-700">
                This expense will repeat{" "}
                <span className="font-semibold lowercase">{recurrence.frequency}</span>
                {recurrence.endDateMode === "ON_DATE" && recurrence.endDate
                  ? ` until ${recurrence.endDate}`
                  : " with no end date"}
                .
              </p>
            </div>
          )}

          {/* Actions */}
          <div className="flex gap-3 pt-2">
            <Button
              type="button"
              variant="outline"
              onClick={handleCancel}
              className="flex-1 border-gray-200 text-gray-700 hover:bg-gray-50"
            >
              Cancel
            </Button>
            <Button
              type="submit"
              disabled={isSubmitting || !expenseForm.amount || !expenseForm.categoryId}
              className="flex-1 bg-blue-600 hover:bg-blue-700 text-white disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isSubmitting ? (
                <span className="flex items-center gap-2">
                  <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
                  </svg>
                  Saving...
                </span>
              ) : recurrence.isRecurring ? (
                "Save & Schedule"
              ) : (
                "Add Expense"
              )}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddExpenseForm;
