```tsx
import React, { useState } from "react";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

// ─── Types ────────────────────────────────────────────────────────────────────

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";
type EndDateMode = "NEVER" | "ON_DATE";
type PaymentMethod = "CASH" | "CREDIT_CARD" | "DEBIT_CARD" | "BANK_TRANSFER" | "OTHER";

interface ExpenseFormData {
  amount: string;
  categoryId: string;
  merchantName: string;
  date: string;
  paymentMethod: PaymentMethod | "";
  note: string;
  recurringTemplateId?: string;
}

interface RecurrenceFormData {
  isRecurring: boolean;
  frequency: Frequency;
  startDate: string;
  endDateMode: EndDateMode;
  endDate: string | undefined;
}

// ─── FrequencyChip ────────────────────────────────────────────────────────────

interface FrequencyChipProps {
  label: string;
  value: Frequency;
  isSelected: boolean;
  onClick: (value: Frequency) => void;
}

const FrequencyChip: React.FC<FrequencyChipProps> = ({
  label,
  value,
  isSelected,
  onClick,
}) => {
  return (
    <button
      type="button"
      onClick={() => onClick(value)}
      className={cn(
        "px-3 py-1.5 rounded-full border text-sm font-medium transition-all duration-150 min-h-[36px] focus:outline-none focus:ring-2 focus:ring-blue-600 focus:ring-offset-2",
        isSelected
          ? "bg-blue-100 border-blue-600 text-blue-600"
          : "bg-white border-gray-200 text-gray-700 hover:border-gray-300 hover:bg-gray-50"
      )}
      aria-pressed={isSelected}
    >
      {label}
    </button>
  );
};

// ─── FrequencyChipSelector ────────────────────────────────────────────────────

interface FrequencyChipSelectorProps {
  value: Frequency;
  onChange: (value: Frequency) => void;
}

const FREQUENCY_OPTIONS: { value: Frequency; label: string }[] = [
  { value: "WEEKLY", label: "Weekly" },
  { value: "MONTHLY", label: "Monthly" },
  { value: "YEARLY", label: "Yearly" },
];

const FrequencyChipSelector: React.FC<FrequencyChipSelectorProps> = ({
  value,
  onChange,
}) => {
  return (
    <div className="flex flex-col gap-1.5">
      <Label className="text-sm font-medium text-gray-500">Frequency</Label>
      <div className="flex gap-2 flex-wrap">
        {FREQUENCY_OPTIONS.map((option) => (
          <FrequencyChip
            key={option.value}
            label={option.label}
            value={option.value}
            isSelected={value === option.value}
            onClick={onChange}
          />
        ))}
      </div>
    </div>
  );
};

// ─── RadioOption ──────────────────────────────────────────────────────────────

interface RadioOptionProps {
  label: string;
  value: string;
  isSelected: boolean;
  onSelect: () => void;
}

const RadioOption: React.FC<RadioOptionProps> = ({
  label,
  value,
  isSelected,
  onSelect,
}) => {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={isSelected}
      onClick={onSelect}
      className="flex items-center gap-2 min-h-[36px] focus:outline-none focus:ring-2 focus:ring-blue-600 focus:ring-offset-2 rounded"
    >
      <div
        className={cn(
          "w-4 h-4 rounded-full border-2 flex items-center justify-center transition-colors duration-150",
          isSelected ? "border-blue-600" : "border-gray-300"
        )}
      >
        {isSelected && (
          <div className="w-2 h-2 rounded-full bg-blue-600" />
        )}
      </div>
      <span className="text-sm text-gray-700">{label}</span>
    </button>
  );
};

// ─── DatePickerInput ──────────────────────────────────────────────────────────

interface DatePickerInputProps {
  value: string | undefined;
  onChange: (value: string) => void;
  isVisible: boolean;
  minDate?: string;
  placeholder?: string;
}

const DatePickerInput: React.FC<DatePickerInputProps> = ({
  value,
  onChange,
  isVisible,
  minDate,
  placeholder = "Select end date",
}) => {
  if (!isVisible) return null;

  return (
    <Input
      type="date"
      value={value ?? ""}
      min={minDate}
      placeholder={placeholder}
      onChange={(e) => onChange(e.target.value)}
      className="mt-2 border-gray-200 rounded-md text-sm p-3 focus:border-blue-600 focus:ring-blue-600"
    />
  );
};

// ─── EndDateRow ───────────────────────────────────────────────────────────────

interface EndDateRowProps {
  endDateMode: EndDateMode;
  endDate: string | undefined;
  startDate: string;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
}

const EndDateRow: React.FC<EndDateRowProps> = ({
  endDateMode,
  endDate,
  startDate,
  onEndDateModeChange,
  onEndDateChange,
}) => {
  const handleModeChange = (mode: EndDateMode) => {
    onEndDateModeChange(mode);
    if (mode === "NEVER") {
      onEndDateChange(undefined);
    }
  };

  return (
    <div className="flex flex-col gap-2">
      <Label className="text-sm font-medium text-gray-500">End date</Label>
      <div className="flex gap-4">
        <RadioOption
          label="Never"
          value="NEVER"
          isSelected={endDateMode === "NEVER"}
          onSelect={() => handleModeChange("NEVER")}
        />
        <RadioOption
          label="On date"
          value="ON_DATE"
          isSelected={endDateMode === "ON_DATE"}
          onSelect={() => handleModeChange("ON_DATE")}
        />
      </div>
      <DatePickerInput
        value={endDate}
        onChange={onEndDateChange}
        isVisible={endDateMode === "ON_DATE"}
        minDate={startDate}
        placeholder="Select end date"
      />
    </div>
  );
};

// ─── RecurrenceToggleRow ──────────────────────────────────────────────────────

interface RecurrenceToggleRowProps {
  checked: boolean;
  onCheckedChange: (value: boolean) => void;
}

const RecurrenceToggleRow: React.FC<RecurrenceToggleRowProps> = ({
  checked,
  onCheckedChange,
}) => {
  return (
    <div className="flex items-center justify-between py-1">
      <Label
        htmlFor="recurring-toggle"
        className="text-sm font-semibold text-gray-900 cursor-pointer"
      >
        Make this recurring
      </Label>
      <Switch
        id="recurring-toggle"
        checked={checked}
        onCheckedChange={onCheckedChange}
        className="data-[state=checked]:bg-blue-600 data-[state=unchecked]:bg-gray-200"
      />
    </div>
  );
};

// ─── RecurrenceConfigPanel ────────────────────────────────────────────────────

interface RecurrenceConfigPanelProps {
  isVisible: boolean;
  frequency: Frequency;
  startDate: string;
  endDateMode: EndDateMode;
  endDate: string | undefined;
  onFrequencyChange: (value: Frequency) => void;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
}

const RecurrenceConfigPanel: React.FC<RecurrenceConfigPanelProps> = ({
  isVisible,
  frequency,
  startDate,
  endDateMode,
  endDate,
  onFrequencyChange,
  onEndDateModeChange,
  onEndDateChange,
}) => {
  return (
    <div
      className={cn(
        "overflow-hidden transition-all duration-150 ease-in-out",
        isVisible ? "max-h-96 opacity-100" : "max-h-0 opacity-0"
      )}
      aria-hidden={!isVisible}
    >
      <div className="flex flex-col gap-4 pt-2 pb-1">
        <FrequencyChipSelector value={frequency} onChange={onFrequencyChange} />

        <div className="flex flex-col gap-1.5">
          <Label className="text-sm font-medium text-gray-500">Start date</Label>
          <Input
            type="date"
            value={startDate}
            readOnly
            className="border-gray-200 rounded-md text-sm focus:border-blue-600 focus:ring-blue-600 bg-gray-50 text-gray-500"
          />
          <p className="text-xs text-gray-400">Uses the expense date as start date</p>
        </div>

        <EndDateRow
          endDateMode={endDateMode}
          endDate={endDate}
          startDate={startDate}
          onEndDateModeChange={onEndDateModeChange}
          onEndDateChange={onEndDateChange}
        />
      </div>
    </div>
  );
};

// ─── RecurrenceConfigSection ──────────────────────────────────────────────────

interface RecurrenceConfigSectionProps {
  isRecurring: boolean;
  frequency: Frequency;
  startDate: string;
  endDateMode: EndDateMode;
  endDate: string | undefined;
  onIsRecurringChange: (value: boolean) => void;
  onFrequencyChange: (value: Frequency) => void;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
  isEditingSeries?: boolean;
}

const RecurrenceConfigSection: React.FC<RecurrenceConfigSectionProps> = ({
  isRecurring,
  frequency,
  startDate,
  endDateMode,
  endDate,
  onIsRecurringChange,
  onFrequencyChange,
  onEndDateModeChange,
  onEndDateChange,
  isEditingSeries = false,
}) => {
  return (
    <div className="flex flex-col gap-4 rounded-xl border border-gray-200 bg-gray-50 p-4">
      <RecurrenceToggleRow
        checked={isRecurring}
        onCheckedChange={onIsRecurringChange}
      />
      {isEditingSeries && (
        <Badge variant="secondary" className="w-fit text-xs bg-blue-100 text-blue-700 border-blue-200">
          Editing recurring series
        </Badge>
      )}
      <RecurrenceConfigPanel
        isVisible={isRecurring}
        frequency={frequency}
        startDate={startDate}
        endDateMode={endDateMode}
        endDate={endDate}
        onFrequencyChange={onFrequencyChange}
        onEndDateModeChange={onEndDateModeChange}
        onEndDateChange={onEndDateChange}
      />
    </div>
  );
};

// ─── Payment Method Chip ──────────────────────────────────────────────────────

const PAYMENT_METHODS: { value: PaymentMethod; label: string }[] = [
  { value: "CASH", label: "Cash" },
  { value: "CREDIT_CARD", label: "Credit Card" },
  { value: "DEBIT_CARD", label: "Debit Card" },
  { value: "BANK_TRANSFER", label: "Bank Transfer" },
  { value: "OTHER", label: "Other" },
];

const CATEGORIES = [
  { id: "cat-1", label: "Food & Dining" },
  { id: "cat-2", label: "Transportation" },
  { id: "cat-3", label: "Shopping" },
  { id: "cat-4", label: "Entertainment" },
  { id: "cat-5", label: "Health" },
  { id: "cat-6", label: "Utilities" },
  { id: "cat-7", label: "Other" },
];

// ─── Main AddExpenseForm ──────────────────────────────────────────────────────

const AddExpenseForm: React.FC = () => {
  const today = new Date().toISOString().split("T")[0];

  // Expense form state
  const [expenseForm, setExpenseForm] = useState<ExpenseFormData>({
    amount: "",
    categoryId: "",
    merchantName: "",
    date: today,
    paymentMethod: "",
    note: "",
  });

  // Recurrence state
  const [recurrence, setRecurrence] = useState<RecurrenceFormData>({
    isRecurring: false,
    frequency: "MONTHLY",
    startDate: today,
    endDateMode: "NEVER",
    endDate: undefined,
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);

  // Keep recurrence startDate in sync with expense date
  const handleDateChange = (date: string) => {
    setExpenseForm((prev) => ({ ...prev, date }));
    setRecurrence((prev) => ({ ...prev, startDate: date }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      // Simulate API calls
      if (recurrence.isRecurring) {
        const templatePayload = {
          amount: parseFloat(expenseForm.amount),
          categoryId: expenseForm.categoryId,
          merchantName: expenseForm.merchantName,
          frequency: recurrence.frequency,
          startDate: recurrence.startDate,
          endDate: recurrence.endDateMode === "ON_DATE" ? recurrence.endDate : undefined,
          paymentMethod: expenseForm.paymentMethod,
          note: expenseForm.note,
          status: "ACTIVE",
        };
        console.log("POST /api/recurring-templates", templatePayload);
      }

      const expensePayload = {
        amount: parseFloat(expenseForm.amount),
        categoryId: expenseForm.categoryId,
        merchantName: expenseForm.merchantName,
        date: expenseForm.date,
        paymentMethod: expenseForm.paymentMethod,
        note: expenseForm.note,
      };
      console.log("POST /api/expenses", expensePayload);

      await new Promise((r) => setTimeout(r, 600));
      setSubmitSuccess(true);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitSuccess) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <Card className="w-full max-w-md text-center p-8">
          <div className="text-4xl mb-4">✅</div>
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Expense Added!</h2>
          <p className="text-gray-500 text-sm mb-6">
            {recurrence.isRecurring
              ? "Your recurring expense has been set up successfully."
              : "Your expense has been recorded."}
          </p>
          <Button
            onClick={() => {
              setSubmitSuccess(false);
              setExpenseForm({
                amount: "",
                categoryId: "",
                merchantName: "",
                date: today,
                paymentMethod: "",
                note: "",
              });
              setRecurrence({
                isRecurring: false,
                frequency: "MONTHLY",
                startDate: today,
                endDateMode: "NEVER",
                endDate: undefined,
              });
            }}
            className="bg-blue-600 hover:bg-blue-700 text-white"
          >
            Add Another
          </Button>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-6 px-4">
      <div className="max-w-md mx-auto">
        {/* Header */}
        <div className="flex items-center gap-3 mb-6">
          <button
            type="button"
            className="text-gray-500 hover:text-gray-700 focus:outline-none focus:ring-2 focus:ring-blue-600 rounded p-1"
            aria-label="Go back"
          >
            <svg
              className="w-5 h-5"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M15 19l-7-7 7-7"
              />
            </svg>
          </button>
          <h1 className="text-xl font-bold text-gray-900">Add Expense</h1>
        </div>

        <form onSubmit={handleSubmit} noValidate>
          <Card className="shadow-sm border-gray-200">
            <CardContent className="p-5 flex flex-col gap-5">

              {/* Amount */}
              <div className="flex flex-col gap-1.5">
                <Label htmlFor="amount" className="text-sm font-medium text-gray-700">
                  Amount <span className="text-red-500">*</span>
                </Label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm font-medium">
                    $
                  </span>
                  <Input
                    id="amount"
                    type="number"
                    min="0"
                    step="0.01"
                    placeholder="0.00"
                    value={expenseForm.amount}
                    onChange={(e) =>
                      setExpenseForm((prev) => ({ ...prev, amount: e.target.value }))
                    }
                    className="pl-7 border-gray-200 focus:border-blue-600 focus:ring-blue-600 text-lg font-semibold"
                    required
                  />
                </div>
              </div>

              {/* Merchant Name */}
              <div className="flex flex-col gap-1.5">
                <Label htmlFor="merchantName" className="text-sm font-medium text-gray-700">
                  Merchant
                </Label>
                <Input
                  id="merchantName"
                  type="text"
                  placeholder="e.g. Starbucks"
                  value={expenseForm.merchantName}
                  onChange={(e) =>
                    setExpenseForm((prev) => ({ ...prev, merchantName: e.target.value }))
                  }
                  className="border-gray-200 focus:border-blue-600 focus:ring-blue-600"
                />
              </div>

              {/* Category */}
              <div className="flex flex-col gap-1.5">
                <Label htmlFor="category" className="text-sm font-medium text-gray-700">
                  Category <span className="text-red-500">*</span>
                </Label>
                <Select
                  value={expenseForm.categoryId}
                  onValueChange={(val) =>
                    setExpenseForm((prev) => ({ ...prev, categoryId: val }))
                  }
                >
                  <SelectTrigger
                    id="category"
                    className="border-gray-200 focus:border-blue-600 focus:ring-blue-600"
                  >
                    <SelectValue placeholder="Select a category" />
                  </SelectTrigger>
                  <SelectContent>
                    {CATEGORIES.map((cat) => (
                      <SelectItem key={cat.id} value={cat.id}>
                        {cat.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Date */}
              <div className="flex flex-col gap-1.5">
                <Label htmlFor="date" className="text-sm font-medium text-gray-700">
                  Date <span className="text-red-500">*</span>
                </Label>
                <Input
                  id="date"
                  type="date"
                  value={expenseForm.date}
                  onChange={(e) => handleDateChange(e.target.value)}
                  className="border-gray-200 focus:border-blue-600 focus:ring-blue-600"
                  required
                />
              </div>

              {/* Payment Method */}
              <div className="flex flex-col gap-1.5">
                <Label className="text-sm font-medium text-gray-700">
                  Payment Method
                </Label>
                <div className="flex flex-wrap gap-2">
                  {PAYMENT_METHODS.map((method) => (
                    <button
                      key={method.value}
                      type="button"
                      onClick={() =>
                        setExpenseForm((prev) => ({
                          ...prev,
                          paymentMethod:
                            prev.paymentMethod === method.value ? "" : method.value,
                        }))
                      }
                      className={cn(
                        "px-3 py-1.5 rounded-full border text-xs font-medium transition-all duration-150 min-h-[32px] focus:outline-none focus:ring-2 focus:ring-blue-600 focus:ring-offset-1",
                        expenseForm.paymentMethod === method.value
                          ? "bg-blue-100 border-blue-600 text-blue-600"
                          : "bg-white border-gray-200 text-gray-600 hover:border-gray-300"
                      )}
                    >
                      {method.label}
                    </button>
                  ))}
                </div>
              </div>

              {/* Note */}
              <div className="flex flex-col gap-1.5">
                <Label htmlFor="note" className="text-sm font-medium text-gray-700">
                  Note
                </Label>
                <Textarea
                  id="note"
                  placeholder="Add a note..."
                  value={expenseForm.note}
                  onChange={(e) =>
                    setExpenseForm((prev) => ({ ...prev, note: e.target.value }))
                  }
                  rows={2}
                  className="border-gray-200 focus:border-blue-600 focus:ring-blue-600 resize-none text-sm"
                />
              </div>

              {/* Divider */}
              <div className="border-t border-gray-100" />

              {/* Recurrence Config Section */}
              <RecurrenceConfigSection
                isRecurring={recurrence.isRecurring}
                frequency={recurrence.frequency}
                startDate={recurrence.startDate}
                endDateMode={recurrence.endDateMode}
                endDate={recurrence.endDate}
                onIsRecurringChange={(value) =>
                  setRecurrence((prev) => ({ ...prev, isRecurring: value }))
                }
                onFrequencyChange={(value) =>
                  setRecurrence((prev) => ({ ...prev, frequency: value }))
                }
                onEndDateModeChange={(value) =>
                  setRecurrence((prev) => ({ ...prev, endDateMode: value }))
                }
                onEndDateChange={(value) =>
                  setRecurrence((prev) => ({ ...prev, endDate: value }))
                }
                isEditingSeries={false}
              />

              {/* Submit */}
              <Button
                type="submit"
                disabled={isSubmitting || !expenseForm.amount || !expenseForm.categoryId}
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-3 rounded-xl transition-colors duration-150 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isSubmitting
                  ? "Saving..."
                  : recurrence.isRecurring
                  ? "Save Recurring Expense"
                  : "Save Expense"}
              </Button>

            </CardContent>
          </Card>
        </form>
      </div>
    </div>
  );
};

export default AddExpenseForm;
