import React, { useEffect, useRef, useState } from "react";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";

// ── Types ────────────────────────────────────────────────────────────────────

type BudgetStatus = "On Track" | "Heads Up" | "Over Budget";

interface MonthSummary {
  id: string;
  month: string;
  totalSpent: number;
  transactionCount: number;
  dailyAverage: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
  remainingAmount: number;
  updatedAt: string;
}

interface BudgetSummaryCardProps {
  monthSummary: MonthSummary;
  currency: string;
  animateOnMount?: boolean;
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function formatCurrency(amount: number, currency: string): string {
  try {
    return new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: currency || "USD",
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(amount);
  } catch {
    return `$${amount.toFixed(2)}`;
  }
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

// ── Sub-components ────────────────────────────────────────────────────────────

// StatusBadge
interface StatusBadgeProps {
  status: BudgetStatus;
}

const statusConfig: Record<
  BudgetStatus,
  { label: string; className: string }
> = {
  "On Track": {
    label: "✓ On Track",
    className:
      "bg-blue-100 text-blue-700 border-0 font-semibold text-xs px-3 py-1 rounded-full",
  },
  "Heads Up": {
    label: "⚠ Heads Up",
    className:
      "bg-amber-100 text-amber-700 border-0 font-semibold text-xs px-3 py-1 rounded-full",
  },
  "Over Budget": {
    label: "✕ Over Budget",
    className:
      "bg-red-100 text-red-700 border-0 font-semibold text-xs px-3 py-1 rounded-full",
  },
};

function StatusBadge({ status }: StatusBadgeProps) {
  const config = statusConfig[status];
  return (
    <span className={config.className} role="status" aria-label={`Budget status: ${status}`}>
      {config.label}
    </span>
  );
}

// AnimatedAmountDisplay
interface AnimatedAmountDisplayProps {
  amount: number;
  currency: string;
  label: string;
  animate: boolean;
}

function AnimatedAmountDisplay({
  amount,
  currency,
  label,
  animate,
}: AnimatedAmountDisplayProps) {
  const [displayAmount, setDisplayAmount] = useState(animate ? 0 : amount);
  const frameRef = useRef<number | null>(null);
  const startTimeRef = useRef<number | null>(null);
  const duration = 900;

  useEffect(() => {
    if (!animate) {
      setDisplayAmount(amount);
      return;
    }
    startTimeRef.current = null;
    const step = (timestamp: number) => {
      if (startTimeRef.current === null) startTimeRef.current = timestamp;
      const elapsed = timestamp - startTimeRef.current;
      const progress = clamp(elapsed / duration, 0, 1);
      // ease-out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayAmount(eased * amount);
      if (progress < 1) {
        frameRef.current = requestAnimationFrame(step);
      } else {
        setDisplayAmount(amount);
      }
    };
    frameRef.current = requestAnimationFrame(step);
    return () => {
      if (frameRef.current !== null) cancelAnimationFrame(frameRef.current);
    };
  }, [amount, animate]);

  return (
    <div className="flex flex-col gap-0.5">
      <span className="text-sm text-gray-500 font-medium">{label}</span>
      <span
        className="text-4xl font-bold text-gray-900 tabular-nums leading-tight"
        aria-live="polite"
      >
        {formatCurrency(displayAmount, currency)}
      </span>
    </div>
  );
}

// BudgetProgressBar
interface BudgetProgressBarProps {
  spentAmount: number;
  budgetLimit: number;
  status: BudgetStatus;
}

function BudgetProgressBar({
  spentAmount,
  budgetLimit,
  status,
}: BudgetProgressBarProps) {
  const percentage = budgetLimit > 0 ? (spentAmount / budgetLimit) * 100 : 0;
  const clamped = clamp(percentage, 0, 100);

  const fillColor =
    status === "Over Budget"
      ? "bg-red-500"
      : status === "Heads Up"
      ? "bg-amber-500"
      : "bg-blue-600";

  return (
    <div className="w-full" role="progressbar" aria-valuenow={Math.round(clamped)} aria-valuemin={0} aria-valuemax={100} aria-label={`Budget used: ${Math.round(clamped)}%`}>
      <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
        <div
          className={`h-full rounded-full transition-all duration-700 ease-out ${fillColor}`}
          style={{ width: `${clamped}%` }}
        />
      </div>
      <div className="flex justify-between mt-1">
        <span className="text-xs text-gray-400 tabular-nums">
          {Math.round(clamped)}% used
        </span>
        <span className="text-xs text-gray-400 tabular-nums">
          100%
        </span>
      </div>
    </div>
  );
}

// BudgetRemainingDisplay
interface BudgetRemainingDisplayProps {
  remainingAmount: number;
  currency: string;
  isOverBudget: boolean;
}

function BudgetRemainingDisplay({
  remainingAmount,
  currency,
  isOverBudget,
}: BudgetRemainingDisplayProps) {
  const absAmount = Math.abs(remainingAmount);
  const textColor = isOverBudget ? "text-red-500" : "text-gray-600";
  const label = isOverBudget
    ? `${formatCurrency(absAmount, currency)} over budget`
    : `${formatCurrency(absAmount, currency)} remaining`;

  return (
    <div className="flex items-center justify-between">
      <span className={`text-sm font-semibold tabular-nums ${textColor}`}>
        {label}
      </span>
    </div>
  );
}

// DailyAverageDisplay
interface DailyAverageDisplayProps {
  dailyAverage: number;
  currency: string;
  transactionCount: number;
}

function DailyAverageDisplay({
  dailyAverage,
  currency,
  transactionCount,
}: DailyAverageDisplayProps) {
  return (
    <div className="flex items-center justify-between pt-1 border-t border-gray-100">
      <div className="flex flex-col gap-0.5">
        <span className="text-xs text-gray-400">Daily Average</span>
        <span className="text-sm font-semibold text-gray-700 tabular-nums">
          {formatCurrency(dailyAverage, currency)}
        </span>
      </div>
      <div className="flex flex-col gap-0.5 items-end">
        <span className="text-xs text-gray-400">Transactions</span>
        <span className="text-sm font-semibold text-gray-700 tabular-nums">
          {transactionCount}
        </span>
      </div>
    </div>
  );
}

// ── Main Component ────────────────────────────────────────────────────────────

const BudgetSummaryCard: React.FC<BudgetSummaryCardProps> = ({
  monthSummary,
  currency,
  animateOnMount = true,
}) => {
  const {
    totalSpent,
    budgetLimit,
    remainingAmount,
    budgetStatus,
    dailyAverage,
    transactionCount,
    month,
  } = monthSummary;

  const isOverBudget = budgetStatus === "Over Budget";

  // Format month label e.g. "2026-03" → "March 2026"
  const monthLabel = (() => {
    try {
      const [year, mon] = month.split("-");
      const date = new Date(Number(year), Number(mon) - 1, 1);
      return date.toLocaleDateString("en-US", { month: "long", year: "numeric" });
    } catch {
      return month;
    }
  })();

  return (
    <Card
      className="w-full bg-white rounded-2xl shadow-sm border border-gray-100 p-6 flex flex-col gap-4"
      aria-label="Monthly Budget Summary"
    >
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex flex-col gap-0.5">
          <h2 className="text-base font-semibold text-gray-900">Monthly Budget</h2>
          <span className="text-xs text-gray-400">{monthLabel}</span>
        </div>
        <StatusBadge status={budgetStatus} />
      </div>

      {/* Amount Display */}
      <div className="flex items-end justify-between gap-2">
        <AnimatedAmountDisplay
          amount={totalSpent}
          currency={currency}
          label="Spent"
          animate={animateOnMount}
        />
        <div className="flex flex-col gap-0.5 text-right">
          <span className="text-sm text-gray-500">of</span>
          <span className="text-lg font-semibold text-gray-700 tabular-nums">
            {formatCurrency(budgetLimit, currency)}
          </span>
        </div>
      </div>

      {/* Progress Bar */}
      <BudgetProgressBar
        spentAmount={totalSpent}
        budgetLimit={budgetLimit}
        status={budgetStatus}
      />

      {/* Remaining */}
      <BudgetRemainingDisplay
