// ── Helpers ──────────────────────────────────────────────────────────────────

function formatCurrency(amount: number, currency = "USD"): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency,
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(Math.abs(amount));
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

// ── Sub-components ───────────────────────────────────────────────────────────

// StatusBadge
interface StatusBadgeProps {
  status: BudgetStatus;
}

const STATUS_CONFIG: Record<
  BudgetStatus,
  { label: string; bg: string; text: string }
> = {
  "On Track": {
    label: "✓ On Track",
    bg: "bg-blue-100",
    text: "text-blue-700",
  },
  "Heads Up": {
    label: "⚠ Heads Up",
    bg: "bg-amber-100",
    text: "text-amber-700",
  },
  "Over Budget": {
    label: "✕ Over Budget",
    bg: "bg-red-100",
    text: "text-red-700",
  },
};

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const config = STATUS_CONFIG[status];
  return (
    <span
      className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold ${config.bg} ${config.text}`}
    >
      {config.label}
    </span>
  );
};

// AnimatedCounter
interface AnimatedCounterProps {
  target: number;
  duration?: number;
  animate?: boolean;
}

const AnimatedCounter: React.FC<AnimatedCounterProps> = ({
  target,
  duration = 800,
  animate = true,
}) => {
  const [displayed, setDisplayed] = useState(animate ? 0 : target);
  const rafRef = useRef<number | null>(null);
  const startRef = useRef<number | null>(null);

  useEffect(() => {
    if (!animate) {
      setDisplayed(target);
      return;
    }
    startRef.current = null;
    const startValue = 0;

    const step = (timestamp: number) => {
      if (startRef.current === null) startRef.current = timestamp;
      const elapsed = timestamp - startRef.current;
      const progress = clamp(elapsed / duration, 0, 1);
      // ease-out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayed(startValue + (target - startValue) * eased);
      if (progress < 1) {
        rafRef.current = requestAnimationFrame(step);
      }
    };

    rafRef.current = requestAnimationFrame(step);
    return () => {
      if (rafRef.current !== null) cancelAnimationFrame(rafRef.current);
    };
  }, [target, duration, animate]);

  return <>{displayed}</>;
};

// AnimatedAmountDisplay
interface AnimatedAmountDisplayProps {
  amount: number;
  currency: string;
  label: string;
  animateCounter?: boolean;
}

const AnimatedAmountDisplay: React.FC<AnimatedAmountDisplayProps> = ({
  amount,
  currency,
  label,
  animateCounter = true,
}) => {
  const [displayAmount, setDisplayAmount] = useState(animateCounter ? 0 : amount);
  const rafRef = useRef<number | null>(null);
  const startRef = useRef<number | null>(null);
  const duration = 800;

  useEffect(() => {
    if (!animateCounter) {
      setDisplayAmount(amount);
      return;
    }
    startRef.current = null;
    const startValue = 0;

    const step = (timestamp: number) => {
      if (startRef.current === null) startRef.current = timestamp;
      const elapsed = timestamp - startRef.current;
      const progress = clamp(elapsed / duration, 0, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayAmount(startValue + (amount - startValue) * eased);
      if (progress < 1) {
        rafRef.current = requestAnimationFrame(step);
      }
    };

    rafRef.current = requestAnimationFrame(step);
    return () => {
      if (rafRef.current !== null) cancelAnimationFrame(rafRef.current);
    };
  }, [amount, animateCounter]);

  return (
    <div className="flex flex-col gap-0.5">
      <span className="text-sm text-gray-500 font-medium">{label}</span>
      <span
        className="text-4xl font-bold text-gray-900 tabular-nums"
        style={{ fontFamily: "Inter, sans-serif" }}
      >
        {formatCurrency(displayAmount, currency)}
      </span>
    </div>
  );
};

// BudgetProgressBar
interface BudgetProgressBarProps {
  spentAmount: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
  animateOnMount?: boolean;
}

const BudgetProgressBar: React.FC<BudgetProgressBarProps> = ({
  spentAmount,
  budgetLimit,
  budgetStatus,
  animateOnMount = true,
}) => {
  const rawPercent = budgetLimit > 0 ? (spentAmount / budgetLimit) * 100 : 0;
  const cappedPercent = clamp(rawPercent, 0, 100);

  const [width, setWidth] = useState(animateOnMount ? 0 : cappedPercent);

  useEffect(() => {
    if (!animateOnMount) {
      setWidth(cappedPercent);
      return;
    }
    const timer = setTimeout(() => setWidth(cappedPercent), 80);
    return () => clearTimeout(timer);
  }, [cappedPercent, animateOnMount]);

  let fillColor = "bg-blue-600";
  if (budgetStatus === "Over Budget") fillColor = "bg-red-500";
  else if (budgetStatus === "Heads Up") fillColor = "bg-amber-500";

  return (
    <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
      <div
        className={`h-full rounded-full transition-all duration-700 ease-out ${fillColor}`}
        style={{ width: `${width}%` }}
        role="progressbar"
        aria-valuenow={Math.round(rawPercent)}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={`Budget used: ${Math.round(rawPercent)}%`}
      />
    </div>
  );
};

// BudgetRemainingDisplay
interface BudgetRemainingDisplayProps {
  remainingAmount: number;
  currency: string;
  isOverBudget: boolean;
  budgetLimit: number;
  totalSpent: number;
