  return (
    <div className="flex items-center justify-between w-full">
      <div className="flex items-center gap-1.5">
        <span className="text-xs text-gray-500">of</span>
        <span
          className="text-sm font-semibold text-gray-500 tabular-nums"
          style={{ fontFamily: "Inter, sans-serif" }}
        >
          {formatCurrency(budgetLimit, currency)}
        </span>
      </div>
      <div className="flex items-center gap-1.5">
        <span
          className={`text-sm font-semibold tabular-nums ${textColor}`}
          style={{ fontFamily: "Inter, sans-serif" }}
        >
          {isOverBudget
            ? `${formatCurrency(Math.abs(remainingAmount), currency)} over`
            : `${formatCurrency(remainingAmount, currency)} left`}
        </span>
        <span className="text-xs text-gray-400">
          ({Math.round(clamp(rawPercent, 0, 999))}%)
        </span>
      </div>
    </div>
  );
};

