        className="text-sm font-semibold text-gray-700 tabular-nums"
        style={{ fontFamily: "Inter, sans-serif" }}
      >
        {transactionCount}
      </span>
    </div>
  </div>
);

// ── Main Component ────────────────────────────────────────────────────────────

const BudgetSummaryCard: React.FC<BudgetSummaryCardProps> = ({
  monthSummary,
