const MONTHS = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December",
];

// ─── Helpers ──────────────────────────────────────────────────────────────────

function formatCurrency(amount: number, currency = "USD"): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency,
    minimumFractionDigits: 2,
  }).format(amount);
}

function formatMonthLabel(monthStr: string): string {
  const [year, month] = monthStr.split("-");
  return `${MONTHS[parseInt(month, 10) - 1]} ${year}`;
}

function formatDate(dateStr: string): string {
  const d = new Date(dateStr);
  return `${MONTHS[d.getMonth()].slice(0, 3)} ${d.getDate()}`;
}

function trendPct(current: number, previous: number): number {
  if (previous === 0) return 0;
  return Math.abs(((current - previous) / previous) * 100);
}

// ─── Sub-components ───────────────────────────────────────────────────────────

interface StatCellProps {
  label: string;
  value: string;
  trendDirection: "up" | "down" | "same";
  trendLabel: string;
  borderRight?: boolean;
}

const StatCell: React.FC<StatCellProps> = ({ label, value, trendDirection, trendLabel, borderRight }) => {
  const trendColor =
    trendDirection === "up"
      ? "bg-red-100 text-red-700"
      : trendDirection === "down"
      ? "bg-emerald-100 text-emerald-700"
      : "bg-gray-100 text-gray-700";

  const arrow = trendDirection === "up" ? "↑" : trendDirection === "down" ? "↓" : "→";

  return (
    <div
      className={`flex flex-col gap-2 px-8 py-6 flex-1 ${borderRight ? "border-r border-gray-200" : ""}`}
    >
      <p className="text-sm text-gray-500 font-medium">{label}</p>
      <p className="text-2xl font-bold text-gray-900 tabular-nums">{value}</p>
      <span className={`inline-flex items-center self-start px-2.5 py-0.5 rounded-full text-xs font-semibold ${trendColor}`}>
        {arrow} {trendLabel}
      </span>
    </div>
  );
};

interface DailyChartProps {
  data: DailySpending[];
  averageDaily: number;
  mode: "bar" | "line";
  currency: string;
}

const DailyChart: React.FC<DailyChartProps> = ({ data, averageDaily, mode, currency }) => {
  const [tooltip, setTooltip] = useState<{ point: DailySpending; x: number } | null>(null);
  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);
  const chartHeight = 180;

  if (mode === "bar") {
    return (
      <div className="relative">
        <div
          className="flex items-end justify-between gap-1 px-2 py-3 border border-gray-200 rounded-lg bg-white"
          style={{ height: chartHeight + 24 }}
          role="img"
          aria-label="Daily spending bar chart"
        >
          {data.map((point, i) => {
            const barH = Math.max((point.totalAmount / maxAmount) * chartHeight, 4);
            const isHigh = point.totalAmount > averageDaily * 1.3;
            return (
              <div
                key={point.date}
                className="relative flex-1 flex flex-col items-center justify-end cursor-pointer group"
                style={{ height: chartHeight }}
                onMouseEnter={(e) => setTooltip({ point, x: e.currentTarget.getBoundingClientRect().left })}
                onMouseLeave={() => setTooltip(null)}
              >
                <div
                  className="w-full rounded-sm transition-opacity group-hover:opacity-80"
                  style={{
                    height: barH,
                    backgroundColor: isHigh ? "#EF4444" : "#2563EB",
                    minWidth: 8,
                  }}
                />
                {tooltip?.point.date === point.date && (
                  <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 z-10 bg-white shadow-lg rounded-lg p-2 text-xs whitespace-nowrap border border-gray-100">
                    <p className="font-semibold text-gray-900">{formatCurrency(point.totalAmount, currency)}</p>
                    <p className="text-gray-500">{formatDate(point.date)}</p>
                    <p className="text-gray-500">{point.transactionCount} txns</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
        <div className="flex items-center gap-2 mt-2">
          <div className="flex-1 border-t-2 border-dashed border-amber-500" />
          <span className="text-xs text-gray-500 whitespace-nowrap">
            Avg {formatCurrency(averageDaily, currency)} / day
          </span>
        </div>
      </div>
    );
  }

  // Line chart
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * 100,
    y: 100 - (d.totalAmount / maxAmount) * 100,
    data: d,
  }));

  const pathD = points
    .map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`)
    .join(" ");

  const fillD = `${pathD} L 100 100 L 0 100 Z`;

  return (
    <div className="relative">
      <div
        className="border border-gray-200 rounded-lg bg-white overflow-hidden"
        style={{ height: chartHeight + 24 }}
        role="img"
        aria-label="Daily spending line chart"
      >
        <svg
          viewBox="0 0 100 100"
          preserveAspectRatio="none"
          className="w-full h-full"
        >
          <path d={fillD} fill="#DBEAFE" opacity="0.6" />
          <path d={pathD} fill="none" stroke="#2563EB" strokeWidth="0.5" />
          {points.map((p, i) => (
            <circle
              key={i}
              cx={p.x}
              cy={p.y}
              r="1.2"
              fill="#2563EB"
              className="cursor-pointer"
              onMouseEnter={() => setTooltip({ point: p.data, x: 0 })}
              onMouseLeave={() => setTooltip(null)}
            />
          ))}
        </svg>
        {tooltip && (
          <div className="absolute top-2 left-2 z-10 bg-white shadow-lg rounded-lg p-2 text-xs border border-gray-100">
            <p className="font-semibold text-gray-900">{formatCurrency(tooltip.point.totalAmount, currency)}</p>
            <p className="text-gray-500">{formatDate(tooltip.point.date)}</p>
            <p className="text-gray-500">{tooltip.point.transactionCount} txns</p>
          </div>
        )}
      </div>
      <div className="flex items-center gap-2 mt-2">
        <div className="flex-1 border-t-2 border-dashed border-amber-500" />
        <span className="text-xs text-gray-500 whitespace-nowrap">
          Avg {formatCurrency(averageDaily, currency)} / day
        </span>
      </div>
    </div>
  );
};

