interface StatCellProps {
  label: string;
  value: string;
  trendDirection: "up" | "down" | "same";
  trendLabel: string;
  borderRight?: boolean;
}

const StatCell: React.FC<StatCellProps> = ({ label, value, trendDirection, trendLabel, borderRight }) => {
  const trendColor =
    trendDirection === "up" ? "bg-red-100 text-red-700" :
    trendDirection === "down" ? "bg-emerald-100 text-emerald-700" :
    "bg-gray-100 text-gray-700";

  return (
    <div
      className={`flex flex-col gap-2 px-8 py-6 flex-1 ${borderRight ? "border-r border-gray-200" : ""}`}
    >
      <span className="text-sm text-gray-500 font-medium">{label}</span>
      <span className="text-2xl font-bold text-gray-900 tabular-nums">{value}</span>
      <span className={`inline-flex w-fit items-center px-2.5 py-0.5 rounded-full text-xs font-semibold ${trendColor}`}>
        {trendLabel}
      </span>
    </div>
  );
};

// ─── Daily Spending Chart ─────────────────────────────────────────────────────

interface DailyChartProps {
  data: DailySpending[];
  averageDaily: number;
  currency: string;
  mode: "bar" | "line";
}

const DailySpendingChart: React.FC<DailyChartProps> = ({ data, averageDaily, currency, mode }) => {
  const [hoveredIdx, setHoveredIdx] = useState<number | null>(null);
  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);
  const chartHeight = 180;

  if (mode === "bar") {
    return (
      <div className="relative w-full" style={{ height: chartHeight + 24 }}>
        {/* Average line */}
        <div
          className="absolute left-0 right-0 border-t-2 border-dashed border-amber-400 z-10 pointer-events-none"
          style={{ bottom: ((averageDaily / maxAmount) * chartHeight) + 12 }}
        />
        <div className="flex items-end justify-between gap-1 px-2 h-full pb-6">
          {data.map((d, i) => {
            const barH = Math.max(4, (d.totalAmount / maxAmount) * chartHeight);
            const isHigh = d.totalAmount > averageDaily * 1.3;
            const isHovered = hoveredIdx === i;
            return (
              <div
                key={d.date}
                className="relative flex flex-col items-center flex-1 cursor-pointer group"
                onMouseEnter={() => setHoveredIdx(i)}
                onMouseLeave={() => setHoveredIdx(null)}
              >
                {isHovered && (
                  <div className="absolute bottom-full mb-2 z-20 bg-white shadow-lg rounded-lg px-3 py-2 text-xs whitespace-nowrap border border-gray-100">
                    <div className="font-semibold text-gray-900">{formatDate(d.date)}</div>
                    <div className="text-gray-700 tabular-nums">{formatCurrency(d.totalAmount, currency)}</div>
                    <div className="text-gray-500">{d.transactionCount} txns</div>
                  </div>
                )}
                <div
                  className="w-full rounded-t transition-all duration-150"
                  style={{
                    height: barH,
                    backgroundColor: isHigh ? "#EF4444" : "#2563EB",
                    opacity: hoveredIdx !== null && !isHovered ? 0.6 : 1,
                  }}
                />
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  // Line mode
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * 100,
    y: 100 - (d.totalAmount / maxAmount) * 100,
    ...d,
  }));

  const pathD = points.map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`).join(" ");
  const fillD = `${pathD} L ${points[points.length - 1].x} 100 L ${points[0].x} 100 Z`;

  return (
    <div className="relative w-full" style={{ height: chartHeight + 24 }}>
      <svg
        viewBox="0 0 100 100"
        preserveAspectRatio="none"
        className="w-full"
        style={{ height: chartHeight }}
      >
        <defs>
          <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#BFDBFE" stopOpacity="0.8" />
            <stop offset="100%" stopColor="#BFDBFE" stopOpacity="0" />
          </linearGradient>
        </defs>
        <path d={fillD} fill="url(#lineGrad)" />
        <path d={pathD} fill="none" stroke="#2563EB" strokeWidth="1.5" vectorEffect="non-scaling-stroke" />
        {/* Average line */}
        <line
          x1="0"
          y1={100 - (averageDaily / maxAmount) * 100}
          x2="100"
          y2={100 - (averageDaily / maxAmount) * 100}
          stroke="#F59E0B"
          strokeWidth="1"
          strokeDasharray="4 2"
          vectorEffect="non-scaling-stroke"
        />
        {points.map((p, i) => (
          <circle
            key={i}
            cx={p.x}
            cy={p.y}
            r="1.5"
            fill="#2563EB"
            vectorEffect="non-scaling-stroke"
            className="cursor-pointer"
            onMouseEnter={() => setHoveredIdx(i)}
            onMouseLeave={() => setHoveredIdx(null)}
          />
        ))}
      </svg>
    </div>
  );
};

