interface MonthComparisonCardProps {
  currentMonth: string;
  currentAmount: number;
  previousMonth: string;
  previousAmount: number;
  delta: number;
  deltaDirection: "less" | "more" | "same";
  currency: string;
}

const MonthComparisonCard: React.FC<MonthComparisonCardProps> = ({
  currentMonth,
  currentAmount,
  previousMonth,
  previousAmount,
  delta,
  deltaDirection,
  currency,
}) => {
  const maxAmount = Math.max(currentAmount, previousAmount, 1);
  const currentPct = (currentAmount / maxAmount) * 100;
  const previousPct = (previousAmount / maxAmount) * 100;

  const badgeClass =
    deltaDirection === "less"
      ? "bg-emerald-100 text-emerald-700"
      : deltaDirection === "more"
      ? "bg-red-100 text-red-700"
      : "bg-gray-100 text-gray-700";

  const badgeLabel =
    deltaDirection === "less"
      ? `↓ ${formatCurrency(delta, currency)} less than ${previousMonth}`
      : deltaDirection === "more"
      ? `↑ ${formatCurrency(delta, currency)} more than ${previousMonth}`
      : `Same as ${previousMonth}`;

  return (
    <Card className="p-6 rounded-2xl border border-gray-200 shadow-sm">
      <div className="flex items-center justify-between mb-5">
        <h2 className="text-base font-semibold text-gray-900">Month-over-Month Comparison</h2>
        <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold ${badgeClass}`}>
          {badgeLabel}
        </span>
      </div>
      <div className="flex flex-col gap-4">
        {/* Current month */}
        <div className="flex flex-col gap-1.5">
          <div className="flex justify-between text-xs">
            <span className="text-gray-500">{currentMonth}</span>
            <span className="font-semibold text-gray-900 tabular-nums">{formatCurrency(currentAmount, currency)}</span>
          </div>
          <div className="w-full h-8 bg-gray-100 rounded-md overflow-hidden">
            <div
              className="h-full bg-blue-600 rounded-md transition-all duration-700"
              style={{ width: `${currentPct}%` }}
            />
          </div>
        </div>
        {/* Previous month */}
        <div className="flex flex-col gap-1.5">
          <div className="flex justify-between text-xs">
            <span className="text-gray-500">{previousMonth}</span>
            <span className="font-semibold text-gray-900 tabular-nums">{formatCurrency(previousAmount, currency)}</span>
          </div>
          <div className="w-full h-8 bg-gray-100 rounded-md overflow-hidden">
            <div
              className="h-full bg-gray-300 rounded-md transition-all duration-700"
              style={{ width: `${previousPct}%` }}
            />
          </div>
        </div>
      </div>
    </Card>
  );
};

