interface DailyChartProps {
  data: DailySpending[];
  averageDaily: number;
  currency: string;
  mode: "bar" | "line";
}

const DailyChart: React.FC<DailyChartProps> = ({ data, averageDaily, currency, mode }) => {
  const [hoveredPoint, setHoveredPoint] = useState<DailySpending | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);
  const chartHeight = 180;

  if (mode === "bar") {
    return (
      <div className="relative">
        <div
          className="flex items-end justify-between gap-1 px-2 py-3 border border-gray-200 rounded-xl bg-white"
          style={{ height: `${chartHeight + 24}px` }}
          role="img"
          aria-label="Daily spending bar chart"
        >
          {data.map((point) => {
            const barHeight = Math.max((point.totalAmount / maxAmount) * chartHeight, 4);
            const isAboveAverage = point.totalAmount > averageDaily * 1.3;
            return (
              <div
                key={point.date}
                className="relative flex-1 flex flex-col items-center justify-end cursor-pointer group"
                style={{ height: `${chartHeight}px` }}
                onMouseEnter={(e) => {
                  setHoveredPoint(point);
                  setTooltipPos({ x: e.clientX, y: e.clientY });
                }}
                onMouseLeave={() => setHoveredPoint(null)}
              >
                <div
                  className="w-full rounded-t transition-all duration-200 group-hover:opacity-80"
                  style={{
                    height: `${barHeight}px`,
                    backgroundColor: isAboveAverage ? "#EF4444" : "#2563EB",
                    minWidth: "8px",
                    maxWidth: "24px",
                  }}
                />
              </div>
            );
          })}
        </div>
        {hoveredPoint && (
          <div
            className="fixed z-50 bg-white shadow-lg rounded-xl p-3 text-sm pointer-events-none border border-gray-100"
            style={{ left: tooltipPos.x + 12, top: tooltipPos.y - 60 }}
          >
            <p className="font-semibold text-gray-900">{formatDate(hoveredPoint.date)}</p>
            <p className="text-gray-700 tabular-nums">{formatCurrency(hoveredPoint.totalAmount, currency)}</p>
            <p className="text-gray-500">{hoveredPoint.transactionCount} transactions</p>
          </div>
        )}
      </div>
    );
  }

  // Line chart
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * 100,
    y: 100 - (d.totalAmount / maxAmount) * 100,
    data: d,
  }));

  const pathD = points
    .map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`)
    .join(" ");

  const fillD = `${pathD} L 100 100 L 0 100 Z`;

  return (
    <div className="relative border border-gray-200 rounded-xl bg-white p-3" style={{ height: `${chartHeight + 24}px` }}>
      <svg
        viewBox="0 0 100 100"
        preserveAspectRatio="none"
        className="w-full h-full"
        role="img"
        aria-label="Daily spending line chart"
      >
        <path d={fillD} fill="#DBEAFE" opacity="0.6" />
        <path d={pathD} fill="none" stroke="#2563EB" strokeWidth="0.8" />
        {points.map((p) => (
          <circle
            key={p.data.date}
            cx={p.x}
            cy={p.y}
            r="1.5"
            fill="#2563EB"
            className="cursor-pointer"
            onMouseEnter={(e) => {
              setHoveredPoint(p.data);
              setTooltipPos({ x: e.clientX, y: e.clientY });
            }}
            onMouseLeave={() => setHoveredPoint(null)}
          />
        ))}
      </svg>
      {hoveredPoint && (
        <div
          className="fixed z-50 bg-white shadow-lg rounded-xl p-3 text-sm pointer-events-none border border-gray-100"
          style={{ left: tooltipPos.x + 12, top: tooltipPos.y - 60 }}
        >
          <p className="font-semibold text-gray-900">{formatDate(hoveredPoint.date)}</p>
          <p className="text-gray-700 tabular-nums">{formatCurrency(hoveredPoint.totalAmount, currency)}</p>
          <p className="text-gray-500">{hoveredPoint.transactionCount} transactions</p>
        </div>
      )}
    </div>
  );
};

