        <div
          style={{
            padding: "12px 14px",
            borderRight: "1px solid #E5E7EB",
            background: "#F3F4F6",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            minWidth: 44,
          }}
        >
          <span style={{ fontSize: 14, fontWeight: 500, color: "#6B7280" }}>
            {CURRENCY_SYMBOLS[currency]}
          </span>
        </div>
        <input
          type="text"
          inputMode="decimal"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onBlur={handleBlur}
          placeholder="0.00"
          style={{
            flex: 1,
            border: "none",
            outline: "none",
            background: "transparent",
            padding: "12px",
            fontSize: 14,
            color: "#111827",
            fontVariantNumeric: "tabular-nums",
          }}
        />
      </div>
    </div>
  );
};

