interface BudgetLimitInputProps {
  value: number;
  onChange: (value: number) => void;
  currency: Currency;
  label: string;
}

const BudgetLimitInput: React.FC<BudgetLimitInputProps> = ({
  value,
  onChange,
  currency,
  label,
}) => {
  const [raw, setRaw] = useState(value.toFixed(2));

  useEffect(() => {
    setRaw(value.toFixed(2));
  }, [value]);

  const handleBlur = () => {
    const parsed = parseFloat(raw.replace(/,/g, ""));
    if (!isNaN(parsed) && parsed >= 0) {
      onChange(parsed);
      setRaw(parsed.toFixed(2));
    } else {
      setRaw(value.toFixed(2));
    }
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 6, width: "100%" }}>
      <Label style={{ fontSize: 13, fontWeight: 500, color: "#374151" }}>
        {label}
      </Label>
      <div
        style={{
          display: "flex",
          flexDirection: "row",
          alignItems: "center",
          border: "1px solid #e5e7eb",
          borderRadius: 10,
          background: "#f9fafb",
          overflow: "hidden",
          width: "100%",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            padding: "12px 14px",
            borderRight: "1px solid #e5e7eb",
            background: "#f3f4f6",
            minWidth: 44,
          }}
        >
          <span style={{ fontSize: 14, fontWeight: 500, color: "#6b7280" }}>
            {CURRENCY_SYMBOLS[currency]}
          </span>
        </div>
        <input
          type="text"
          inputMode="decimal"
          value={raw}
          onChange={(e) => setRaw(e.target.value)}
          onBlur={handleBlur}
          placeholder="0.00"
          style={{
            flex: 1,
            border: "none",
            outline: "none",
            background: "transparent",
            padding: "12px",
            fontSize: 14,
            color: "#111827",
            fontVariantNumeric: "tabular-nums",
          }}
        />
      </div>
    </div>
  );
};

