interface SettingsFormProps {
  isOpen?: boolean;
  onClose?: () => void;
}

const SettingsForm: React.FC<SettingsFormProps> = ({
  isOpen = true,
  onClose = () => {},
}) => {
  const [settings, setSettings] = useState<UserSettings>(INITIAL_SETTINGS);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [budgetValue, setBudgetValue] = useState<number>(INITIAL_SETTINGS.defaultMonthlyBudget);
  const [useSystemLocale, setUseSystemLocale] = useState(false);
  const [statusText, setStatusText] = useState("");
  const [toast, setToast] = useState<ToastState>({ message: "", visible: false });
  const [isSaving, setIsSaving] = useState(false);

  const showToast = useCallback((message: string) => {
    setToast({ message, visible: true });
    setTimeout(() => setToast({ message: "", visible: false }), 3000);
  }, []);

  // Close on Escape key
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape" && isOpen) onClose();
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, onClose]);

  const handleCurrencyChange = async (currency: Currency) => {
    setSettings((prev) => ({ ...prev, currency }));
    // PUT /api/settings
    try {
      // await fetch('/api/settings', { method: 'PUT', body: JSON.stringify({ currency }) });
      showToast(`Currency changed to ${CURRENCY_LABELS[currency]}`);
    } catch {
      showToast("Failed to update currency");
    }
  };

  const handleBudgetChange = (value: number) => {
    setBudgetValue(value);
    setSettings((prev) => ({ ...prev, defaultMonthlyBudget: value }));
  };

  const handleCategoryDelete = async (categoryId: string) => {
    const cat = categories.find((c) => c.id === categoryId);
    if (!cat || cat.isDefault) return;
    setCategories((prev) => prev.filter((c) => c.id !== categoryId));
    // DELETE /api/categories/{id}
    showToast(`Category "${cat.name}" deleted`);
  };

  const handleCategoryAdd = () => {
    // Navigate to screen-002 (add category)
    showToast("Opening add category…");
  };

  const handleSave = async () => {
    setIsSaving(true);
    setStatusText("Saving…");
    try {
      // PUT /api/settings
      // PUT /api/budgets/{month}
      await new Promise((r) => setTimeout(r, 800));
      setStatusText("Settings saved ✓");
      showToast("Settings saved successfully");
      setTimeout(() => setStatusText(""), 3000);
    } catch {
      setStatusText("Failed to save");
    } finally {
      setIsSaving(false);
    }
  };

  const handleResetBudgets = () => {
    if (window.confirm("Are you sure you want to reset all budgets? This cannot be undone.")) {
      setBudgetValue(0);
      setSettings((prev) => ({ ...prev, defaultMonthlyBudget: 0 }));
      showToast("All budgets reset");
    }
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Scrim */}
      <div
        onClick={onClose}
        style={{
          position: "fixed",
          inset: 0,
          background: "rgba(0,0,0,0.5)",
          zIndex: 40,
        }}
        aria-hidden="true"
      />

      {/* Drawer Panel */}
      <div
        role="dialog"
        aria-modal="true"
        aria-label="Settings"
        style={{
          position: "fixed",
          top: 0,
          right: 0,
          bottom: 0,
          width: "100%",
          maxWidth: 420,
          background: "#ffffff",
          zIndex: 50,
          display: "flex",
          flexDirection: "column",
          boxShadow: "0 25px 50px -12px rgba(0,0,0,0.25)",
          overflowY: "auto",
        }}
      >
        {/* Header */}
        <DialogHeader title="Settings" onClose={onClose} />

        {/* Content */}
        <div
          style={{
            flex: 1,
            overflowY: "auto",
            padding: "0 20px",
          }}
        >
          {/* Currency Section */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3
                style={{
                  fontSize: 16,
                  fontWeight: 600,
                  color: "#111827",
                  margin: 0,
                  marginBottom: 4,
                }}
              >
                Currency
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: 0 }}>
                Select your preferred display currency
              </p>
            </div>
            <CurrencySelector
              options={CURRENCY_OPTIONS}
              selectedCurrency={settings.currency}
              onSelect={handleCurrencyChange}
              label="Currency"
            />
          </section>

          <Separator />

          {/* Budget Section */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3
                style={{
                  fontSize: 16,
                  fontWeight: 600,
                  color: "#111827",
                  margin: 0,
                  marginBottom: 4,
                }}
              >
                Monthly Budget
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: 0 }}>
                Set your default monthly spending limit
              </p>
            </div>
            <BudgetLimitInput
              value={budgetValue}
              onChange={handleBudgetChange}
              currency={settings.currency}
              label="Budget Limit"
            />
          </section>

          <Separator />

          {/* Categories Section */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3
                style={{
                  fontSize: 16,
                  fontWeight: 600,
                  color: "#111827",
                  margin: 0,
                  marginBottom: 4,
                }}
              >
                Expense Categories
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: 0 }}>
                Manage your expense categories
              </p>
            </div>
            <CategoryManager
              categories={categories}
              onDelete={handleCategoryDelete}
              onAdd={handleCategoryAdd}
              addLabel="Add category"
            />
          </section>

          <Separator />

          {/* Preferences Section */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3
                style={{
                  fontSize: 16,
                  fontWeight: 600,
                  color: "#111827",
                  margin: 0,
                  marginBottom: 4,
                }}
              >
                Preferences
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: 0 }}>
                Customize your app experience
              </p>
            </div>
            <div
              style={{
                display: "flex",
                flexDirection: "row",
                alignItems: "center",
                justifyContent: "space-between",
                gap: 12,
                padding: "14px 16px",
                borderRadius: 10,
                background: "#f9fafb",
                border: "1px solid #e5e7eb",
              }}
            >
              <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
                <span style={{ fontSize: 14, fontWeight: 500, color: "#111827" }}>
                  Use system locale
                </span>
                <span style={{ fontSize: 12, color: "#6b7280" }}>
                  Format numbers and dates using device locale
                </span>
              </div>
              <Switch
                checked={useSystemLocale}
                onCheckedChange={setUseSystemLocale}
                aria-label="Toggle system locale"
              />
            </div>
          </section>

          <Separator />

          {/* Danger Zone */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3
                style={{
                  fontSize: 16,
                  fontWeight: 600,
                  color: "#ef4444",
                  margin: 0,
                  marginBottom: 4,
                }}
              >
                Danger Zone
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: 0 }}>
                Irreversible actions — proceed with caution
              </p>
            </div>
            <button
              onClick={handleResetBudgets}
              style={{
                width: "100%",
                minHeight: 44,
                borderRadius: 10,
                border: "1px solid #ef4444",
                background: "transparent",
                color: "#ef4444",
                fontSize: 14,
                fontWeight: 500,
                cursor: "pointer",
                transition: "background 0.15s",
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = "#fef2f2")}
              onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}
            >
              Reset All Budgets
            </button>
          </section>
        </div>

        {/* Footer */}
        <div
          style={{
            padding: "20px",
            background: "#f9fafb",
            borderTop: "1px solid #e5e7eb",
            display: "flex",
            flexDirection: "column",
            gap: 12,
          }}
        >
          <Button
            onClick={handleSave}
            disabled={isSaving}
            style={{
              width: "100%",
              minHeight: 44,
              borderRadius: 16,
              fontWeight: 700,
              fontSize: 15,
            }}
          >
            {isSaving ? "Saving…" : "Save Settings"}
          </Button>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              minHeight: 20,
            }}
          >
            <span style={{ fontSize: 13, color: "#6b7280" }}>{statusText}</span>
          </div>
        </div>
      </div>

      {/* Toast */}
      {toast.visible && (
        <div
          role="status"
          aria-live="polite"
          style={{
