// ─── Main Settings Component ──────────────────────────────────────────────────

interface SettingsFormProps {
  isOpen?: boolean;
  onClose?: () => void;
}

const SettingsForm: React.FC<SettingsFormProps> = ({
  isOpen = true,
  onClose = () => {},
}) => {
  const [settings, setSettings] = useState<UserSettings>(MOCK_SETTINGS);
  const [categories, setCategories] = useState<Category[]>(MOCK_CATEGORIES);
  const [budgetValue, setBudgetValue] = useState<number>(MOCK_SETTINGS.defaultMonthlyBudget);
  const [useSystemLocale, setUseSystemLocale] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [statusText, setStatusText] = useState("");
  const [toast, setToast] = useState<ToastState>({ message: "", visible: false, type: "success" });

  const showToast = useCallback((message: string, type: "success" | "error" = "success") => {
    setToast({ message, visible: true, type });
    setTimeout(() => setToast((t) => ({ ...t, visible: false })), 3000);
  }, []);

  // Keyboard close
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    if (isOpen) window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, onClose]);

  const handleCurrencyChange = async (currency: Currency) => {
    setSettings((prev) => ({ ...prev, currency }));
    try {
      // PUT /api/settings
      await Promise.resolve(); // mock API call
      showToast(`Currency changed to ${currency}`, "success");
    } catch {
      showToast("Failed to update currency", "error");
    }
  };

  const handleBudgetChange = (value: number) => {
    setBudgetValue(value);
    setSettings((prev) => ({ ...prev, defaultMonthlyBudget: value }));
  };

  const handleCategoryDelete = async (categoryId: string) => {
    try {
      // DELETE /api/categories/{id}
      await Promise.resolve(); // mock API call
      setCategories((prev) => prev.filter((c) => c.id !== categoryId));
      showToast("Category deleted", "success");
    } catch {
      showToast("Failed to delete category", "error");
    }
  };

  const handleCategoryAdd = () => {
    // Navigate to screen-002 (add category)
    showToast("Opening category editor…", "success");
  };

  const handleSave = async () => {
    setIsSaving(true);
    setStatusText("Saving…");
    try {
      // PUT /api/settings
      await new Promise((r) => setTimeout(r, 800)); // mock delay
      // PUT /api/budgets/{month}
      setStatusText("Settings saved ✓");
      showToast("Settings saved successfully!", "success");
      setTimeout(() => setStatusText(""), 3000);
    } catch {
      setStatusText("Failed to save");
      showToast("Failed to save settings", "error");
    } finally {
      setIsSaving(false);
    }
  };

  const handleResetBudgets = () => {
    if (window.confirm("Are you sure you want to reset all budgets? This cannot be undone.")) {
      setBudgetValue(0);
      setSettings((prev) => ({ ...prev, defaultMonthlyBudget: 0 }));
      showToast("All budgets reset", "success");
    }
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Scrim */}
      <div
        onClick={onClose}
        style={{
          position: "fixed",
          inset: 0,
          background: "rgba(0,0,0,0.5)",
          zIndex: 40,
        }}
        aria-hidden="true"
      />

      {/* Drawer Panel */}
      <div
        role="dialog"
        aria-modal="true"
        aria-label="Settings"
        style={{
          position: "fixed",
          top: 0,
          right: 0,
          bottom: 0,
          width: "100%",
          maxWidth: 420,
          background: "#ffffff",
          zIndex: 50,
          display: "flex",
          flexDirection: "column",
          boxShadow: "0 20px 60px rgba(0,0,0,0.2)",
          overflowY: "auto",
        }}
      >
        {/* Dialog Header */}
        <DialogHeader title="Settings" onClose={onClose} />

        {/* Scrollable Content */}
        <div
          style={{
            flex: 1,
            overflowY: "auto",
            padding: "0 20px",
          }}
        >
          {/* Currency Section */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3 style={{ fontSize: 16, fontWeight: 600, color: "#111827", margin: 0 }}>
                Currency
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: "4px 0 0" }}>
                Select your preferred display currency
              </p>
            </div>
            <CurrencySelector
              options={CURRENCY_OPTIONS}
              selectedCurrency={settings.currency}
              onSelect={handleCurrencyChange}
              label="Currency"
            />
          </section>

          <Separator />

          {/* Budget Section */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3 style={{ fontSize: 16, fontWeight: 600, color: "#111827", margin: 0 }}>
                Monthly Budget
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: "4px 0 0" }}>
                Set your default monthly spending limit
              </p>
            </div>
            <BudgetLimitInput
              value={budgetValue}
              onChange={handleBudgetChange}
              currency={settings.currency}
              label="Monthly Limit"
            />
          </section>

          <Separator />

          {/* Category Manager Section */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3 style={{ fontSize: 16, fontWeight: 600, color: "#111827", margin: 0 }}>
                Expense Categories
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: "4px 0 0" }}>
                Manage your expense categories
              </p>
            </div>
            <CategoryManager
              categories={categories}
              onDelete={handleCategoryDelete}
              onAdd={handleCategoryAdd}
              addLabel="Add category"
            />
          </section>

          <Separator />

          {/* Preferences Section */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3 style={{ fontSize: 16, fontWeight: 600, color: "#111827", margin: 0 }}>
                Preferences
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: "4px 0 0" }}>
                Customize your app experience
              </p>
            </div>
            <div
              style={{
                display: "flex",
                flexDirection: "row",
                alignItems: "center",
                justifyContent: "space-between",
                gap: 12,
                padding: "14px 16px",
                border: "1px solid #e5e7eb",
                borderRadius: 10,
                background: "#f9fafb",
              }}
            >
              <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
                <span style={{ fontSize: 14, fontWeight: 500, color: "#111827" }}>
                  Use system locale
                </span>
                <span style={{ fontSize: 12, color: "#6b7280" }}>
                  Format numbers and dates using device locale
                </span>
              </div>
              <Switch
                checked={useSystemLocale}
                onCheckedChange={setUseSystemLocale}
                aria-label="Toggle system locale"
              />
            </div>
          </section>

          <Separator />

          {/* Danger Zone */}
          <section style={{ padding: "20px 0 16px" }}>
            <div style={{ marginBottom: 12 }}>
              <h3 style={{ fontSize: 16, fontWeight: 600, color: "#ef4444", margin: 0 }}>
                Danger Zone
              </h3>
              <p style={{ fontSize: 13, color: "#6b7280", margin: "4px 0 0" }}>
                Irreversible actions — proceed with caution
              </p>
            </div>
            <button
              onClick={handleResetBudgets}
              style={{
                width: "100%",
                minHeight: 44,
                border: "1px solid #ef4444",
                borderRadius: 10,
                background: "transparent",
                color: "#ef4444",
                fontSize: 14,
                fontWeight: 500,
                cursor: "pointer",
                transition: "background 0.15s",
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = "#fef2f2")}
              onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}
            >
              Reset All Budgets
            </button>
          </section>
        </div>

        {/* Footer */}
        <div
          style={{
            padding: "20px",
            borderTop: "1px solid #e5e7eb",
            background: "#f9fafb",
            display: "flex",
            flexDirection: "column",
            gap: 12,
          }}
        >
          <Button
            onClick={handleSave}
            disabled={isSaving}
            style={{
              width: "100%",
              minHeight: 44,
              borderRadius: 16,
              fontWeight: 700,
              fontSize: 15,
            }}
          >
            {isSaving ? "Saving…" : "Save Settings"}
          </Button>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              height: 20,
            }}
          >
            <span style={{ fontSize: 12, color: "#6b7280" }}>{statusText}</span>
          </div>
        </div>
      </div>

      {/* Toast Notification */}
      {toast.visible && (
        <div
          role="alert"
          aria-live="polite"
          style={{
            position: "fixed",
            bottom: 80,
            left: "50%",
            transform: "translateX(-50%)",
            background: toast.type === "success" ? "#111827" : "#ef4444",
            color: "#ffffff",
            padding: "10px 20px",
            borderRadius: 10,
            fontSize: 14,
            fontWeight: 500,
            zIndex: 100,
            boxShadow: "0 4px 16px rgba(0,0,0,0.2)",
            whiteSpace: "nowrap",
            pointerEvents: "none",
          }}
        >
          {toast.message}
        </div>
      )}
    </>
  );
};

