import React, { useState } from "react";
import { Switch } from "@/components/ui/switch";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";

// ─── Types ────────────────────────────────────────────────────────────────────

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";
type EndDateMode = "NEVER" | "ON_DATE";
type PaymentMethod = "CASH" | "CREDIT" | "DEBIT" | "APPLE_PAY" | "BANK";
type Category =
  | "FOOD"
  | "TRANSPORT"
  | "SHOPPING"
  | "HEALTH"
  | "ENTERTAINMENT"
  | "UTILITIES";

// ─── Sub-components ───────────────────────────────────────────────────────────

interface FrequencyChipProps {
  label: string;
  value: Frequency;
  isSelected: boolean;
  onClick: (value: Frequency) => void;
}

const FrequencyChip: React.FC<FrequencyChipProps> = ({
  label,
  value,
  isSelected,
  onClick,
}) => (
  <button
    type="button"
    onClick={() => onClick(value)}
    aria-pressed={isSelected}
    style={{ minHeight: 36 }}
    className={[
      "px-4 py-1.5 rounded-full border text-sm font-medium transition-all duration-150 focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2",
      isSelected
        ? "bg-blue-100 border-blue-600 text-blue-600"
        : "bg-white border-gray-200 text-gray-700 hover:border-gray-300",
    ].join(" ")}
  >
    {label}
  </button>
);

interface FrequencyChipSelectorProps {
  value: Frequency;
  onChange: (value: Frequency) => void;
}

const FREQUENCY_OPTIONS: { value: Frequency; label: string }[] = [
  { value: "WEEKLY", label: "Weekly" },
  { value: "MONTHLY", label: "Monthly" },
  { value: "YEARLY", label: "Yearly" },
];

const FrequencyChipSelector: React.FC<FrequencyChipSelectorProps> = ({
  value,
  onChange,
}) => (
  <div className="flex flex-row gap-2 items-center flex-wrap">
    {FREQUENCY_OPTIONS.map((opt) => (
      <FrequencyChip
        key={opt.value}
        label={opt.label}
        value={opt.value}
        isSelected={value === opt.value}
        onClick={onChange}
      />
    ))}
  </div>
);

interface RadioOptionProps {
  label: string;
  value: string;
  isSelected: boolean;
  onSelect: () => void;
}

const RadioOption: React.FC<RadioOptionProps> = ({
  label,
  value,
  isSelected,
  onSelect,
}) => (
  <button
    type="button"
    role="radio"
    aria-checked={isSelected}
    onClick={onSelect}
    style={{ minHeight: 36 }}
    className="flex flex-row items-center gap-2 focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2 rounded"
  >
    <span
      className={[
        "w-[18px] h-[18px] rounded-full border-2 flex items-center justify-center transition-colors duration-150",
        isSelected ? "border-blue-600 bg-blue-600" : "border-gray-300 bg-white",
      ].join(" ")}
    >
      {isSelected && (
        <span className="w-2 h-2 rounded-full bg-white block" />
      )}
    </span>
    <span className="text-sm text-gray-700">{label}</span>
  </button>
);

interface DatePickerInputProps {
  value: string | undefined;
  onChange: (value: string) => void;
  isVisible: boolean;
  minDate?: string;
  placeholder?: string;
}

const DatePickerInput: React.FC<DatePickerInputProps> = ({
  value,
  onChange,
  isVisible,
  minDate,
  placeholder = "Select end date",
}) => {
  if (!isVisible) return null;
  return (
    <Input
      type="date"
      value={value ?? ""}
      min={minDate}
      placeholder={placeholder}
      aria-label="Recurrence end date"
      onChange={(e) => onChange(e.target.value)}
      className="border-gray-200 rounded-lg text-sm px-3 py-2 focus:border-blue-600 focus:ring-blue-600 w-48"
    />
  );
};

interface EndDateRowProps {
  endDateMode: EndDateMode;
  endDate: string | undefined;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
  startDate?: string;
}

const EndDateRow: React.FC<EndDateRowProps> = ({
  endDateMode,
  endDate,
  onEndDateModeChange,
  onEndDateChange,
  startDate,
}) => (
  <div className="flex flex-col gap-2.5">
    <span className="text-xs text-gray-500 font-medium">Ends</span>
    <div
      role="radiogroup"
      aria-label="End date options"
      className="flex flex-col gap-2"
    >
      <RadioOption
        label="Never"
        value="NEVER"
        isSelected={endDateMode === "NEVER"}
        onSelect={() => {
          onEndDateModeChange("NEVER");
          onEndDateChange(undefined);
        }}
      />
      <div className="flex flex-row items-center gap-3 flex-wrap">
        <RadioOption
          label="On date"
          value="ON_DATE"
          isSelected={endDateMode === "ON_DATE"}
          onSelect={() => onEndDateModeChange("ON_DATE")}
        />
        <DatePickerInput
          value={endDate}
          onChange={onEndDateChange}
          isVisible={endDateMode === "ON_DATE"}
          minDate={startDate}
          placeholder="Select end date"
        />
      </div>
    </div>
  </div>
);

interface RecurrenceConfigPanelProps {
  isVisible: boolean;
  frequency: Frequency;
  endDateMode: EndDateMode;
  endDate: string | undefined;
  startDate: string | undefined;
  onFrequencyChange: (value: Frequency) => void;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
}

const RecurrenceConfigPanel: React.FC<RecurrenceConfigPanelProps> = ({
  isVisible,
  frequency,
  endDateMode,
  endDate,
  startDate,
  onFrequencyChange,
  onEndDateModeChange,
  onEndDateChange,
}) => (
  <div
    aria-hidden={!isVisible}
    style={{
      overflow: "hidden",
      maxHeight: isVisible ? 400 : 0,
      opacity: isVisible ? 1 : 0,
      transition: "max-height 150ms ease-in-out, opacity 150ms ease-in-out",
    }}
  >
    {isVisible && (
      <div
        className="flex flex-col gap-4 px-4 py-4 rounded-[10px] border border-gray-200"
        style={{ background: "var(--surface-secondary, #F9FAFB)" }}
      >
        {/* Frequency */}
        <div className="flex flex-col gap-2">
          <span className="text-xs font-medium text-gray-500">Frequency</span>
          <FrequencyChipSelector value={frequency} onChange={onFrequencyChange} />
        </div>

        {/* Start Date */}
        <div className="flex flex-col gap-2">
          <Label htmlFor="recurrence-start-date" className="text-xs font-medium text-gray-500">
            Start Date
          </Label>
          <Input
            id="recurrence-start-date"
            type="date"
            value={startDate ?? ""}
            aria-label="Recurrence start date"
            readOnly
            className="border-gray-200 rounded-lg text-sm px-3 py-2 focus:border-blue-600 focus:ring-blue-600 w-48 bg-gray-50 cursor-default"
          />
        </div>

        {/* End Date */}
        <EndDateRow
          endDateMode={endDateMode}
          endDate={endDate}
          onEndDateModeChange={onEndDateModeChange}
          onEndDateChange={onEndDateChange}
          startDate={startDate}
        />
      </div>
    )}
  </div>
);

interface RecurrenceToggleRowProps {
  checked: boolean;
  onCheckedChange: (value: boolean) => void;
}

const RecurrenceToggleRow: React.FC<RecurrenceToggleRowProps> = ({
  checked,
  onCheckedChange,
}) => (
  <div className="flex flex-row items-center justify-between w-full">
    <span className="text-sm font-semibold text-gray-900">
      Make this recurring
    </span>
    <Switch
      checked={checked}
      onCheckedChange={onCheckedChange}
      aria-label="Make this expense recurring"
      className="data-[state=checked]:bg-blue-600 data-[state=unchecked]:bg-gray-200"
      style={{ width: 44, height: 24 }}
    />
  </div>
);

interface RecurrenceConfigSectionProps {
  isRecurring: boolean;
  frequency: Frequency;
  endDateMode: EndDateMode;
  endDate: string | undefined;
  startDate: string | undefined;
  onIsRecurringChange: (value: boolean) => void;
  onFrequencyChange: (value: Frequency) => void;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
  isEditingSeries?: boolean;
}

const RecurrenceConfigSection: React.FC<RecurrenceConfigSectionProps> = ({
  isRecurring,
  frequency,
  endDateMode,
  endDate,
  startDate,
  onIsRecurringChange,
  onFrequencyChange,
  onEndDateModeChange,
  onEndDateChange,
}) => (
  <div className="flex flex-col gap-4 w-full py-4">
    <RecurrenceToggleRow
      checked={isRecurring}
      onCheckedChange={onIsRecurringChange}
    />
    <RecurrenceConfigPanel
      isVisible={isRecurring}
      frequency={frequency}
      endDateMode={endDateMode}
      endDate={endDate}
      startDate={startDate}
      onFrequencyChange={onFrequencyChange}
      onEndDateModeChange={onEndDateModeChange}
      onEndDateChange={onEndDateChange}
    />
  </div>
);

