import { Repeat, Home, ShoppingCart, MapPin, Zap, Heart, Coffee, ChevronLeft, ChevronRight, Settings, X } from "lucide-react";

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";

interface Expense {
  id: string;
