}

interface RecurringBadgeProps {
  frequency: Frequency;
}

const RecurringBadge: React.FC<RecurringBadgeProps> = ({ frequency }) => {
  const label =
    frequency === "WEEKLY"
      ? "Weekly"
      : frequency === "MONTHLY"
      ? "Monthly"
      : "Yearly";

  return (
    <span
