import React, { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";

// ── Types ────────────────────────────────────────────────────────────────────

type BudgetStatus = "On Track" | "Heads Up" | "Over Budget";

interface MonthSummary {
  id: string;
  month: string;
  totalSpent: number;
  transactionCount: number;
  dailyAverage: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
  remainingAmount: number;
  updatedAt: string;
}

interface BudgetSummaryCardProps {
  monthSummary: MonthSummary;
  currency: string;
  animateOnMount?: boolean;
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function formatCurrency(amount: number, currency: string): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: currency || "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(amount);
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

// ── Sub-components ───────────────────────────────────────────────────────────

interface StatusBadgeProps {
  status: BudgetStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const variantMap: Record<
    BudgetStatus,
    { bg: string; text: string; icon: string }
  > = {
    "On Track": {
      bg: "bg-blue-100",
      text: "text-blue-700",
      icon: "✓",
    },
    "Heads Up": {
      bg: "bg-amber-100",
      text: "text-amber-700",
      icon: "⚠",
    },
    "Over Budget": {
      bg: "bg-red-100",
      text: "text-red-700",
      icon: "✕",
    },
  };

  const variant = variantMap[status];

  return (
    <span
      className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-medium ${variant.bg} ${variant.text}`}
    >
      <span aria-hidden="true">{variant.icon}</span>
      {status}
    </span>
  );
};

// ── Animated Counter ─────────────────────────────────────────────────────────

interface AnimatedAmountDisplayProps {
  amount: number;
  currency: string;
  label: string;
  animate: boolean;
}

const AnimatedAmountDisplay: React.FC<AnimatedAmountDisplayProps> = ({
  amount,
  currency,
  label,
  animate,
}) => {
  const [displayAmount, setDisplayAmount] = useState(animate ? 0 : amount);

  useEffect(() => {
    if (!animate) {
      setDisplayAmount(amount);
      return;
    }

    const duration = 800;
    const steps = 40;
    const stepDuration = duration / steps;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep += 1;
      const progress = currentStep / steps;
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayAmount(amount * eased);

      if (currentStep >= steps) {
        clearInterval(timer);
        setDisplayAmount(amount);
      }
    }, stepDuration);

    return () => clearInterval(timer);
  }, [amount, animate]);

  return (
    <div className="flex flex-col gap-0.5">
      <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">
        {label}
      </span>
      <span
        className="text-4xl font-bold text-gray-900 tabular-nums font-[Inter,sans-serif] leading-tight"
        aria-label={`${label}: ${formatCurrency(amount, currency)}`}
      >
        {formatCurrency(displayAmount, currency)}
      </span>
    </div>
  );
};

// ── Progress Bar ─────────────────────────────────────────────────────────────

interface BudgetProgressBarProps {
  spentAmount: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
}

const BudgetProgressBar: React.FC<BudgetProgressBarProps> = ({
  spentAmount,
  budgetLimit,
  budgetStatus,
}) => {
  const percentage =
    budgetLimit > 0
      ? clamp((spentAmount / budgetLimit) * 100, 0, 100)
      : 0;

  const fillColorMap: Record<BudgetStatus, string> = {
    "On Track": "bg-blue-600",
    "Heads Up": "bg-amber-500",
    "Over Budget": "bg-red-500",
  };

  const fillColor = fillColorMap[budgetStatus];

  return (
    <div className="w-full flex flex-col gap-1.5">
      <div
        className="w-full h-2 bg-gray-200 rounded-full overflow-hidden"
        role="progressbar"
        aria-valuenow={Math.round(percentage)}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={`Budget used: ${Math.round(percentage)}%`}
      >
        <div
          className={`h-full rounded-full transition-all duration-700 ease-out ${fillColor}`}
          style={{ width: `${percentage}%` }}
        />
      </div>
      <div className="flex justify-between text-xs text-gray-500 tabular-nums">
        <span>{Math.round(percentage)}% used</span>
        <span>of {formatCurrency(budgetLimit, "USD")}</span>
      </div>
    </div>
  );
};

// ── Remaining Display ────────────────────────────────────────────────────────

interface BudgetRemainingDisplayProps {
  remainingAmount: number;
  currency: string;
  isOverBudget: boolean;
}

const BudgetRemainingDisplay: React.FC<BudgetRemainingDisplayProps> = ({
  remainingAmount,
  currency,
  isOverBudget,
}) => {
  const textColor = isOverBudget ? "text-red-500" : "text-gray-600";
  const label = isOverBudget ? "over budget" : "remaining";
  const displayAmount = Math.abs(remainingAmount);

  return (
    <div className={`flex items-center gap-1.5 text-sm font-medium ${textColor} tabular-nums font-[Inter,sans-serif]`}>
      <span
        className={`inline-flex items-center justify-center w-4 h-4 rounded-full text-xs ${
          isOverBudget ? "bg-red-100 text-red-600" : "bg-green-100 text-green-600"
        }`}
        aria-hidden="true"
      >
        {isOverBudget ? "↑" : "↓"}
      </span>
      <span>
        <span className="font-semibold">
          {formatCurrency(displayAmount, currency)}
        </span>{" "}
        {label}
      </span>
    </div>
  );
};

// ── Stat Row ─────────────────────────────────────────────────────────────────

interface StatRowProps {
  label: string;
  value: string;
}

const StatRow: React.FC<StatRowProps> = ({ label, value }) => (
  <div className="flex items-center justify-between py-1">
    <span className="text-sm text-gray-500">{label}</span>
    <span className="text-sm font-semibold text-gray-900 tabular-nums">
      {value}
    </span>
  </div>
);

// ── Main Component ───────────────────────────────────────────────────────────

const BudgetSummaryCard: React.FC<BudgetSummaryCardProps> = ({
  monthSummary,
  currency,
  animateOnMount = true,
}) => {
  const {
    month,
    totalSpent,
    transactionCount,
    dailyAverage,
    budgetLimit,
    budgetStatus,
    remainingAmount,
  } = monthSummary;

  const isOverBudget = budgetStatus === "Over Budget";

  // Format month label e.g. "2026-03" → "March 2026"
  const monthLabel = (() => {
    try {
      const [year, mon] = month.split("-");
      const date = new Date(Number(year), Number(mon) - 1, 1);
      return date.toLocaleDateString("en-US", { month: "long", year: "numeric" });
    } catch {
      return month;
    }
  })();

  return (
    <Card
      className="w-full bg-white rounded-2xl shadow-md border-0"
      style={{ width: "360px" }}
    >
      <CardHeader className="pb-3 px-6 pt-6">
        <div className="flex items-center justify-between">
          <CardTitle className="text-base font-semibold text-gray-900">
            Monthly Budget
          </CardTitle>
          <StatusBadge status={budgetStatus} />
        </div>
        <p className="text-xs text-gray-400 mt-0.5">{monthLabel}</p>
      </CardHeader>

      <CardContent className="px-6 pb-6 flex flex-col gap-5">
        {/* Hero amount */}
        <AnimatedAmountDisplay
          amount={totalSpent}
          currency={currency}
          label="Total Spent"
          animate={animateOnMount}
        />

        {/* Progress bar */}
        <BudgetProgressBar
          spentAmount={totalSpent}
          budgetLimit={budgetLimit}
          budgetStatus={budgetStatus}
        />

        {/* Remaining */}
        <BudgetRemainingDisplay
          remainingAmount={remainingAmount}
          currency={currency}
          isOverBudget={isOverBudget}
        />

        {/* Divider */}
        <div className="border-t border-gray-100" />

        {/* Stats */}
        <div className="flex flex-col gap-0.5">
          <StatRow
            label="Daily Average"
            value={formatCurrency(dailyAverage, currency)}
          />
          <StatRow
            label="Transactions"
            value={transactionCount.toString()}
          />
          <StatRow
            label="Budget Limit"
            value={formatCurrency(budgetLimit, currency)}
          />
        </div>
      </CardContent>
    </Card>
  );
};

// ── Demo / Export ────────────────────────────────────────────────────────────

