    const duration = 800;
    const steps = 40;
    const increment = amount / steps;
    let current = 0;
    let step = 0;

    const timer = setInterval(() => {
      step++;
      current = Math.min(current + increment, amount);
      setDisplayAmount(current);
      if (step >= steps) {
        clearInterval(timer);
        setDisplayAmount(amount);
      }
    }, duration / steps);

    return () => clearInterval(timer);
