  currency: string;
  animateOnMount?: boolean;
}

// --- Helpers ---

function formatCurrency(amount: number, currency: string): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: currency || "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(amount);
}

function getSpendPercentage(totalSpent: number, budgetLimit: number): number {
  if (budgetLimit <= 0) return 0;
  return Math.min((totalSpent / budgetLimit) * 100, 100);
}

// --- Sub-components ---

interface StatusBadgeProps {
  status: BudgetStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const variantMap: Record<
    BudgetStatus,
    { bg: string; text: string; icon: string }
  > = {
    "On Track": {
      bg: "bg-blue-100",
      text: "text-blue-700",
      icon: "✓",
    },
    "Heads Up": {
      bg: "bg-amber-100",
      text: "text-amber-700",
      icon: "⚠",
    },
    "Over Budget": {
      bg: "bg-red-100",
      text: "text-red-700",
      icon: "✕",
    },
  };

  const variant = variantMap[status];

  return (
    <span
      className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-medium ${variant.bg} ${variant.text}`}
      aria-label={`Budget status: ${status}`}
    >
      <span aria-hidden="true">{variant.icon}</span>
      {status}
    </span>
  );
};

interface AnimatedCounterProps {
  targetValue: number;
  currency: string;
  animate: boolean;
  duration?: number;
}

const AnimatedCounter: React.FC<AnimatedCounterProps> = ({
  targetValue,
  currency,
  animate,
  duration = 1000,
}) => {
  const [displayValue, setDisplayValue] = useState(animate ? 0 : targetValue);

  useEffect(() => {
    if (!animate) {
      setDisplayValue(targetValue);
      return;
    }

    let startTime: number | null = null;
    const startValue = 0;

    const step = (timestamp: number) => {
      if (!startTime) startTime = timestamp;
      const elapsed = timestamp - startTime;
      const progress = Math.min(elapsed / duration, 1);
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayValue(startValue + (targetValue - startValue) * eased);

      if (progress < 1) {
        requestAnimationFrame(step);
      }
    };

    const rafId = requestAnimationFrame(step);
    return () => cancelAnimationFrame(rafId);
  }, [targetValue, animate, duration]);

  return (
    <span className="font-bold text-3xl text-gray-900 tabular-nums font-[Inter,sans-serif]">
      {formatCurrency(displayValue, currency)}
    </span>
  );
};

interface BudgetProgressBarProps {
  spentAmount: number;
  budgetLimit: number;
  spendPercentage: number;
  budgetStatus: BudgetStatus;
}

const BudgetProgressBar: React.FC<BudgetProgressBarProps> = ({
  spendPercentage,
  budgetStatus,
}) => {
  const fillColorMap: Record<BudgetStatus, string> = {
    "On Track": "bg-blue-600",
    "Heads Up": "bg-amber-500",
    "Over Budget": "bg-red-500",
  };

  const fillColor = fillColorMap[budgetStatus];

  return (
    <div className="w-full">
      <div
        className="w-full h-2 bg-gray-200 rounded-full overflow-hidden"
        role="progressbar"
        aria-valuenow={Math.round(spendPercentage)}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={`Budget used: ${Math.round(spendPercentage)}%`}
      >
        <div
          className={`h-full rounded-full transition-all duration-700 ease-out ${fillColor}`}
          style={{ width: `${spendPercentage}%` }}
        />
      </div>
      <div className="flex justify-between mt-1">
        <span className="text-xs text-gray-500 tabular-nums">
          {Math.round(spendPercentage)}% used
        </span>
        <span className="text-xs text-gray-500 tabular-nums">100%</span>
      </div>
    </div>
  );
};

interface BudgetRemainingDisplayProps {
  remainingAmount: number;
  currency: string;
  isOverBudget: boolean;
}

const BudgetRemainingDisplay: React.FC<BudgetRemainingDisplayProps> = ({
  remainingAmount,
  currency,
  isOverBudget,
}) => {
  const textColor = isOverBudget ? "text-red-500" : "text-gray-600";
  const label = isOverBudget ? "over budget" : "remaining";
  const displayAmount = Math.abs(remainingAmount);

  return (
    <div className="flex items-center gap-1">
