const StatCell: React.FC<StatCellProps> = ({
  label,
  value,
  trendDirection,
  trendPercentage,
  trendLabel,
  trendGoodDirection = "down",
}) => {
  const isGood =
    trendDirection === "same" ||
    trendDirection === trendGoodDirection;

  const trendColor =
    trendDirection === "same"
      ? "text-gray-500"
      : isGood
      ? "text-emerald-600"
      : "text-red-500";

  const TrendIcon =
    trendDirection === "up"
      ? TrendingUp
      : trendDirection === "down"
      ? TrendingDown
      : Minus;

  return (
    <div className="flex flex-col gap-1">
      <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">
        {label}
      </span>
      <span className="text-2xl font-bold text-gray-900 tabular-nums">
        {value}
      </span>
      {(trendPercentage !== undefined || trendLabel) && (
        <span className={`flex items-center gap-1 text-xs font-medium ${trendColor}`}>
          <TrendIcon className="w-3 h-3" />
          {trendLabel || `${trendPercentage}%`}
        </span>
