  monthSummary,
  comparison,
  currency,
}) => {
  const prev = comparison.previous;

  const spentTrend =
    !prev
      ? "same"
      : monthSummary.totalSpent > prev.totalSpent
      ? "up"
      : monthSummary.totalSpent < prev.totalSpent
      ? "down"
      : "same";

  const avgTrend =
    !prev
      ? "same"
      : monthSummary.dailyAverage > prev.dailyAverage
      ? "up"
      : monthSummary.dailyAverage < prev.dailyAverage
      ? "down"
      : "same";

  const countTrend =
    !prev
      ? "same"
      : monthSummary.transactionCount > prev.transactionCount
      ? "up"
      : monthSummary.transactionCount < prev.transactionCount
      ? "down"
      : "same";

  const spentPct = prev
    ? Math.abs(
        ((monthSummary.totalSpent - prev.totalSpent) / prev.totalSpent) * 100
      ).toFixed(1)
    : null;

  const avgPct = prev
    ? Math.abs(
        ((monthSummary.dailyAverage - prev.dailyAverage) /
          prev.dailyAverage) *
          100
      ).toFixed(1)
    : null;

  const countDiff = prev
    ? Math.abs(monthSummary.transactionCount - prev.transactionCount)
    : null;

  return (
    <Card className="bg-white shadow-sm">
