            trendGoodDirection="down"
          />
          <div className="pl-4">
            <StatCell
              label="Daily Average"
              value={formatCurrency(monthSummary.dailyAverage, currency)}
              trendDirection={avgTrend}
              trendLabel={avgPct ? `${avgTrend === "up" ? "↑" : "↓"} ${avgPct}% vs prev` : undefined}
              trendGoodDirection="down"
            />
          </div>
          <div className="pl-4">
            <StatCell
              label="Transactions"
              value={String(monthSummary.transactionCount)}
              trendDirection={countTrend}
              trendLabel={
                countDiff !== null
                  ? `${countTrend === "up" ? "↑" : "↓"} ${countDiff} vs prev`
                  : undefined
              }
              trendGoodDirection="down"
            />
          </div>
        </div>
