  const [tooltipX, setTooltipX] = useState(0);

  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);
  const chartHeight = 160;

  const getBarColor = (amount: number) =>
    amount > averageDaily * 1.5 ? "#ef4444" : "#2563eb";

  // Line chart path
  const svgWidth = 600;
  const svgHeight = chartHeight;
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * svgWidth,
    y: svgHeight - (d.totalAmount / maxAmount) * svgHeight * 0.9 - 8,
    ...d,
  }));

  const pathD = points
    .map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`)
    .join(" ");

  const fillD = `${pathD} L ${svgWidth} ${svgHeight} L 0 ${svgHeight} Z`;

  return (
    <Card className="bg-white shadow-sm">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <CardTitle className="text-base font-semibold text-gray-900">
            Daily Spending
          </CardTitle>
          <div className="flex rounded-lg overflow-hidden border border-gray-200">
            <button
              onClick={() => onModeChange("bar")}
              className={`flex items-center gap-1 px-3 py-1.5 text-xs font-medium transition-colors ${
                mode === "bar"
                  ? "bg-blue-600 text-white"
                  : "bg-gray-100 text-gray-700 hover:bg-gray-200"
              }`}
            >
              <BarChart2 className="w-3 h-3" />
              Bar
            </button>
            <button
              onClick={() => onModeChange("line")}
              className={`flex items-center gap-1 px-3 py-1.5 text-xs font-medium transition-colors ${
                mode === "line"
                  ? "bg-blue-600 text-white"
                  : "bg-gray-100 text-gray-700 hover:bg-gray-200"
              }`}
            >
              <LineChart className="w-3 h-3" />
              Line
            </button>
          </div>
        </div>
      </CardHeader>
      <CardContent className="px-6 pb-6">
        <div className="relative" style={{ height: chartHeight + 40 }}>
          {/* Tooltip */}
          {hoveredPoint && (
            <div
              className="absolute z-10 bg-white border border-gray-200 rounded-lg shadow-lg p-2 text-xs pointer-events-none"
              style={{
                left: Math.min(tooltipX, 260),
                top: -8,
                transform: "translateX(-50%)",
              }}
            >
              <div className="font-semibold text-gray-900">
                {formatDate(hoveredPoint.date)}
              </div>
              <div className="text-gray-700">
                {formatCurrency(hoveredPoint.totalAmount, currency)}
              </div>
              <div className="text-gray-500">
                {hoveredPoint.transactionCount} txns
              </div>
            </div>
          )}

          {mode === "bar" ? (
            <div className="flex items-end gap-0.5 h-40 relative">
              {/* Average line */}
              <div
                className="absolute left-0 right-0 border-t-2 border-dashed border-amber-500 pointer-events-none"
                style={{
                  bottom: `${(averageDaily / maxAmount) * 100 * 0.9}%`,
                }}
              />
              {data.map((d, i) => {
                const heightPct = (d.totalAmount / maxAmount) * 90;
                return (
                  <div
                    key={d.date}
                    className="flex-1 flex flex-col items-center group cursor-pointer"
                    onMouseEnter={(e) => {
                      setHoveredPoint(d);
                      const rect = (
                        e.currentTarget.closest(".relative") as HTMLElement
                      )?.getBoundingClientRect();
                      const elRect =
                        e.currentTarget.getBoundingClientRect();
                      setTooltipX(elRect.left - rect.left + elRect.width / 2);
                    }}
                    onMouseLeave={() => setHoveredPoint(null)}
                  >
                    <div
                      className="w-full rounded-t-sm transition-opacity group-hover:opacity-80"
                      style={{
                        height: `${heightPct}%`,
                        backgroundColor: getBarColor(d.totalAmount),
                        minHeight: 2,
                      }}
                    />
                  </div>
                );
              })}
            </div>
          ) : (
            <svg
              width="100%"
              height={chartHeight}
              viewBox={`0 0 ${svgWidth} ${svgHeight}`}
              preserveAspectRatio="none"
              className="overflow-visible"
            >
              {/* Average dashed line */}
              <line
                x1={0}
                x2={svgWidth}
                y1={svgHeight - (averageDaily / maxAmount) * svgHeight * 0.9 - 8}
                y2={svgHeight - (averageDaily / maxAmount) * svgHeight * 0.9 - 8}
                stroke="#f59e0b"
                strokeWidth={1.5}
                strokeDasharray="6,4"
              />
              {/* Fill */}
              <path d={fillD} fill="#dbeafe" opacity={0.5} />
              {/* Line */}
              <path
                d={pathD}
                fill="none"
                stroke="#2563eb"
                strokeWidth={2}
                strokeLinejoin="round"
              />
              {/* Points */}
              {points.map((p, i) => (
                <circle
                  key={i}
                  cx={p.x}
                  cy={p.y}
                  r={3}
                  fill="#2563eb"
                  className="cursor-pointer"
                  onMouseEnter={() => setHoveredPoint(data[i])}
                  onMouseLeave={() => setHoveredPoint(null)}
                />
              ))}
            </svg>
          )}

          {/* X-axis labels */}
          <div className="flex justify-between mt-1">
            <span className="text-xs text-gray-400">1</span>
            <span className="text-xs text-gray-400">
              {Math.floor(data.length / 2)}
            </span>
            <span className="text-xs text-gray-400">{data.length}</span>
          </div>
        </div>

        <div className="flex items-center gap-2 mt-2">
          <div className="w-6 border-t-2 border-dashed border-amber-500" />
          <span className="text-xs text-gray-500">
            Avg {formatCurrency(averageDaily, currency)} / day
          </span>
        </div>
      </CardContent>
    </Card>
  );
};

