const DailySpendingChart: React.FC<DailySpendingChartProps> = ({ data, mode, averageDaily, currency }) => {
  const [tooltip, setTooltip] = useState<{ point: DailySpending; x: number; y: number } | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const maxAmount = Math.max(...data.map((d) => d.totalAmount), averageDaily * 1.5);
  const chartHeight = 160;

  const getBarHeight = (amount: number) => Math.max((amount / maxAmount) * chartHeight, 2);

  const getLinePoints = () => {
    if (data.length === 0) return "";
    const width = 100 / data.length;
    return data
      .map((d, i) => {
        const x = (i + 0.5) * width;
        const y = 100 - (d.totalAmount / maxAmount) * 100;
        return `${x},${y}`;
      })
      .join(" ");
  };

  const avgY = 100 - (averageDaily / maxAmount) * 100;

  return (
    <div ref={containerRef} className="relative w-full" style={{ height: chartHeight + 24 }}>
      {mode === "bar" ? (
        <div className="flex items-end gap-0.5 w-full" style={{ height: chartHeight }}>
          {data.map((d, i) => {
            const isAboveAvg = d.totalAmount > averageDaily * 1.3;
            const barH = getBarHeight(d.totalAmount);
            return (
              <div
                key={i}
                className="flex-1 flex flex-col items-center justify-end cursor-pointer group"
                style={{ height: chartHeight }}
                onMouseEnter={(e) => {
                  const rect = containerRef.current?.getBoundingClientRect();
                  const el = e.currentTarget.getBoundingClientRect();
                  if (rect) {
                    setTooltip({ point: d, x: el.left - rect.left + el.width / 2, y: chartHeight - barH });
                  }
                }}
                onMouseLeave={() => setTooltip(null)}
              >
                <div
                  className="w-full rounded-t transition-opacity group-hover:opacity-80"
                  style={{
                    height: barH,
                    backgroundColor: isAboveAvg ? "#ef4444" : "#2563eb",
                  }}
                />
              </div>
            );
          })}
          {/* Average line overlay */}
          <div
            className="absolute left-0 right-0 border-t-2 border-dashed border-amber-500 pointer-events-none"
            style={{ bottom: (averageDaily / maxAmount) * chartHeight }}
          />
        </div>
      ) : (
        <div className="relative w-full" style={{ height: chartHeight }}>
          <svg viewBox="0 0 100 100" preserveAspectRatio="none" className="w-full h-full">
            <defs>
              <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor="#bfdbfe" stopOpacity="0.8" />
                <stop offset="100%" stopColor="#bfdbfe" stopOpacity="0" />
              </linearGradient>
            </defs>
            {/* Fill area */}
            <polygon
              points={`0,100 ${getLinePoints()} 100,100`}
              fill="url(#lineGrad)"
            />
            {/* Line */}
            <polyline
              points={getLinePoints()}
              fill="none"
              stroke="#2563eb"
              strokeWidth="0.8"
              vectorEffect="non-scaling-stroke"
            />
            {/* Average line */}
            <line x1="0" y1={avgY} x2="100" y2={avgY} stroke="#f59e0b" strokeWidth="0.6" strokeDasharray="2,1" vectorEffect="non-scaling-stroke" />
          </svg>
          {/* Hover targets */}
          <div className="absolute inset-0 flex">
            {data.map((d, i) => (
              <div
                key={i}
                className="flex-1 cursor-pointer"
                onMouseEnter={(e) => {
                  const rect = containerRef.current?.getBoundingClientRect();
                  const el = e.currentTarget.getBoundingClientRect();
                  if (rect) {
                    const yPos = chartHeight - (d.totalAmount / maxAmount) * chartHeight;
                    setTooltip({ point: d, x: el.left - rect.left + el.width / 2, y: yPos });
                  }
                }}
                onMouseLeave={() => setTooltip(null)}
              />
            ))}
          </div>
        </div>
      )}
      {/* X-axis labels */}
      <div className="flex w-full mt-1">
        {data.filter((_, i) => i % 5 === 0 || i === data.length - 1).map((d, i) => (
          <div key={i} className="flex-1 text-center text-xs text-gray-400">
            {new Date(d.date).getDate()}
          </div>
        ))}
      </div>
      {tooltip && (
        <ChartTooltip
          date={tooltip.point.date}
          amount={tooltip.point.totalAmount}
          transactionCount={tooltip.point.transactionCount}
          currency={currency}
          x={tooltip.x}
          y={tooltip.y}
        />
      )}
    </div>
  );
};

