// StatCell
interface StatCellProps {
  label: string;
  value: string;
  trendDirection: "up" | "down" | "same";
  trendLabel: string;
  trendGoodDirection?: "down" | "up";
}

const StatCell: React.FC<StatCellProps> = ({
  label,
  value,
  trendDirection,
  trendLabel,
  trendGoodDirection = "down",
}) => {
  const isGood =
    trendDirection === "same" ||
    trendDirection === trendGoodDirection;

  const trendColor = trendDirection === "same"
    ? "text-gray-500 bg-gray-100"
    : isGood
    ? "text-emerald-700 bg-emerald-100"
    : "text-red-700 bg-red-100";

  const arrow =
    trendDirection === "up" ? "↑" : trendDirection === "down" ? "↓" : "→";

  return (
    <div className="flex flex-col gap-1 flex-1 min-w-0">
      <span className="text-xs text-gray-500 font-medium uppercase tracking-wide">
        {label}
      </span>
      <span className="text-2xl font-bold text-gray-900 tabular-nums">
        {value}
      </span>
      <span
        className={`inline-flex items-center gap-0.5 text-xs font-semibold px-2 py-0.5 rounded-full w-fit ${trendColor}`}
      >
        {arrow} {trendLabel}
      </span>
    </div>
  );
};

// DailySpendingChart (bar)
interface DailySpendingChartProps {
  data: DailySpending[];
  averageDaily: number;
  currency: string;
  mode: "bar" | "line";
}

const DailySpendingChart: React.FC<DailySpendingChartProps> = ({
  data,
  averageDaily,
  currency,
  mode,
}) => {
  const [tooltip, setTooltip] = useState<{
    point: DailySpending;
    x: number;
  } | null>(null);

  const maxAmount = Math.max(...data.map((d) => d.totalAmount), averageDaily);
  const chartHeight = 160;

  if (mode === "bar") {
    return (
      <div className="relative">
        <div
          className="flex items-end gap-0.5 overflow-x-auto"
          style={{ height: chartHeight + 24 }}
          role="img"
          aria-label="Daily spending bar chart"
        >
          {data.map((point, i) => {
            const barH = Math.max(4, (point.totalAmount / maxAmount) * chartHeight);
            const isHigh = point.totalAmount > averageDaily * 1.3;
            const barColor = isHigh ? "#ef4444" : "#2563eb";
            const day = new Date(point.date + "T00:00:00").getDate();
            return (
              <div
                key={point.date}
                className="flex flex-col items-center flex-1 min-w-[8px] cursor-pointer group"
                onMouseEnter={(e) =>
                  setTooltip({ point, x: e.currentTarget.getBoundingClientRect().left })
                }
                onMouseLeave={() => setTooltip(null)}
              >
                <div
                  className="w-full rounded-t transition-opacity group-hover:opacity-80"
                  style={{
                    height: barH,
                    backgroundColor: barColor,
                    marginTop: chartHeight - barH,
                  }}
                />
                {(i === 0 || (i + 1) % 7 === 0) && (
                  <span className="text-[9px] text-gray-400 mt-1">{day}</span>
                )}
              </div>
            );
          })}
          {/* Average line overlay */}
          <div
            className="absolute left-0 right-0 border-t-2 border-dashed border-amber-500 pointer-events-none"
            style={{
              bottom: 24 + (averageDaily / maxAmount) * chartHeight,
            }}
          />
        </div>
        {tooltip && (
          <div className="absolute z-10 bg-white shadow-lg rounded-lg p-2 text-xs pointer-events-none border border-gray-100 -top-16 left-1/2 -translate-x-1/2">
            <div className="font-semibold text-gray-900">
              {new Date(tooltip.point.date + "T00:00:00").toLocaleDateString("en-US", {
                month: "short",
                day: "numeric",
              })}
            </div>
            <div className="text-gray-700">{formatCurrency(tooltip.point.totalAmount, currency)}</div>
            <div className="text-gray-500">{tooltip.point.transactionCount} txns</div>
          </div>
        )}
        <div className="flex items-center gap-1 mt-1">
          <div className="w-6 border-t-2 border-dashed border-amber-500" />
          <span className="text-xs text-gray-500">
            Avg {formatCurrency(averageDaily, currency)} / day
          </span>
        </div>
      </div>
    );
  }

  // Line mode
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * 100,
    y: 100 - (d.totalAmount / maxAmount) * 100,
    data: d,
  }));

  const pathD = points
    .map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`)
    .join(" ");

  const fillD =
    pathD +
    ` L ${points[points.length - 1].x} 100 L ${points[0].x} 100 Z`;

  return (
    <div className="relative">
      <svg
        viewBox="0 0 100 100"
        preserveAspectRatio="none"
        className="w-full"
        style={{ height: chartHeight }}
        role="img"
        aria-label="Daily spending line chart"
      >
        <defs>
          <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#dbeafe" stopOpacity="0.8" />
            <stop offset="100%" stopColor="#dbeafe" stopOpacity="0" />
          </linearGradient>
        </defs>
        <path d={fillD} fill="url(#lineGrad)" />
        <path d={pathD} fill="none" stroke="#2563eb" strokeWidth="1.5" vectorEffect="non-scaling-stroke" />
        <line
          x1="0"
          y1={100 - (averageDaily / maxAmount) * 100}
          x2="100"
          y2={100 - (averageDaily / maxAmount) * 100}
          stroke="#f59e0b"
          strokeWidth="1"
          strokeDasharray="3,2"
          vectorEffect="non-scaling-stroke"
        />
      </svg>
      <div className="flex items-center gap-1 mt-1">
        <div className="w-6 border-t-2 border-dashed border-amber-500" />
        <span className="text-xs text-gray-500">
          Avg {formatCurrency(averageDaily, currency)} / day
        </span>
      </div>
    </div>
  );
};

