interface BudgetLimitInputProps {
  value: number;
  onChange: (value: number) => void;
  currency: Currency;
  label: string;
}

const BudgetLimitInput: React.FC<BudgetLimitInputProps> = ({
  value,
  onChange,
  currency,
  label,
}) => {
  const [inputValue, setInputValue] = useState(value.toFixed(2));

  useEffect(() => {
    setInputValue(value.toFixed(2));
  }, [value]);

  const handleBlur = () => {
    const parsed = parseFloat(inputValue.replace(/,/g, ""));
    if (!isNaN(parsed) && parsed >= 0) {
      onChange(parsed);
      setInputValue(parsed.toFixed(2));
    } else {
      setInputValue(value.toFixed(2));
    }
  };

  return (
    <div className="space-y-1.5">
      <Label className="text-sm font-medium text-gray-700">{label}</Label>
      <div className="flex items-center border border-gray-200 rounded-md overflow-hidden focus-within:ring-2 focus-within:ring-blue-600">
        <div className="flex items-center justify-center px-3 py-2 bg-gray-50 border-r border-gray-200 min-w-[40px]">
          <span className="text-sm font-medium text-gray-600">
            {CURRENCY_SYMBOLS[currency]}
          </span>
        </div>
        <Input
          type="text"
          inputMode="decimal"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onBlur={handleBlur}
          placeholder="0.00"
          className="border-0 focus-visible:ring-0 focus-visible:ring-offset-0 text-gray-900 font-mono tabular-nums"
        />
      </div>
    </div>
  );
};

