// --- Toast / Status ---

interface StatusToastProps {
  message: string;
  type: "success" | "error" | "idle";
}

const StatusToast: React.FC<StatusToastProps> = ({ message, type }) => {
  if (type === "idle" || !message) return null;
  return (
    <div
      className={`flex items-center gap-2 text-sm px-3 py-2 rounded-md ${
        type === "success"
          ? "bg-green-50 text-green-700"
          : "bg-red-50 text-red-700"
      }`}
      role="status"
      aria-live="polite"
    >
      {type === "success" ? (
        <CheckCircle2 size={14} />
      ) : (
        <AlertTriangle size={14} />
      )}
      {message}
    </div>
  );
};

// --- Main Settings Form Component ---

interface SettingsDialogProps {
  isOpen: boolean;
  onClose: () => void;
  settings: UserSettings;
  categories: Category[];
  onSettingsChange: (settings: { currency?: string; defaultMonthlyBudget?: number }) => void;
  onCategoryDelete: (categoryId: string) => void;
  onCategoryAdd: () => void;
}

const SettingsDialog: React.FC<SettingsDialogProps> = ({
  isOpen,
  onClose,
  settings,
  categories,
  onSettingsChange,
  onCategoryDelete,
  onCategoryAdd,
}) => {
  const [currency, setCurrency] = useState<Currency>(settings.currency);
  const [budget, setBudget] = useState<number>(settings.defaultMonthlyBudget);
  const [useSystemLocale, setUseSystemLocale] = useState(false);
  const [status, setStatus] = useState<{ message: string; type: "success" | "error" | "idle" }>({
    message: "",
    type: "idle",
  });
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    setCurrency(settings.currency);
    setBudget(settings.defaultMonthlyBudget);
  }, [settings]);

  const showStatus = (message: string, type: "success" | "error") => {
    setStatus({ message, type });
    setTimeout(() => setStatus({ message: "", type: "idle" }), 3000);
  };

  const handleCurrencyChange = (newCurrency: Currency) => {
    setCurrency(newCurrency);
  };

  const handleBudgetChange = (newBudget: number) => {
    setBudget(newBudget);
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      // Simulate PUT /api/settings
      await new Promise((res) => setTimeout(res, 600));
      onSettingsChange({ currency, defaultMonthlyBudget: budget });
      showStatus("Settings saved successfully", "success");
    } catch {
      showStatus("Failed to save settings", "error");
    } finally {
      setIsSaving(false);
    }
  };

  const handleResetBudgets = async () => {
    if (!window.confirm("Are you sure you want to reset all budgets? This cannot be undone.")) return;
    try {
      await new Promise((res) => setTimeout(res, 400));
      showStatus("All budgets have been reset", "success");
    } catch {
      showStatus("Failed to reset budgets", "error");
    }
  };

  const handleKeyDown = useCallback(
    (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    },
    [onClose]
  );

  useEffect(() => {
    if (isOpen) {
      document.addEventListener("keydown", handleKeyDown);
    }
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, handleKeyDown]);

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-start justify-end"
      role="dialog"
      aria-modal="true"
      aria-label="Settings"
    >
      {/* Scrim */}
      <div
        className="absolute inset-0 bg-black/50"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Drawer Panel */}
      <div
        className="relative z-10 flex flex-col h-full w-full max-w-[420px] bg-white shadow-2xl overflow-hidden"
        style={{ maxWidth: 420 }}
      >
        {/* Drawer Header */}
        <div className="px-6 pt-6 pb-0 flex-shrink-0">
          <DialogHeader title="Settings" onClose={onClose} />
        </div>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto px-6 py-4 space-y-6">
          {/* Currency Section */}
          <section aria-labelledby="currency-section-title">
            <div className="mb-3">
              <h3
                id="currency-section-title"
                className="text-sm font-semibold text-gray-900"
              >
                Currency
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                Select your preferred display currency
              </p>
            </div>
            <CurrencySelector
              options={CURRENCY_OPTIONS}
              selectedCurrency={currency}
              onSelect={handleCurrencyChange}
              label="Currency"
            />
          </section>

          <Separator />

          {/* Budget Section */}
          <section aria-labelledby="budget-section-title">
            <div className="mb-3">
              <h3
                id="budget-section-title"
                className="text-sm font-semibold text-gray-900"
              >
                Monthly Budget
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                Set your default monthly spending limit
              </p>
            </div>
            <BudgetLimitInput
              value={budget}
              onChange={handleBudgetChange}
              currency={currency}
              label="Monthly Limit"
            />
          </section>

          <Separator />

          {/* Categories Section */}
          <section aria-labelledby="categories-section-title">
            <div className="mb-3">
              <h3
                id="categories-section-title"
                className="text-sm font-semibold text-gray-900"
              >
                Expense Categories
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                Manage your expense categories
              </p>
            </div>
            <CategoryManager
              categories={categories}
              onDelete={onCategoryDelete}
              onAdd={onCategoryAdd}
              addLabel="Add category"
            />
          </section>

          <Separator />

          {/* Preferences Section */}
          <section aria-labelledby="preferences-section-title">
            <div className="mb-3">
              <h3
                id="preferences-section-title"
                className="text-sm font-semibold text-gray-900"
              >
                Preferences
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                Customize your app experience
              </p>
            </div>
            <div className="flex items-center justify-between py-2">
              <div>
                <p className="text-sm font-medium text-gray-900">
                  Use system locale
                </p>
                <p className="text-xs text-gray-500">
                  Format numbers and dates using device locale
                </p>
              </div>
              <Switch
                checked={useSystemLocale}
                onCheckedChange={setUseSystemLocale}
                aria-label="Use system locale"
              />
            </div>
          </section>

          <Separator />

          {/* Danger Zone */}
          <section aria-labelledby="danger-zone-title">
            <div className="mb-3">
              <h3
                id="danger-zone-title"
                className="text-sm font-semibold text-red-600"
              >
                Danger Zone
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                Irreversible actions — proceed with caution
              </p>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={handleResetBudgets}
              className="border-red-200 text-red-600 hover:bg-red-50 hover:text-red-700 hover:border-red-300"
            >
              <AlertTriangle size={14} className="mr-1.5" />
              Reset All Budgets
            </Button>
          </section>
        </div>

        {/* Footer */}
        <div className="flex-shrink-0 px-6 py-4 border-t border-gray-100 bg-white space-y-3">
          <StatusToast message={status.message} type={status.type} />
          <div className="flex items-center gap-3">
            <Button
              onClick={handleSave}
              disabled={isSaving}
              className="flex-1 bg-blue-600 hover:bg-blue-700 text-white focus:ring-2 focus:ring-blue-600"
            >
              {isSaving ? "Saving…" : "Save Settings"}
            </Button>
            <Button
              variant="outline"
              onClick={onClose}
              className="border-gray-200 text-gray-700 hover:bg-gray-50"
            >
              Cancel
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

