const BudgetLimitInput: React.FC<BudgetLimitInputProps> = ({
  value,
  onChange,
  currency,
  label,
}) => {
  const [raw, setRaw] = useState(value.toFixed(2));

  useEffect(() => {
    setRaw(value.toFixed(2));
  }, [value]);

  const handleBlur = () => {
    const parsed = parseFloat(raw.replace(/,/g, ""));
    if (!isNaN(parsed) && parsed >= 0) {
      onChange(parsed);
      setRaw(parsed.toFixed(2));
    } else {
      setRaw(value.toFixed(2));
    }
  };

  return (
    <div className="space-y-1.5">
      <Label className="text-sm font-medium text-gray-700">{label}</Label>
      <div className="flex items-center border border-gray-200 rounded-lg overflow-hidden focus-within:ring-2 focus-within:ring-blue-600">
