  onSettingsChange: (settings: { currency?: string; defaultMonthlyBudget?: number }) => void;
  onCategoryDelete: (categoryId: string) => void;
  onCategoryAdd: () => void;
}

const SettingsDialog: React.FC<SettingsDialogProps> = ({
  isOpen,
  onClose,
  settings,
  categories,
  onSettingsChange,
  onCategoryDelete,
  onCategoryAdd,
}) => {
  const [localCurrency, setLocalCurrency] = useState<Currency>(settings.currency);
  const [localBudget, setLocalBudget] = useState<number>(settings.defaultMonthlyBudget);
  const [useSystemLocale, setUseSystemLocale] = useState(false);
  const [statusText, setStatusText] = useState("");
  const [toast, setToast] = useState<{ message: string; type: "success" | "info"; visible: boolean }>({
    message: "",
    type: "success",
    visible: false,
  });
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  useEffect(() => {
    setLocalCurrency(settings.currency);
    setLocalBudget(settings.defaultMonthlyBudget);
  }, [settings]);

  const showToast = useCallback((message: string, type: "success" | "info" = "success") => {
    setToast({ message, type, visible: true });
    setTimeout(() => setToast((t) => ({ ...t, visible: false })), 3000);
  }, []);

  const handleCurrencyChange = (currency: Currency) => {
    setLocalCurrency(currency);
    showToast(`Currency changed to ${CURRENCY_LABELS[currency]}`, "info");
  };

  const handleSave = () => {
    onSettingsChange({ currency: localCurrency, defaultMonthlyBudget: localBudget });
    setStatusText("Settings saved successfully.");
    showToast("Settings saved!", "success");
    setTimeout(() => setStatusText(""), 4000);
    onClose();
  };

  const handleResetBudgets = () => {
    if (!showResetConfirm) {
      setShowResetConfirm(true);
      setTimeout(() => setShowResetConfirm(false), 4000);
      return;
    }
    setShowResetConfirm(false);
    showToast("All budgets have been reset.", "info");
  };

  // Close on Escape
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    document.addEventListener("keydown", handler);
    return () => document.removeEventListener("keydown", handler);
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <>
      {/* Scrim */}
      <div
        className="fixed inset-0 z-40 bg-black/50"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Drawer panel */}
      <div
