);

interface BudgetLimitInputProps {
  value: number;
  onChange: (value: number) => void;
  currency: Currency;
  label: string;
}

const BudgetLimitInput: React.FC<BudgetLimitInputProps> = ({
  value,
  onChange,
  currency,
  label,
}) => {
  const [inputValue, setInputValue] = useState(value.toFixed(2));

  useEffect(() => {
    setInputValue(value.toFixed(2));
  }, [value]);

  const handleBlur = () => {
    const parsed = parseFloat(inputValue.replace(/,/g, ""));
    if (!isNaN(parsed) && parsed >= 0) {
      onChange(parsed);
      setInputValue(parsed.toFixed(2));
    } else {
      setInputValue(value.toFixed(2));
    }
  };

  return (
    <div className="space-y-1.5">
      <Label className="text-sm font-medium text-gray-700">{label}</Label>
      <div className="flex items-center border border-gray-200 rounded-lg overflow-hidden focus-within:ring-2 focus-within:ring-blue-600 focus-within:border-transparent">
        <div className="flex items-center justify-center px-3 py-2 bg-gray-50 border-r border-gray-200 min-w-[44px]">
          <span className="text-gray-500 font-medium text-sm">
            {CURRENCY_SYMBOLS[currency]}
          </span>
        </div>
        <input
          type="text"
          inputMode="decimal"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onBlur={handleBlur}
          placeholder="0.00"
          className="flex-1 px-3 py-2 text-gray-900 font-mono tabular-nums text-sm bg-white outline-none"
          aria-label={label}
        />
      </div>
    </div>
  );
};

interface CategoryManagerRowProps {
  category: Category;
  onDelete: (categoryId: string) => void;
}

const CategoryManagerRow: React.FC<CategoryManagerRowProps> = ({
  category,
  onDelete,
}) => {
  const isDeleteDisabled = category.isDefault;

  return (
    <div className="flex items-center justify-between min-h-[36px] py-1.5 group">
      <div className="flex items-center gap-3">
        <span
          className="w-3 h-3 rounded-full flex-shrink-0"
          style={{ backgroundColor: category.color }}
          aria-hidden="true"
        />
        <span className="text-sm text-gray-900">{category.icon}</span>
        <span className="text-sm text-gray-900">{category.name}</span>
        {category.isDefault && (
          <Badge
            variant="secondary"
            className="text-xs px-1.5 py-0 h-4 bg-gray-100 text-gray-500 font-normal"
          >
            default
          </Badge>
        )}
      </div>
      <button
        onClick={() => !isDeleteDisabled && onDelete(category.id)}
        disabled={isDeleteDisabled}
        aria-label={
          isDeleteDisabled
            ? `Cannot delete default category ${category.name}`
            : `Delete category ${category.name}`
        }
        className={`p-1.5 rounded-md transition-colors focus:outline-none focus:ring-2 focus:ring-blue-600 ${
          isDeleteDisabled
            ? "text-gray-300 cursor-not-allowed"
            : "text-red-400 hover:text-red-500 hover:bg-red-50 opacity-0 group-hover:opacity-100"
        }`}
      >
        <Trash2 className="w-4 h-4" />
      </button>
    </div>
  );
};

interface CategoryManagerProps {
  categories: Category[];
  onDelete: (categoryId: string) => void;
  onAdd: () => void;
  addLabel: string;
}

const CategoryManager: React.FC<CategoryManagerProps> = ({
  categories,
  onDelete,
  onAdd,
  addLabel,
}) => (
  <div className="space-y-1">
    <div className="divide-y divide-gray-50">
