// ─── Main Settings Form ───────────────────────────────────────────────────────

const SettingsForm: React.FC<SettingsFormProps> = ({
  isOpen = true,
  onClose,
  onCategoryAdd,
}) => {
  const [settings, setSettings] = useState<UserSettings>(INITIAL_SETTINGS);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [pendingCurrency, setPendingCurrency] = useState<Currency>(INITIAL_SETTINGS.currency);
  const [pendingBudget, setPendingBudget] = useState<number>(INITIAL_SETTINGS.defaultMonthlyBudget);
  const [useSystemLocale, setUseSystemLocale] = useState(false);
  const [statusMessage, setStatusMessage] = useState("");
  const [statusType, setStatusType] = useState<"success" | "error" | "idle">("idle");
  const [isSaving, setIsSaving] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  const currentMonth = new Date().toISOString().slice(0, 7);

  const showStatus = (message: string, type: "success" | "error") => {
    setStatusMessage(message);
    setStatusType(type);
    setTimeout(() => {
      setStatusMessage("");
      setStatusType("idle");
    }, 3000);
  };

  const handleClose = useCallback(() => {
    onClose?.();
  }, [onClose]);

  // Escape key handler
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape" && isOpen) {
        handleClose();
      }
    };
    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, handleClose]);

  const handleCurrencyChange = (currency: Currency) => {
    setPendingCurrency(currency);
  };

  const handleBudgetChange = (value: number) => {
    setPendingBudget(value);
  };

  const handleCategoryDelete = async (categoryId: string) => {
    const category = categories.find((c) => c.id === categoryId);
    if (!category || category.isDefault) return;

    try {
      // Simulate DELETE /api/categories/{id}
      // await fetch(`/api/categories/${categoryId}`, { method: 'DELETE' });
      setCategories((prev) => prev.filter((c) => c.id !== categoryId));
      showStatus(`Category "${category.name}" deleted.`, "success");
    } catch {
      showStatus("Failed to delete category.", "error");
    }
  };

  const handleCategoryAdd = () => {
    onCategoryAdd?.();
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      // Simulate PUT /api/settings
      // await fetch('/api/settings', { method: 'PUT', body: JSON.stringify({ currency: pendingCurrency, defaultMonthlyBudget: pendingBudget }) });
      await new Promise((r) => setTimeout(r, 600));

      // Simulate PUT /api/budgets/{month}
      // await fetch(`/api/budgets/${currentMonth}`, { method: 'PUT', body: JSON.stringify({ monthlyLimit: pendingBudget, currency: pendingCurrency }) });

      const currencyChanged = pendingCurrency !== settings.currency;

      setSettings((prev) => ({
        ...prev,
        currency: pendingCurrency,
        defaultMonthlyBudget: pendingBudget,
        updatedAt: new Date().toISOString(),
      }));

      if (currencyChanged) {
        showStatus(`Currency updated to ${pendingCurrency}.`, "success");
      } else {
        showStatus("Settings saved successfully.", "success");
      }
    } catch {
      showStatus("Failed to save settings.", "error");
    } finally {
      setIsSaving(false);
    }
  };

  const handleResetBudgets = async () => {
    if (!showResetConfirm) {
      setShowResetConfirm(true);
      setTimeout(() => setShowResetConfirm(false), 3000);
      return;
    }
    try {
      // Simulate reset
      await new Promise((r) => setTimeout(r, 400));
      setPendingBudget(0);
      setShowResetConfirm(false);
      showStatus("All budgets have been reset.", "success");
    } catch {
      showStatus("Failed to reset budgets.", "error");
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex">
      {/* Scrim */}
      <div
        className="absolute inset-0 bg-black/50"
        onClick={handleClose}
        aria-hidden="true"
      />

      {/* Drawer Panel */}
      <div
        className="relative ml-auto h-full w-full max-w-[420px] bg-white shadow-2xl flex flex-col"
        role="dialog"
        aria-modal="true"
        aria-label="Settings"
      >
        {/* Drawer Header */}
        <div className="px-6 pt-6 pb-0 flex-shrink-0">
          <DialogHeader title="Settings" onClose={handleClose} />
        </div>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto px-6 py-4 space-y-0">

          {/* Currency Section */}
          <section className="py-4" aria-labelledby="currency-section-title">
            <div className="mb-3">
              <h3
                id="currency-section-title"
                className="text-sm font-semibold text-gray-900"
              >
                Currency
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                Select your preferred display currency
              </p>
            </div>
            <CurrencySelector
              options={CURRENCY_OPTIONS}
              selectedCurrency={pendingCurrency}
              onSelect={handleCurrencyChange}
              label="Currency"
            />
          </section>

          <Separator className="bg-gray-100" />

          {/* Budget Section */}
          <section className="py-4" aria-labelledby="budget-section-title">
            <div className="mb-3">
              <h3
                id="budget-section-title"
                className="text-sm font-semibold text-gray-900"
              >
                Monthly Budget
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                Set your default monthly spending limit
              </p>
            </div>
            <BudgetLimitInput
              value={pendingBudget}
              onChange={handleBudgetChange}
              currency={pendingCurrency}
              label="Monthly Limit"
            />
          </section>

          <Separator className="bg-gray-100" />

          {/* Categories Section */}
          <section className="py-4" aria-labelledby="categories-section-title">
            <div className="mb-3">
              <h3
                id="categories-section-title"
                className="text-sm font-semibold text-gray-900"
              >
                Expense Categories
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                Manage your spending categories
              </p>
            </div>
            <CategoryManager
              categories={categories}
              onDelete={handleCategoryDelete}
              onAdd={handleCategoryAdd}
              addLabel="Add category"
            />
          </section>

