// ── Types ──────────────────────────────────────────────────────────────────────

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";
type TemplateStatus = "ACTIVE" | "PAUSED" | "CANCELLED";

interface RecurringTemplateItem {
  templateId: string;
  merchantName: string;
  amount: number;
  nextOccurrenceDate: string;
  frequency: Frequency;
  categoryId: string;
  status: TemplateStatus;
  categoryColor: string;
