import React, { useState } from "react";
import { Switch } from "@/components/ui/switch";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";

// ─── Types ────────────────────────────────────────────────────────────────────

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";
type EndDateMode = "NEVER" | "ON_DATE";
type PaymentMethod = "CASH" | "CREDIT_CARD" | "DEBIT_CARD" | "APPLE_PAY" | "BANK_TRANSFER";
type CategoryId = "food" | "transport" | "shopping" | "health" | "entertainment" | "utilities";

interface RecurringTemplateData {
  frequency: Frequency;
  startDate: string;
  endDate: string | undefined;
}

interface ExpenseFormData {
  amount: string;
  categoryId: CategoryId | null;
  date: string;
  paymentMethod: PaymentMethod | null;
  note: string;
  isRecurring: boolean;
  recurringTemplate: RecurringTemplateData;
}

// ─── FrequencyChip ────────────────────────────────────────────────────────────

interface FrequencyChipProps {
  label: string;
  value: Frequency;
  isSelected: boolean;
  onClick: (value: Frequency) => void;
}

const FrequencyChip: React.FC<FrequencyChipProps> = ({ label, value, isSelected, onClick }) => {
  return (
    <button
      type="button"
      onClick={() => onClick(value)}
      style={{ minHeight: "36px" }}
      className={[
        "px-3 py-1.5 rounded-full border text-sm font-medium transition-all duration-150 focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2",
        isSelected
          ? "bg-blue-100 border-blue-600 text-blue-600"
          : "bg-white border-gray-200 text-gray-700 hover:border-gray-300",
      ].join(" ")}
    >
      {label}
    </button>
  );
};

// ─── FrequencyChipSelector ────────────────────────────────────────────────────

interface FrequencyChipSelectorProps {
  value: Frequency;
  onChange: (value: Frequency) => void;
}

const FREQUENCY_OPTIONS: { value: Frequency; label: string }[] = [
  { value: "WEEKLY", label: "Weekly" },
  { value: "MONTHLY", label: "Monthly" },
  { value: "YEARLY", label: "Yearly" },
];

const FrequencyChipSelector: React.FC<FrequencyChipSelectorProps> = ({ value, onChange }) => {
  return (
    <div className="flex gap-2 flex-wrap">
      {FREQUENCY_OPTIONS.map((opt) => (
        <FrequencyChip
          key={opt.value}
          label={opt.label}
          value={opt.value}
          isSelected={value === opt.value}
          onClick={onChange}
        />
      ))}
    </div>
  );
};

// ─── RadioOption ──────────────────────────────────────────────────────────────

interface RadioOptionProps {
  label: string;
  value: string;
  isSelected: boolean;
  onSelect: () => void;
}

const RadioOption: React.FC<RadioOptionProps> = ({ label, value, isSelected, onSelect }) => {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={isSelected}
      onClick={onSelect}
      style={{ minHeight: "36px" }}
      className="flex items-center gap-2 focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2 rounded"
    >
      <div
        className={[
          "w-4 h-4 rounded-full border-2 flex items-center justify-center transition-colors duration-150",
          isSelected ? "border-blue-600" : "border-gray-300",
        ].join(" ")}
      >
        {isSelected && <div className="w-2 h-2 rounded-full bg-blue-600" />}
      </div>
      <span className="text-sm text-gray-700">{label}</span>
    </button>
  );
};

// ─── DatePickerInput ──────────────────────────────────────────────────────────

interface DatePickerInputProps {
  value: string | undefined;
  onChange: (value: string) => void;
  isVisible: boolean;
  minDate?: string;
  placeholder?: string;
}

const DatePickerInput: React.FC<DatePickerInputProps> = ({
  value,
  onChange,
  isVisible,
  minDate,
  placeholder = "Select end date",
}) => {
  if (!isVisible) return null;
  return (
    <Input
      type="date"
      value={value ?? ""}
      min={minDate}
      placeholder={placeholder}
      onChange={(e) => onChange(e.target.value)}
      className="mt-2 border-gray-200 rounded-md text-sm focus-visible:ring-blue-600 focus-visible:border-blue-600 p-3"
    />
  );
};

// ─── EndDateRow ───────────────────────────────────────────────────────────────

interface EndDateRowProps {
  endDateMode: EndDateMode;
  endDate: string | undefined;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
  minDate?: string;
}

const EndDateRow: React.FC<EndDateRowProps> = ({
  endDateMode,
  endDate,
  onEndDateModeChange,
  onEndDateChange,
  minDate,
}) => {
  return (
    <div className="flex flex-col gap-2">
      <span className="text-sm text-gray-500 font-medium">Ends</span>
      <div className="flex flex-col gap-1">
        <RadioOption
          label="Never"
          value="NEVER"
          isSelected={endDateMode === "NEVER"}
          onSelect={() => {
            onEndDateModeChange("NEVER");
            onEndDateChange(undefined);
          }}
        />
        <div className="flex flex-col">
          <RadioOption
            label="On date"
            value="ON_DATE"
            isSelected={endDateMode === "ON_DATE"}
            onSelect={() => onEndDateModeChange("ON_DATE")}
          />
          <DatePickerInput
            value={endDate}
            onChange={onEndDateChange}
            isVisible={endDateMode === "ON_DATE"}
            minDate={minDate}
            placeholder="Select end date"
          />
        </div>
      </div>
    </div>
  );
};

// ─── RecurrenceConfigPanel ────────────────────────────────────────────────────

interface RecurrenceConfigPanelProps {
  isVisible: boolean;
  frequency: Frequency;
  endDateMode: EndDateMode;
  endDate: string | undefined;
  startDate: string;
  onFrequencyChange: (value: Frequency) => void;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
}

const RecurrenceConfigPanel: React.FC<RecurrenceConfigPanelProps> = ({
  isVisible,
  frequency,
  endDateMode,
  endDate,
  startDate,
  onFrequencyChange,
  onEndDateModeChange,
  onEndDateChange,
}) => {
  return (
    <div
      className={[
        "overflow-hidden transition-all duration-150 ease-in-out",
