const AddExpensePage: React.FC = () => {
  const today = new Date().toISOString().split("T")[0];

  const [form, setForm] = useState<ExpenseFormData>({
    amount: "",
    categoryId: null,
    date: today,
    paymentMethod: null,
    note: "",
    isRecurring: false,
    recurringTemplate: {
      frequency: "MONTHLY",
      startDate: today,
      endDate: undefined,
    },
  });

  const [endDateMode, setEndDateMode] = useState<EndDateMode>("NEVER");
  const [showNewCategory, setShowNewCategory] = useState(false);
  const [newCatName, setNewCatName] = useState("");
  const [noteValue, setNoteValue] = useState("");
  const NOTE_MAX = 140;

  // Handlers
  const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) =>
    setForm((f) => ({ ...f, amount: e.target.value }));

  const handleCategoryClick = (value: CategoryId) =>
    setForm((f) => ({ ...f, categoryId: value }));

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) =>
    setForm((f) => ({
      ...f,
      date: e.target.value,
      recurringTemplate: { ...f.recurringTemplate, startDate: e.target.value },
    }));

  const handlePaymentMethodClick = (value: PaymentMethod) =>
    setForm((f) => ({ ...f, paymentMethod: value }));

  const handleNoteChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value.slice(0, NOTE_MAX);
    setNoteValue(val);
    setForm((f) => ({ ...f, note: val }));
  };

  const handleIsRecurringChange = (value: boolean) =>
    setForm((f) => ({ ...f, isRecurring: value }));

  const handleFrequencyChange = (value: Frequency) =>
    setForm((f) => ({
      ...f,
      recurringTemplate: { ...f.recurringTemplate, frequency: value },
    }));

  const handleEndDateModeChange = (value: EndDateMode) => {
    setEndDateMode(value);
    if (value === "NEVER") {
      setForm((f) => ({
        ...f,
        recurringTemplate: { ...f.recurringTemplate, endDate: undefined },
      }));
    }
  };

  const handleEndDateChange = (value: string | undefined) =>
    setForm((f) => ({
      ...f,
      recurringTemplate: { ...f.recurringTemplate, endDate: value },
    }));

  const handleQuickAdd = (amount: string, category: CategoryId) => {
    setForm((f) => ({ ...f, amount, categoryId: category }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (form.isRecurring) {
        await fetch("/api/recurring-templates", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            amount: parseFloat(form.amount),
            categoryId: form.categoryId,
            paymentMethod: form.paymentMethod,
            note: form.note,
            frequency: form.recurringTemplate.frequency,
            startDate: form.recurringTemplate.startDate,
            endDate: form.recurringTemplate.endDate ?? null,
          }),
        });
      } else {
        await fetch("/api/expenses", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            amount: parseFloat(form.amount),
            categoryId: form.categoryId,
            date: form.date,
            paymentMethod: form.paymentMethod,
            note: form.note,
          }),
        });
      }
      // Navigate to dashboard (screen-001)
      window.location.href = "/";
    } catch (err) {
      console.error("Failed to save expense", err);
    }
  };

  const categories: { value: CategoryId; label: string }[] = [
    { value: "food", label: "🍔 Food" },
    { value: "transport", label: "🚗 Transport" },
    { value: "shopping", label: "🛍️ Shopping" },
    { value: "health", label: "💊 Health" },
    { value: "entertainment", label: "🎬 Entertainment" },
    { value: "utilities", label: "💡 Utilities" },
  ];

  const paymentMethods: { value: PaymentMethod; label: string }[] = [
    { value: "CASH", label: "💵 Cash" },
    { value: "CREDIT_CARD", label: "💳 Credit Card" },
    { value: "DEBIT_CARD", label: "🏦 Debit Card" },
    { value: "APPLE_PAY", label: "📱 Apple Pay" },
    { value: "BANK_TRANSFER", label: "🏛️ Bank Transfer" },
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Top Bar */}
      <header className="flex items-center justify-between px-4 py-3 bg-white border-b border-gray-100 sticky top-0 z-10">
        <Button
          variant="ghost"
          size="sm"
          onClick={() => (window.location.href = "/")}
          className="text-gray-600"
        >
          ← Back
        </Button>
        <h1 className="text-base font-semibold text-gray-900">Add Expense</h1>
        <div className="flex gap-1">
          <Button variant="ghost" size="sm" className="text-gray-600">
            +
          </Button>
          <Button variant="ghost" size="sm" className="text-gray-600">
            ⚙
          </Button>
        </div>
      </header>

      {/* Page Body */}
      <main className="flex-1 flex justify-center px-4 py-6 pb-24">
        <div className="w-full max-w-lg flex flex-col gap-6">
          {/* Quick Add Section */}
          <section className="flex flex-col gap-2">
            <span className="text-xs font-semibold text-gray-500 uppercase tracking-wide">
              Quick Add
            </span>
            <div className="flex gap-2 flex-wrap">
              <QuickAddChip
                label="☕ Coffee $4.50"
                onClick={() => handleQuickAdd("4.50", "food")}
              />
              <QuickAddChip
                label="🍜 Lunch $12.80"
                onClick={() => handleQuickAdd("12.80", "food")}
              />
              <QuickAddChip
                label="🚇 Transit $2.75"
                onClick={() => handleQuickAdd("2.75", "transport")}
              />
              <QuickAddChip
                label="🛒 Groceries $67.20"
                onClick={() => handleQuickAdd("67.20", "shopping")}
              />
              <QuickAddChip
                label="🏋️ Gym $30.00"
                onClick={() => handleQuickAdd("30.00", "health")}
              />
            </div>
          </section>

          {/* Amount Hero */}
          <section className="flex flex-col items-center gap-1">
            <div className="flex items-center gap-2">
              <span className="text-4xl font-bold text-gray-900">$</span>
              <input
                type="number"
                inputMode="decimal"
                placeholder="0.00"
                value={form.amount}
                onChange={handleAmountChange}
                className="text-4xl font-bold text-gray-900 bg-transparent border-none outline-none w-40 placeholder-gray-300 text-center"
              />
            </div>
            <span className="text-sm text-gray-400">Enter the expense amount</span>
          </section>

          {/* Expense Form Card */}
          <form onSubmit={handleSubmit}>
            <Card className="shadow-sm border border-gray-100">
              <CardContent className="p-0 flex flex-col divide-y divide-gray-100">
                {/* Category Section */}
                <div className="p-4 flex flex-col gap-3">
                  <span className="text-sm font-semibold text-gray-900">Category</span>
                  <div className="flex flex-wrap gap-2">
                    {categories.map((cat) => (
                      <CategoryChip
                        key={cat.value}
                        label={cat.label}
                        value={cat.value}
                        isSelected={form.categoryId === cat.value}
                        onClick={handleCategoryClick}
                      />
                    ))}
                    <button
                      type="button"
                      onClick={() => setShowNewCategory((v) => !v)}
                      className="px-3 py-1.5 rounded-full border border-dashed border-gray-300 text-sm text-gray-500 hover:border-gray-400 transition-all duration-150 focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2"
