                          Add Category
                        </Button>
                      </div>
                    </div>
                  )}
                </div>

                {/* Date Section */}
                <div className="p-4 flex flex-col gap-3">
                  <span className="text-sm font-semibold text-gray-900">Date</span>
                  <Input
                    type="date"
                    value={form.date}
