import React, { useState } from "react";
import { Switch } from "@/components/ui/switch";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

// ─── Types ───────────────────────────────────────────────────────────────────

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";
type EndDateMode = "NEVER" | "ON_DATE";
type PaymentMethod = "CASH" | "CREDIT" | "DEBIT" | "APPLE_PAY" | "BANK";
type CategoryId = "food" | "transport" | "shopping" | "health" | "entertainment" | "utilities";

// ─── Sub-components ──────────────────────────────────────────────────────────

interface FrequencyChipProps {
  label: string;
  value: Frequency;
  isSelected: boolean;
  onClick: (value: Frequency) => void;
}

const FrequencyChip: React.FC<FrequencyChipProps> = ({ label, value, isSelected, onClick }) => (
  <button
    type="button"
    onClick={() => onClick(value)}
    className={cn(
      "px-4 py-1.5 rounded-full border text-sm font-medium transition-all duration-150 min-h-[36px] focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2",
      isSelected
        ? "bg-blue-100 border-blue-600 text-blue-600"
        : "bg-white border-gray-200 text-gray-700 hover:border-gray-300"
    )}
  >
    {label}
  </button>
);

interface FrequencyChipSelectorProps {
  value: Frequency;
  onChange: (value: Frequency) => void;
}

const FrequencyChipSelector: React.FC<FrequencyChipSelectorProps> = ({ value, onChange }) => {
  const options: { value: Frequency; label: string }[] = [
    { value: "WEEKLY", label: "Weekly" },
    { value: "MONTHLY", label: "Monthly" },
    { value: "YEARLY", label: "Yearly" },
  ];

  return (
    <div className="flex gap-2 flex-wrap">
      {options.map((opt) => (
        <FrequencyChip
          key={opt.value}
          label={opt.label}
          value={opt.value}
          isSelected={value === opt.value}
          onClick={onChange}
        />
      ))}
    </div>
  );
};

interface RadioOptionProps {
  label: string;
  value: string;
  isSelected: boolean;
  onSelect: () => void;
}

const RadioOption: React.FC<RadioOptionProps> = ({ label, value, isSelected, onSelect }) => (
  <button
    type="button"
    onClick={onSelect}
    className="flex items-center gap-2 min-h-[36px] focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2 rounded"
    aria-pressed={isSelected}
  >
    <div
      className={cn(
        "w-4 h-4 rounded-full border-2 flex items-center justify-center transition-colors",
        isSelected ? "border-blue-600" : "border-gray-300"
      )}
    >
      {isSelected && <div className="w-2 h-2 rounded-full bg-blue-600" />}
    </div>
    <span className="text-sm text-gray-700">{label}</span>
  </button>
);

interface EndDateRowProps {
  endDateMode: EndDateMode;
  endDate: string | undefined;
  startDate: string;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
}

const EndDateRow: React.FC<EndDateRowProps> = ({
  endDateMode,
  endDate,
  startDate,
  onEndDateModeChange,
  onEndDateChange,
