```tsx
import React, { useEffect, useState } from "react";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";

// --- Types ---

type BudgetStatus = "On Track" | "Heads Up" | "Over Budget";

interface MonthSummary {
  id: string;
  month: string;
  totalSpent: number;
  transactionCount: number;
  dailyAverage: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
  remainingAmount: number;
  updatedAt: string;
}

interface BudgetSummaryCardProps {
  monthSummary: MonthSummary;
  currency: string;
  animateOnMount?: boolean;
}

// --- Helpers ---

function formatCurrency(amount: number, currency: string): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: currency || "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(amount);
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

// --- Sub-components ---

interface StatusBadgeProps {
  status: BudgetStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const variantMap: Record<
    BudgetStatus,
    { bg: string; text: string; dot: string }
  > = {
    "On Track": {
      bg: "bg-blue-100",
      text: "text-blue-700",
      dot: "bg-blue-500",
    },
    "Heads Up": {
      bg: "bg-amber-100",
      text: "text-amber-700",
      dot: "bg-amber-500",
    },
    "Over Budget": {
      bg: "bg-red-100",
      text: "text-red-700",
      dot: "bg-red-500",
    },
  };

  const variant = variantMap[status];

  return (
    <span
      className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${variant.bg} ${variant.text}`}
      aria-label={`Budget status: ${status}`}
    >
      <span
        className={`w-1.5 h-1.5 rounded-full ${variant.dot}`}
        aria-hidden="true"
      />
      {status}
    </span>
  );
};

interface AnimatedCounterProps {
  value: number;
  currency: string;
  animate: boolean;
}

const AnimatedCounter: React.FC<AnimatedCounterProps> = ({
  value,
  currency,
  animate,
}) => {
  const [displayValue, setDisplayValue] = useState(animate ? 0 : value);

  useEffect(() => {
    if (!animate) {
      setDisplayValue(value);
      return;
    }

    const duration = 800;
    const steps = 40;
    const stepDuration = duration / steps;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      const progress = currentStep / steps;
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayValue(value * eased);

      if (currentStep >= steps) {
        clearInterval(timer);
        setDisplayValue(value);
      }
    }, stepDuration);

    return () => clearInterval(timer);
  }, [value, animate]);

  return (
    <span className="font-variant-numeric tabular-nums">
      {formatCurrency(displayValue, currency)}
    </span>
  );
};

interface BudgetProgressBarProps {
  spentAmount: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
}

const BudgetProgressBar: React.FC<BudgetProgressBarProps> = ({
  spentAmount,
  budgetLimit,
  budgetStatus,
}) => {
  const spendPercentage =
    budgetLimit > 0 ? clamp((spentAmount / budgetLimit) * 100, 0, 100) : 0;

  const fillColorMap: Record<BudgetStatus, string> = {
    "On Track": "bg-blue-600",
    "Heads Up": "bg-amber-500",
    "Over Budget": "bg-red-500",
  };

  const fillColor = fillColorMap[budgetStatus];

  return (
    <div
      className="w-full h-2 bg-gray-200 rounded-full overflow-hidden"
      role="progressbar"
      aria-valuenow={Math.round(spendPercentage)}
      aria-valuemin={0}
      aria-valuemax={100}
      aria-label={`Budget used: ${Math.round(spendPercentage)}%`}
    >
      <div
        className={`h-full rounded-full transition-all duration-700 ease-out ${fillColor}`}
        style={{ width: `${spendPercentage}%` }}
      />
    </div>
  );
};

interface BudgetRemainingDisplayProps {
  remainingAmount: number;
  currency: string;
  isOverBudget: boolean;
}

const BudgetRemainingDisplay: React.FC<BudgetRemainingDisplayProps> = ({
  remainingAmount,
  currency,
  isOverBudget,
}) => {
  const textColor = isOverBudget ? "text-red-500" : "text-gray-600";
  const label = isOverBudget ? "Over budget by" : "Remaining";
  const displayAmount = Math.abs(remainingAmount);

  return (
    <div className="flex items-center justify-between">
      <span className={`text-sm ${textColor}`}>{label}</span>
      <span
        className={`text-sm font-medium tabular-nums ${textColor}`}
        aria-label={`${label}: ${formatCurrency(displayAmount, currency)}`}
      >
        {isOverBudget ? "+" : ""}
        {formatCurrency(displayAmount, currency)}
      </span>
    </div>
  );
};

// --- Stat Row ---

interface StatItemProps {
  label: string;
  value: string;
  subLabel?: string;
}

const StatItem: React.FC<StatItemProps> = ({ label, value, subLabel }) => (
  <div className="flex flex-col gap-0.5">
    <span className="text-xs text-gray-500 font-medium uppercase tracking-wide">
      {label}
    </span>
    <span className="text-sm font-semibold text-gray-900 tabular-nums">
      {value}
    </span>
    {subLabel && <span className="text-xs text-gray-400">{subLabel}</span>}
  </div>
);

// --- Main Component ---

const BudgetSummaryCard: React.FC<BudgetSummaryCardProps> = ({
  monthSummary,
  currency,
  animateOnMount = true,
}) => {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setMounted(true), 50);
    return () => clearTimeout(timer);
  }, []);

  const {
    totalSpent,
    budgetLimit,
    budgetStatus,
    remainingAmount,
    dailyAverage,
    transactionCount,
    month,
  } = monthSummary;

  const isOverBudget = budgetStatus === "Over Budget";
  const spendPercentage =
    budgetLimit > 0 ? clamp((totalSpent / budgetLimit) * 100, 0, 100) : 0;

  const formattedMonth = (() => {
    try {
      const [year, monthNum] = month.split("-");
      const date = new Date(Number(year), Number(monthNum) - 1, 1);
      return date.toLocaleDateString("en-US", {
        month: "long",
        year: "numeric",
      });
    } catch {
      return month;
    }
  })();

  return (
    <Card
      className="w-full bg-white rounded-2xl shadow-md border-0"
      style={{ width: "360px" }}
      aria-label="Budget Summary Card"
    >
      <CardHeader className="pb-3 pt-6 px-6">
        {/* Header row: title + status badge */}
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-base font-semibold text-gray-900 leading-tight">
              Monthly Budget
            </h2>
            <p className="text-xs text-gray-500 mt-0.5">{formattedMonth}</p>
          </div>
          <StatusBadge status={budgetStatus} />
        </div>
      </CardHeader>

      <CardContent className="px-6 pb-6 flex flex-col gap-5">
        {/* Total Spent - Hero Amount */}
        <div className="flex flex-col gap-1">
          <span className="text-xs text-gray-500 font-medium uppercase tracking-wide">
            Total Spent
          </span>
          <div className="text-3xl font-bold text-gray-900 leading-none tracking-tight">
            <AnimatedCounter
              value={totalSpent}
              currency={currency}
              animate={animateOnMount && mounted}
            />
          </div>
          <span className="text-xs text-gray-400">
            of {formatCurrency(budgetLimit, currency)} budget
          </span>
        </div>

        {/* Progress Bar */}
        <div className="flex flex-col gap-2">
          <BudgetProgressBar
            spentAmount={totalSpent}
            budgetLimit={budgetLimit}
            budgetStatus={budgetStatus}
          />
          <div className="flex items-center justify-between">
            <span className="text-xs text-gray-400">
              {Math.round(spendPercentage)}% used
            </span>
            <span className="text-xs text-gray-400">
              {formatCurrency(budgetLimit, currency)} limit
            </span>
          </div>
        </div>

        {/* Remaining */}
        <div className="bg-gray-50 rounded-xl px-4 py-3">
          <BudgetRemainingDisplay
            remainingAmount={remainingAmount}
            currency={currency}
            isOverBudget={isOverBudget}
          />
        </div>

        {/* Stats Row */}
        <div className="grid grid-cols-2 gap-4 pt-1 border-t border-gray-100">
          <StatItem
            label="Daily Average"
            value={formatCurrency(dailyAverage, currency)}
            subLabel="per day"
          />
          <StatItem
            label="Transactions"
            value={transactionCount.toString()}
            subLabel={transactionCount === 1 ? "expense" : "expenses"}
          />
        </div>
      </CardContent>
    </Card>
  );
};

