// --- Types ---

type BudgetStatus = "On Track" | "Heads Up" | "Over Budget";

interface MonthSummary {
  id: string;
  month: string;
  totalSpent: number;
  transactionCount: number;
  dailyAverage: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
  remainingAmount: number;
  updatedAt: string;
}

interface BudgetSummaryCardProps {
  monthSummary: MonthSummary;
  currency: string;
  animateOnMount?: boolean;
}

// --- Helpers ---

function formatCurrency(amount: number, currency: string): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: currency || "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(amount);
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

// --- Sub-components ---

interface StatusBadgeProps {
  status: BudgetStatus;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status }) => {
  const variantStyles: Record<BudgetStatus, string> = {
    "On Track": "bg-blue-100 text-blue-700 hover:bg-blue-100",
    "Heads Up": "bg-amber-100 text-amber-700 hover:bg-amber-100",
    "Over Budget": "bg-red-100 text-red-700 hover:bg-red-100",
  };

  const icons: Record<BudgetStatus, string> = {
    "On Track": "✓",
    "Heads Up": "⚠",
    "Over Budget": "✕",
  };

  return (
    <Badge
      className={`${variantStyles[status]} rounded-full px-3 py-1 text-xs font-semibold border-0 inline-flex items-center gap-1`}
    >
      <span>{icons[status]}</span>
      <span>{status}</span>
    </Badge>
  );
};

interface AnimatedAmountDisplayProps {
  amount: number;
  currency: string;
  label: string;
  animate: boolean;
}

const AnimatedAmountDisplay: React.FC<AnimatedAmountDisplayProps> = ({
  amount,
  currency,
  label,
  animate,
}) => {
  const [displayAmount, setDisplayAmount] = useState(animate ? 0 : amount);

  useEffect(() => {
    if (!animate) {
      setDisplayAmount(amount);
      return;
    }
    const duration = 800;
    const steps = 40;
    const increment = amount / steps;
    let current = 0;
    let step = 0;
    const timer = setInterval(() => {
      step++;
      current = step >= steps ? amount : current + increment;
      setDisplayAmount(current);
      if (step >= steps) clearInterval(timer);
    }, duration / steps);
    return () => clearInterval(timer);
  }, [amount, animate]);

  return (
    <div className="flex flex-col gap-0.5">
      <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">
        {label}
      </span>
      <span
        className="text-4xl font-bold text-gray-900 tabular-nums font-inter leading-tight"
        style={{ fontVariantNumeric: "tabular-nums" }}
      >
        {formatCurrency(displayAmount, currency)}
      </span>
    </div>
  );
};

interface BudgetProgressBarProps {
  spentAmount: number;
  budgetLimit: number;
  budgetStatus: BudgetStatus;
}

const BudgetProgressBar: React.FC<BudgetProgressBarProps> = ({
  spentAmount,
  budgetLimit,
  budgetStatus,
}) => {
  const percentage =
    budgetLimit > 0 ? clamp((spentAmount / budgetLimit) * 100, 0, 100) : 0;

  const fillColor: Record<BudgetStatus, string> = {
    "On Track": "bg-blue-600",
    "Heads Up": "bg-amber-500",
    "Over Budget": "bg-red-500",
  };

  return (
    <div className="w-full">
      <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
        <div
          className={`h-full rounded-full transition-all duration-700 ease-out ${fillColor[budgetStatus]}`}
          style={{ width: `${percentage}%` }}
          role="progressbar"
          aria-valuenow={Math.round(percentage)}
          aria-valuemin={0}
          aria-valuemax={100}
          aria-label={`Budget used: ${Math.round(percentage)}%`}
        />
      </div>
      <div className="flex justify-between mt-1">
        <span className="text-xs text-gray-400">0%</span>
