// StatCell
interface StatCellProps {
  label: string;
  value: string;
  trendDirection: "up" | "down" | "same";
  trendPercentage: number;
}

const StatCell: React.FC<StatCellProps> = ({ label, value, trendDirection, trendPercentage }) => {
  const trendColor =
    trendDirection === "up" ? "text-red-500" : trendDirection === "down" ? "text-emerald-500" : "text-gray-500";
  const trendIcon = trendDirection === "up" ? "↑" : trendDirection === "down" ? "↓" : "→";
  return (
    <div className="flex flex-col gap-1">
      <span className="text-xs text-gray-500 font-medium uppercase tracking-wide">{label}</span>
      <span className="text-2xl font-bold text-gray-900 tabular-nums">{value}</span>
      {trendDirection !== "same" && (
        <span className={`text-xs font-medium ${trendColor} flex items-center gap-0.5`}>
          {trendIcon} {trendPercentage.toFixed(1)}% vs last month
        </span>
      )}
    </div>
  );
};

// PeriodSummaryCard
interface PeriodSummaryCardProps {
  current: MonthSummary;
  previous: MonthSummary | null;
  currency: string;
}

const PeriodSummaryCard: React.FC<PeriodSummaryCardProps> = ({ current, previous, currency }) => {
  const spentDelta = previous ? ((current.totalSpent - previous.totalSpent) / previous.totalSpent) * 100 : 0;
  const avgDelta = previous ? ((current.dailyAverage - previous.dailyAverage) / previous.dailyAverage) * 100 : 0;
  const countDelta = previous ? ((current.transactionCount - previous.transactionCount) / previous.transactionCount) * 100 : 0;

  const dir = (d: number): "up" | "down" | "same" => (d > 0.5 ? "up" : d < -0.5 ? "down" : "same");

  return (
    <Card className="bg-white shadow-sm border border-gray-100">
      <CardContent className="p-6">
        <div className="grid grid-cols-3 gap-4 divide-x divide-gray-200">
          <StatCell label="Total Spent" value={formatCurrency(current.totalSpent, currency)} trendDirection={dir(spentDelta)} trendPercentage={Math.abs(spentDelta)} />
          <div className="pl-4">
            <StatCell label="Daily Average" value={formatCurrency(current.dailyAverage, currency)} trendDirection={dir(avgDelta)} trendPercentage={Math.abs(avgDelta)} />
          </div>
          <div className="pl-4">
            <StatCell label="Transactions" value={String(current.transactionCount)} trendDirection={dir(countDelta)} trendPercentage={Math.abs(countDelta)} />
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

