// DailySpendingChart
interface DailySpendingChartProps {
  data: DailySpending[];
  mode: "bar" | "line";
  averageDaily: number;
  currency: string;
}

const DailySpendingChart: React.FC<DailySpendingChartProps> = ({ data, mode, averageDaily, currency }) => {
  const [tooltip, setTooltip] = useState<{ point: DailySpending; x: number; y: number } | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);
  const chartHeight = 160;
  const barWidth = 100 / data.length;
  const avgLineY = ((maxAmount - averageDaily) / maxAmount) * chartHeight;

  if (mode === "bar") {
    return (
      <div ref={containerRef} className="relative" style={{ height: chartHeight + 24 }}>
        {/* Average line */}
        <div
          className="absolute left-0 right-0 border-t-2 border-dashed border-amber-500 pointer-events-none"
          style={{ top: avgLineY }}
        >
          <span className="absolute right-0 -top-5 text-xs text-amber-600 font-medium">
            Avg {formatCurrency(averageDaily, currency)}
          </span>
        </div>
        {/* Bars */}
        <div className="flex items-end gap-0.5 h-full pb-6">
          {data.map((d) => {
            const heightPct = (d.totalAmount / maxAmount) * 100;
            const isHigh = d.totalAmount > averageDaily * 1.3;
            return (
              <div
                key={d.date}
                className="flex-1 flex flex-col items-center justify-end group cursor-pointer"
                style={{ height: chartHeight }}
                onMouseEnter={(e) => {
                  const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
                  const containerRect = containerRef.current?.getBoundingClientRect();
                  setTooltip({ point: d, x: rect.left - (containerRect?.left ?? 0), y: rect.top - (containerRect?.top ?? 0) });
                }}
                onMouseLeave={() => setTooltip(null)}
              >
                <div
                  className="w-full rounded-t transition-all duration-300"
                  style={{
                    height: `${heightPct}%`,
                    backgroundColor: isHigh ? "#ef4444" : "#2563eb",
                    minHeight: 2,
                  }}
                />
              </div>
            );
          })}
        </div>
        {/* X-axis labels (every 5th) */}
        <div className="flex gap-0.5 mt-1">
          {data.map((d, i) => (
            <div key={d.date} className="flex-1 text-center">
              {i % 5 === 0 && <span className="text-xs text-gray-400">{new Date(d.date).getDate()}</span>}
            </div>
          ))}
        </div>
        {/* Tooltip */}
        {tooltip && (
          <div
            className="absolute z-10 bg-white shadow-lg rounded-lg p-2 text-xs pointer-events-none border border-gray-100"
            style={{ left: Math.min(tooltip.x, 200), top: Math.max(0, tooltip.y - 70) }}
          >
            <div className="font-semibold text-gray-900">{formatDate(tooltip.point.date)}</div>
            <div className="text-gray-700">{formatCurrency(tooltip.point.totalAmount, currency)}</div>
            <div className="text-gray-500">{tooltip.point.transactionCount} transactions</div>
          </div>
        )}
      </div>
    );
  }

  // Line chart (SVG)
  const svgWidth = 600;
  const svgHeight = chartHeight;
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * svgWidth,
    y: svgHeight - (d.totalAmount / maxAmount) * svgHeight,
    d,
  }));
  const pathD = points.map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`).join(" ");
  const fillD = `${pathD} L ${svgWidth} ${svgHeight} L 0 ${svgHeight} Z`;
  const avgY = svgHeight - (averageDaily / maxAmount) * svgHeight;

  return (
    <div ref={containerRef} className="relative">
      <svg viewBox={`0 0 ${svgWidth} ${svgHeight}`} className="w-full" style={{ height: chartHeight }}>
        <defs>
          <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#dbeafe" stopOpacity="0.8" />
            <stop offset="100%" stopColor="#dbeafe" stopOpacity="0" />
          </linearGradient>
        </defs>
        <path d={fillD} fill="url(#lineGrad)" />
        <path d={pathD} fill="none" stroke="#2563eb" strokeWidth="2" />
        <line x1="0" y1={avgY} x2={svgWidth} y2={avgY} stroke="#f59e0b" strokeWidth="1.5" strokeDasharray="6,4" />
        {points.map((p) => (
          <circle
            key={p.d.date}
            cx={p.x}
            cy={p.y}
            r="3"
            fill="#2563eb"
            className="cursor-pointer"
            onMouseEnter={() => setTooltip({ point: p.d, x: p.x, y: p.y })}
            onMouseLeave={() => setTooltip(null)}
          />
        ))}
      </svg>
      {tooltip && (
        <div
          className="absolute z-10 bg-white shadow-lg rounded-lg p-2 text-xs pointer-events-none border border-gray-100"
          style={{ left: Math.min((tooltip.x / svgWidth) * 100, 70) + "%", top: 0 }}
        >
          <div className="font-semibold text-gray-900">{formatDate(tooltip.point.date)}</div>
          <div className="text-gray-700">{formatCurrency(tooltip.point.totalAmount, currency)}</div>
          <div className="text-gray-500">{tooltip.point.transactionCount} transactions</div>
        </div>
      )}
    </div>
  );
};

