interface StatCellProps {
  label: string;
  value: string;
  trendDirection: "up" | "down" | "same";
  trendPercentage: number;
}

const StatCell: React.FC<StatCellProps> = ({ label, value, trendDirection, trendPercentage }) => {
  const isGood = trendDirection === "down";
  const isBad = trendDirection === "up";
  const trendColor = isGood ? "text-emerald-600" : isBad ? "text-red-500" : "text-gray-500";
  const trendBg = isGood ? "bg-emerald-50" : isBad ? "bg-red-50" : "bg-gray-100";
  const arrow = trendDirection === "up" ? "↑" : trendDirection === "down" ? "↓" : "→";

  return (
    <div className="flex flex-col gap-1">
      <span className="text-xs text-gray-500 font-medium uppercase tracking-wide">{label}</span>
      <span className="text-2xl font-bold text-gray-900 tabular-nums">{value}</span>
      {trendDirection !== "same" && (
        <span className={`inline-flex items-center gap-1 text-xs font-semibold px-2 py-0.5 rounded-full w-fit ${trendColor} ${trendBg}`}>
          {arrow} {trendPercentage.toFixed(1)}%
        </span>
      )}
    </div>
  );
};

interface ChartModeToggleProps {
