);

interface DailySpendingChartProps {
  data: DailySpending[];
  mode: "bar" | "line";
  averageDaily: number;
  currency: string;
}

const DailySpendingChart: React.FC<DailySpendingChartProps> = ({ data, mode, averageDaily, currency }) => {
  const [hoveredPoint, setHoveredPoint] = useState<DailySpending | null>(null);
  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);

  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);
  const chartHeight = 160;

  if (mode === "bar") {
    return (
      <div className="relative">
        <div className="flex items-end gap-1 h-40 px-1" role="img" aria-label="Daily spending bar chart">
          {data.map((point, i) => {
            const heightPct = (point.totalAmount / maxAmount) * 100;
            const isAboveAvg = point.totalAmount > averageDaily * 1.3;
            const barColor = isAboveAvg ? "bg-red-500" : "bg-blue-600";
            const isHovered = hoveredIndex === i;

            return (
              <div
                key={point.date}
                className="flex-1 flex flex-col items-center gap-1 cursor-pointer group"
                onMouseEnter={() => { setHoveredPoint(point); setHoveredIndex(i); }}
                onMouseLeave={() => { setHoveredPoint(null); setHoveredIndex(null); }}
              >
                <div className="w-full flex items-end" style={{ height: chartHeight }}>
                  <div
                    className={`w-full rounded-t transition-all ${barColor} ${isHovered ? "opacity-80" : "opacity-100"}`}
                    style={{ height: `${heightPct}%` }}
                  />
                </div>
                {isHovered && (
                  <div className="absolute bottom-full mb-2 bg-white shadow-lg rounded-lg p-2 text-xs z-10 whitespace-nowrap border border-gray-100">
                    <div className="font-semibold text-gray-900">{formatDate(point.date)}</div>
                    <div className="text-gray-700">{formatCurrency(point.totalAmount, currency)}</div>
                    <div className="text-gray-500">{point.transactionCount} transactions</div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
        <div
          className="absolute left-0 right-0 border-t-2 border-dashed border-amber-500 pointer-events-none"
          style={{ bottom: `${(averageDaily / maxAmount) * chartHeight}px` }}
        >
          <span className="absolute right-0 -top-5 text-xs text-amber-600 font-medium bg-white px-1">
            Avg {formatCurrency(averageDaily, currency)}
          </span>
        </div>
      </div>
    );
  }

  // Line chart
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * 100,
    y: 100 - (d.totalAmount / maxAmount) * 100,
    data: d,
  }));

  const pathD = points
    .map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`)
    .join(" ");

  const fillD = `${pathD} L ${points[points.length - 1].x} 100 L ${points[0].x} 100 Z`;

  return (
    <div className="relative h-40">
      <svg
        viewBox="0 0 100 100"
        preserveAspectRatio="none"
        className="w-full h-full"
        role="img"
        aria-label="Daily spending line chart"
      >
        <path d={fillD} fill="#dbeafe" opacity="0.6" />
        <path d={pathD} fill="none" stroke="#2563eb" strokeWidth="0.8" />
        <line
          x1="0" y1={100 - (averageDaily / maxAmount) * 100}
          x2="100" y2={100 - (averageDaily / maxAmount) * 100}
          stroke="#f59e0b" strokeWidth="0.5" strokeDasharray="2,2"
        />
        {points.map((p, i) => (
          <circle
            key={i}
            cx={p.x}
            cy={p.y}
            r="1.5"
            fill="#2563eb"
            className="cursor-pointer"
            onMouseEnter={() => { setHoveredPoint(p.data); setHoveredIndex(i); }}
            onMouseLeave={() => { setHoveredPoint(null); setHoveredIndex(null); }}
          />
        ))}
      </svg>
      {hoveredPoint && (
        <div className="absolute top-0 left-1/2 -translate-x-1/2 bg-white shadow-lg rounded-lg p-2 text-xs z-10 whitespace-nowrap border border-gray-100">
          <div className="font-semibold text-gray-900">{formatDate(hoveredPoint.date)}</div>
          <div className="text-gray-700">{formatCurrency(hoveredPoint.totalAmount, currency)}</div>
          <div className="text-gray-500">{hoveredPoint.transactionCount} transactions</div>
        </div>
      )}
    </div>
  );
};

