  const max = Math.max(current.totalSpent, previous?.totalSpent ?? 0, 1);
  const currentPct = (current.totalSpent / max) * 100;
  const prevPct = previous ? (previous.totalSpent / max) * 100 : 0;

  return (
    <div className="flex flex-col gap-3">
      <div className="flex flex-col gap-1">
        <div className="flex justify-between text-sm">
          <span className="text-gray-700 font-medium">{formatShortMonth(current.month)}</span>
