// StatCell
interface StatCellProps {
  label: string;
  value: string;
  trendDirection: "up" | "down" | "same";
  trendPercentage: number;
  trendGoodDirection: "up" | "down";
}

const StatCell: React.FC<StatCellProps> = ({
  label,
  value,
  trendDirection,
  trendPercentage,
  trendGoodDirection,
}) => {
  const isGood =
    trendDirection === "same" ||
    (trendGoodDirection === "down" && trendDirection === "down") ||
    (trendGoodDirection === "up" && trendDirection === "up");

  const trendColor =
    trendDirection === "same"
      ? "text-gray-500"
      : isGood
      ? "text-emerald-600"
      : "text-red-500";

  const arrow = trendDirection === "up" ? "↑" : trendDirection === "down" ? "↓" : "→";

  return (
    <div className="flex flex-col gap-1 min-w-0">
      <span className="text-xs text-gray-500 font-medium uppercase tracking-wide truncate">
        {label}
      </span>
      <span className="text-xl font-bold text-gray-900 tabular-nums">{value}</span>
      {trendDirection !== "same" && (
        <span className={`text-xs font-medium ${trendColor} flex items-center gap-0.5`}>
          {arrow} {Math.abs(trendPercentage).toFixed(1)}% vs last month
        </span>
      )}
    </div>
  );
};

// PeriodSummaryCard
interface PeriodSummaryCardProps {
  monthSummary: MonthSummary;
  prevSummary: MonthSummary | null;
  currency: string;
}

const PeriodSummaryCard: React.FC<PeriodSummaryCardProps> = ({
  monthSummary,
  prevSummary,
  currency,
}) => {
  const calcTrend = (
    current: number,
    previous: number | undefined
  ): { direction: "up" | "down" | "same"; pct: number } => {
    if (!previous || previous === 0) return { direction: "same", pct: 0 };
    const pct = ((current - previous) / previous) * 100;
    return {
      direction: pct > 0.5 ? "up" : pct < -0.5 ? "down" : "same",
      pct,
    };
  };

  const spentTrend = calcTrend(monthSummary.totalSpent, prevSummary?.totalSpent);
  const avgTrend = calcTrend(monthSummary.dailyAverage, prevSummary?.dailyAverage);
  const countTrend = calcTrend(monthSummary.transactionCount, prevSummary?.transactionCount);

  return (
    <Card className="bg-white shadow-sm">
      <CardContent className="pt-6">
        <div className="grid grid-cols-3 gap-4 divide-x divide-gray-200">
          <StatCell
            label="Total Spent"
            value={formatCurrency(monthSummary.totalSpent, currency)}
            trendDirection={spentTrend.direction}
            trendPercentage={spentTrend.pct}
            trendGoodDirection="down"
          />
          <div className="pl-4">
            <StatCell
              label="Daily Average"
              value={formatCurrency(monthSummary.dailyAverage, currency)}
              trendDirection={avgTrend.direction}
              trendPercentage={avgTrend.pct}
              trendGoodDirection="down"
            />
          </div>
          <div className="pl-4">
            <StatCell
              label="Transactions"
              value={String(monthSummary.transactionCount)}
              trendDirection={countTrend.direction}
              trendPercentage={countTrend.pct}
              trendGoodDirection="down"
            />
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

// DailySpendingChart
interface DailySpendingChartProps {
  data: DailySpending[];
  mode: "bar" | "line";
  averageDaily: number;
  currency: string;
}

const DailySpendingChart: React.FC<DailySpendingChartProps> = ({
  data,
  mode,
  averageDaily,
  currency,
}) => {
  const [hoveredIdx, setHoveredIdx] = useState<number | null>(null);
  const maxAmount = Math.max(...data.map((d) => d.totalAmount), 1);

  if (mode === "bar") {
    return (
      <div className="relative">
        <div
          className="flex items-end gap-1 h-40 w-full"
          role="img"
          aria-label="Daily spending bar chart"
        >
          {data.map((d, i) => {
            const heightPct = (d.totalAmount / maxAmount) * 100;
            const isAboveAvg = d.totalAmount > averageDaily * 1.3;
            const isHovered = hoveredIdx === i;
            return (
              <div
                key={d.date}
                className="flex-1 flex flex-col items-center justify-end relative group"
                onMouseEnter={() => setHoveredIdx(i)}
                onMouseLeave={() => setHoveredIdx(null)}
              >
                {isHovered && (
                  <div className="absolute bottom-full mb-2 z-10 bg-white shadow-lg rounded-lg p-2 text-xs whitespace-nowrap border border-gray-100">
                    <div className="font-semibold text-gray-900">{formatDate(d.date)}</div>
                    <div className="text-gray-700">{formatCurrency(d.totalAmount, currency)}</div>
                    <div className="text-gray-500">{d.transactionCount} txns</div>
                  </div>
                )}
                <div
                  className="w-full rounded-t transition-all duration-200"
                  style={{
                    height: `${heightPct}%`,
                    backgroundColor: isAboveAvg ? "#ef4444" : "#2563eb",
                    minHeight: "2px",
                  }}
                />
              </div>
            );
          })}
        </div>
        {/* Average line overlay */}
        <div
          className="absolute left-0 right-0 border-t-2 border-dashed border-amber-500 pointer-events-none"
          style={{
            bottom: `${(averageDaily / maxAmount) * 160}px`,
          }}
        >
          <span className="absolute right-0 -top-5 text-xs text-amber-600 font-medium bg-white px-1">
            avg {formatCurrency(averageDaily, currency)}
          </span>
        </div>
        {/* X-axis labels */}
        <div className="flex gap-1 mt-1">
          {data.map((d, i) => (
            <div key={d.date} className="flex-1 text-center">
              {i % 5 === 0 && (
                <span className="text-xs text-gray-400">
                  {new Date(d.date).getDate()}
                </span>
              )}
            </div>
          ))}
        </div>
      </div>
    );
  }

  // Line chart
  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * 100,
    y: 100 - (d.totalAmount / maxAmount) * 100,
    ...d,
  }));

  const pathD = points
    .map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`)
    .join(" ");

  const fillD = `${pathD} L ${points[points.length - 1].x} 100 L 0 100 Z`;

  return (
    <div className="relative">
      <svg
        viewBox="0 0 100 100"
        preserveAspectRatio="none"
        className="w-full h-40"
        role="img"
        aria-label="Daily spending line chart"
      >
        <defs>
          <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#bfdbfe" stopOpacity="0.8" />
            <stop offset="100%" stopColor="#bfdbfe" stopOpacity="0" />
          </linearGradient>
        </defs>
        <path d={fillD} fill="url(#lineGrad)" />
        <path d={pathD} fill="none" stroke="#2563eb" strokeWidth="1.5" vectorEffect="non-scaling-stroke" />
        {/* Average line */}
        <line
          x1="0"
          y1={100 - (averageDaily / maxAmount) * 100}
          x2="100"
          y2={100 - (averageDaily / maxAmount) * 100}
          stroke="#f59e0b"
          strokeWidth="1"
          strokeDasharray="3,2"
          vectorEffect="non-scaling-stroke"
        />
        {points.map((p, i) => (
          <circle
            key={i}
            cx={p.x}
            cy={p.y}
            r="1.5"
            fill="#2563eb"
            vectorEffect="non-scaling-stroke"
            className="cursor-pointer"
            onMouseEnter={() => setHoveredIdx(i)}
            onMouseLeave={() => setHoveredIdx(null)}
          />
        ))}
      </svg>
      {hoveredIdx !== null && (
        <div className="absolute top-0 left-1/2 -translate-x-1/2 bg-white shadow-lg rounded-lg p-2 text-xs border border-gray-100 z-10">
          <div className="font-semibold text-gray-900">{formatDate(data[hoveredIdx].date)}</div>
          <div className="text-gray-700">{formatCurrency(data[hoveredIdx].totalAmount, currency)}</div>
          <div className="text-gray-500">{data[hoveredIdx].transactionCount} txns</div>
        </div>
      )}
    </div>
  );
};

