// ComparisonBadge
interface ComparisonBadgeProps {
  delta: number;
  deltaDirection: "less" | "more" | "same";
  currency: string;
}

const ComparisonBadge: React.FC<ComparisonBadgeProps> = ({ delta, deltaDirection, currency }) => {
  const styles = {
    less: "bg-emerald-100 text-emerald-700",
    more: "bg-red-100 text-red-700",
    same: "bg-gray-100 text-gray-700",
  };
  const labels = {
    less: `↓ ${formatCurrency(Math.abs(delta), currency)} less`,
    more: `↑ ${formatCurrency(Math.abs(delta), currency)} more`,
    same: "Same as last month",
  };

  return (
    <span
      className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-semibold tabular-nums ${styles[deltaDirection]}`}
    >
      {labels[deltaDirection]}
    </span>
  );
};

// MonthComparisonCard
interface MonthComparisonCardProps {
  current: { month: string; totalSpent: number };
  previous: { month: string; totalSpent: number } | null;
  currency: string;
}

const MonthComparisonCard: React.FC<MonthComparisonCardProps> = ({
  current,
  previous,
  currency,
}) => {
  const delta = previous ? current.totalSpent - previous.totalSpent : 0;
  const deltaDirection: "less" | "more" | "same" =
    Math.abs(delta) < 1 ? "same" : delta < 0 ? "less" : "more";

  const maxAmount = Math.max(current.totalSpent, previous?.totalSpent ?? 0, 1);

  return (
    <Card className="bg-white shadow-sm">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between flex-wrap gap-2">
          <CardTitle className="text-base font-semibold text-gray-900">Month Comparison</CardTitle>
          <ComparisonBadge delta={delta} deltaDirection={deltaDirection} currency={currency} />
        </div>
      </CardHeader>
      <CardContent>
        <div className="flex flex-col gap-3">
          {/* Current month */}
          <div className="flex flex-col gap-1">
            <div className="flex justify-between text-sm">
              <span className="text-gray-700 font-medium">{getMonthLabel(current.month)}</span>
              <span className="text-gray-900 font-bold tabular-nums">
                {formatCurrency(current.totalSpent, currency)}
              </span>
            </div>
            <div className="h-3 bg-gray-100 rounded-full overflow-hidden">
              <div
                className="h-full bg-blue-600 rounded-full transition-all duration-700"
                style={{ width: `${(current.totalSpent / maxAmount) * 100}%` }}
              />
            </div>
          </div>
          {/* Previous month */}
          {previous && (
            <div className="flex flex-col gap-1">
              <div className="flex justify-between text-sm">
                <span className="text-gray-500">{getMonthLabel(previous.month)}</span>
                <span className="text-gray-600 tabular-nums">
                  {formatCurrency(previous.totalSpent, currency)}
                </span>
              </div>
              <div className="h-3 bg-gray-100 rounded-full overflow-hidden">
                <div
                  className="h-full bg-gray-300 rounded-full transition-all duration-700"
                  style={{ width: `${(previous.totalSpent / maxAmount) * 100}%` }}
                />
              </div>
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );
};

