  settings: UserSettings;
  categories: Category[];
  onSettingsChange: (settings: { currency?: string; defaultMonthlyBudget?: number }) => void;
  onCategoryDelete: (categoryId: string) => void;
  onCategoryAdd: () => void;
}

// ─── Currency helpers ─────────────────────────────────────────────────────────

const CURRENCY_OPTIONS: Currency[] = ["USD", "EUR", "GBP", "INR", "JPY"];

const CURRENCY_SYMBOLS: Record<Currency, string> = {
  USD: "$",
  EUR: "€",
  GBP: "£",
  INR: "₹",
  JPY: "¥",
};

// ─── Sub-components ───────────────────────────────────────────────────────────

interface DialogHeaderProps {
  title: string;
  onClose: () => void;
}

const DialogHeader: React.FC<DialogHeaderProps> = ({ title, onClose }) => (
  <div className="flex items-center justify-between pb-4">
    <div className="flex items-center gap-2">
      <Settings className="h-5 w-5 text-blue-600" />
      <h2 className="text-lg font-semibold text-gray-900">{title}</h2>
    </div>
    <button
      onClick={onClose}
      aria-label="Close settings"
      className="rounded-md p-1 text-gray-500 hover:bg-gray-100 hover:text-gray-700 focus:outline-none focus:ring-2 focus:ring-blue-600 transition-colors"
    >
      <X className="h-5 w-5" />
    </button>
  </div>
);

interface CurrencySelectorProps {
  options: Currency[];
  selectedCurrency: Currency;
  onSelect: (currency: Currency) => void;
