}

const CurrencySelector: React.FC<CurrencySelectorProps> = ({
  options,
  selectedCurrency,
  onSelect,
  label,
}) => (
  <div className="space-y-1.5">
    <label className="text-sm font-medium text-gray-700">{label}</label>
    <Select value={selectedCurrency} onValueChange={(v) => onSelect(v as Currency)}>
      <SelectTrigger className="w-full border-gray-200 rounded-md focus:ring-2 focus:ring-blue-600 text-gray-900">
        <SelectValue placeholder="Select currency" />
      </SelectTrigger>
      <SelectContent>
        {options.map((c) => (
          <SelectItem key={c} value={c}>
            <span className="flex items-center gap-2">
              <span className="font-mono text-gray-500">{CURRENCY_SYMBOLS[c]}</span>
              <span>{c}</span>
            </span>
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  </div>
);

interface BudgetLimitInputProps {
  value: number;
  onChange: (value: number) => void;
  currency: Currency;
  label: string;
}

const BudgetLimitInput: React.FC<BudgetLimitInputProps> = ({
  value,
  onChange,
  currency,
  label,
}) => {
  const [raw, setRaw] = useState(String(value));

  useEffect(() => {
    setRaw(String(value));
  }, [value]);

  const handleBlur = () => {
    const parsed = parseFloat(raw);
    if (!isNaN(parsed) && parsed >= 0) {
      onChange(parsed);
    } else {
      setRaw(String(value));
    }
  };

  return (
    <div className="space-y-1.5">
      <label className="text-sm font-medium text-gray-700">{label}</label>
      <div className="flex items-center rounded-md border border-gray-200 focus-within:ring-2 focus-within:ring-blue-600 overflow-hidden">
