        </span>
        <Input
          type="number"
          inputMode="decimal"
          value={raw}
          onChange={(e) => setRaw(e.target.value)}
          onBlur={handleBlur}
          className="border-0 focus-visible:ring-0 focus-visible:ring-offset-0 font-mono tabular-nums text-gray-900 rounded-none"
          min={0}
          step={1}
        />
      </div>
    </div>
  );
};

interface CategoryManagerRowProps {
