      {category.isDefault && (
        <Badge variant="secondary" className="text-xs py-0 px-1.5 h-4">
          Default
        </Badge>
      )}
    </div>
    <button
      onClick={() => !category.isDefault && onDelete(category.id)}
      disabled={category.isDefault}
