      }
      className={`rounded-md p-1 transition-colors focus:outline-none focus:ring-2 focus:ring-blue-600 ${
        category.isDefault
          ? "text-gray-300 cursor-not-allowed"
          : "text-red-500 hover:bg-red-50 hover:text-red-600 opacity-0 group-hover:opacity-100"
      }`}
    >
      <Trash2 className="h-4 w-4" />
    </button>
  </div>
);

interface CategoryManagerProps {
  categories: Category[];
  onDelete: (categoryId: string) => void;
  onAdd: () => void;
  addLabel: string;
}

const CategoryManager: React.FC<CategoryManagerProps> = ({
  categories,
  onDelete,
  onAdd,
  addLabel,
}) => (
  <div className="space-y-1">
    <div className="space-y-0.5 max-h-48 overflow-y-auto pr-1">
      {categories.length === 0 ? (
        <p className="text-sm text-gray-400 py-2 text-center">No categories yet.</p>
