// ─── Toast notification (lightweight) ────────────────────────────────────────

interface ToastState {
  message: string;
  visible: boolean;
}

// ─── Main SettingsForm component ──────────────────────────────────────────────

const SettingsForm: React.FC<SettingsFormProps> = ({
  isOpen,
  onClose,
  settings,
  categories,
  onSettingsChange,
  onCategoryDelete,
  onCategoryAdd,
}) => {
  const [localCurrency, setLocalCurrency] = useState<Currency>(settings.currency);
  const [localBudget, setLocalBudget] = useState<number>(settings.defaultMonthlyBudget);
  const [toast, setToast] = useState<ToastState>({ message: "", visible: false });
  const [isSaving, setIsSaving] = useState(false);
  const [saveStatus, setSaveStatus] = useState<"idle" | "saved" | "error">("idle");

  // Sync local state when settings prop changes
  useEffect(() => {
    setLocalCurrency(settings.currency);
    setLocalBudget(settings.defaultMonthlyBudget);
  }, [settings]);

  // Close on Escape key
  useEffect(() => {
    if (!isOpen) return;
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isOpen, onClose]);

  const showToast = useCallback((message: string) => {
    setToast({ message, visible: true });
    setTimeout(() => setToast({ message: "", visible: false }), 3000);
  }, []);

  const handleCurrencyChange = (currency: Currency) => {
    setLocalCurrency(currency);
  };

  const handleBudgetChange = (value: number) => {
    setLocalBudget(value);
  };

  const handleSave = async () => {
    setIsSaving(true);
    setSaveStatus("idle");
    try {
      const currencyChanged = localCurrency !== settings.currency;
      const budgetChanged = localBudget !== settings.defaultMonthlyBudget;

      if (currencyChanged || budgetChanged) {
        onSettingsChange({
          ...(currencyChanged && { currency: localCurrency }),
          ...(budgetChanged && { defaultMonthlyBudget: localBudget }),
        });
      }

      if (currencyChanged) {
        showToast(`Currency changed to ${localCurrency}`);
      }

      setSaveStatus("saved");
      setTimeout(() => setSaveStatus("idle"), 2500);
    } catch {
      setSaveStatus("error");
    } finally {
      setIsSaving(false);
    }
  };

  const handleScrimClick = () => onClose();

  if (!isOpen) return null;

  return (
    <>
      {/* Scrim */}
      <div
        className="fixed inset-0 z-40 bg-black/50"
        onClick={handleScrimClick}
        aria-hidden="true"
      />

      {/* Toast */}
      {toast.visible && (
        <div
          role="status"
          aria-live="polite"
          className="fixed top-4 left-1/2 -translate-x-1/2 z-[60] bg-gray-900 text-white text-sm px-4 py-2 rounded-lg shadow-lg transition-all"
        >
          {toast.message}
        </div>
      )}

      {/* Dialog */}
      <div
        role="dialog"
        aria-modal="true"
        aria-labelledby="settings-dialog-title"
        className="fixed inset-0 z-50 flex items-center justify-center p-4"
      >
        <div
          className="relative w-full bg-white rounded-2xl shadow-2xl flex flex-col"
          style={{ maxWidth: "420px", maxHeight: "90vh" }}
          onClick={(e) => e.stopPropagation()}
        >
          {/* Inner padding wrapper */}
          <div className="flex flex-col flex-1 overflow-hidden p-6">
            {/* Header */}
            <DialogHeader title="Settings" onClose={onClose} />

            {/* Scrollable content */}
            <div className="flex-1 overflow-y-auto space-y-5 pr-0.5">
              {/* Currency Section */}
              <section aria-labelledby="currency-section-title">
                <div className="mb-3">
                  <h3
                    id="currency-section-title"
                    className="text-sm font-semibold text-gray-900"
                  >
                    Currency
                  </h3>
                  <p className="text-xs text-gray-500 mt-0.5">
                    Choose the currency used across CashPulse.
                  </p>
                </div>
                <CurrencySelector
                  options={CURRENCY_OPTIONS}
                  selectedCurrency={localCurrency}
                  onSelect={handleCurrencyChange}
                  label="Default Currency"
                />
              </section>

              <Separator className="bg-gray-100" />

              {/* Budget Section */}
              <section aria-labelledby="budget-section-title">
                <div className="mb-3">
                  <h3
                    id="budget-section-title"
                    className="text-sm font-semibold text-gray-900"
                  >
                    Monthly Budget
                  </h3>
                  <p className="text-xs text-gray-500 mt-0.5">
                    Set your default monthly spending limit.
                  </p>
                </div>
                <BudgetLimitInput
                  value={localBudget}
                  onChange={handleBudgetChange}
                  currency={localCurrency}
                  label="Budget Limit"
                />
              </section>

              <Separator className="bg-gray-100" />

              {/* Category Manager Section */}
              <section aria-labelledby="categories-section-title">
                <div className="mb-3">
                  <h3
                    id="categories-section-title"
                    className="text-sm font-semibold text-gray-900"
                  >
                    Expense Categories
                  </h3>
                  <p className="text-xs text-gray-500 mt-0.5">
                    Manage your expense categories. Default categories cannot be deleted.
                  </p>
                </div>
                <CategoryManager
                  categories={categories}
                  onDelete={onCategoryDelete}
                  onAdd={onCategoryAdd}
                  addLabel="Add category"
                />
              </section>
            </div>

            {/* Footer */}
            <div className="pt-5 border-t border-gray-100 mt-5 flex items-center justify-between gap-3">
              <div className="flex-1">
                {saveStatus === "saved" && (
                  <p className="text-xs text-green-600 font-medium" role="status">
                    ✓ Settings saved
                  </p>
                )}
                {saveStatus === "error" && (
                  <p className="text-xs text-red-500 font-medium" role="alert">
                    Failed to save. Try again.
                  </p>
                )}
              </div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={onClose}
                  className="text-gray-700 border-gray-200 hover:bg-gray-50"
                >
                  Cancel
                </Button>
                <Button
                  onClick={handleSave}
                  disabled={isSaving}
                  className="bg-blue-600 hover:bg-blue-700 text-white focus:ring-2 focus:ring-blue-600 focus:ring-offset-2"
                >
                  {isSaving ? "Saving…" : "Save Settings"}
                </Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

