  const handleSettingsChange = (updates: { currency?: string; defaultMonthlyBudget?: number }) => {
    setSettings((prev) => ({
      ...prev,
      ...(updates.currency && { currency: updates.currency as Currency }),
      ...(updates.defaultMonthlyBudget !== undefined && {
