interface ToastState {
  message: string;
  visible: boolean;
}

// ─── Main SettingsForm component ──────────────────────────────────────────────

const SettingsForm: React.FC<SettingsFormProps> = ({
  isOpen,
  onClose,
  settings,
  categories,
  onSettingsChange,
  onCategoryDelete,
  onCategoryAdd,
}) => {
  const [selectedCurrency, setSelectedCurrency] = useState<Currency>(settings.currency);
  const [budgetValue, setBudgetValue] = useState<number>(settings.defaultMonthlyBudget);
  const [toast, setToast] = useState<ToastState>({ message: "", visible: false });
  const [isSaving, setIsSaving] = useState(false);
  const [saveStatus, setSaveStatus] = useState<"idle" | "saved" | "error">("idle");

  // Sync local state when settings prop changes
  useEffect(() => {
    setSelectedCurrency(settings.currency);
    setBudgetValue(settings.defaultMonthlyBudget);
  }, [settings]);

  // Close on Escape key
  useEffect(() => {
    if (!isOpen) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, onClose]);

  const showToast = useCallback((message: string) => {
    setToast({ message, visible: true });
    setTimeout(() => setToast({ message: "", visible: false }), 3000);
  }, []);

  const handleCurrencyChange = (currency: Currency) => {
    setSelectedCurrency(currency);
  };

  const handleBudgetChange = (value: number) => {
    setBudgetValue(value);
  };

  const handleSave = async () => {
    setIsSaving(true);
    setSaveStatus("idle");
    try {
      const currencyChanged = selectedCurrency !== settings.currency;
      onSettingsChange({
        currency: selectedCurrency,
        defaultMonthlyBudget: budgetValue,
      });
      setSaveStatus("saved");
      if (currencyChanged) {
        showToast(`Currency changed to ${selectedCurrency}`);
      } else {
        showToast("Settings saved successfully");
      }
    } catch {
      setSaveStatus("error");
      showToast("Failed to save settings");
    } finally {
      setIsSaving(false);
    }
  };

  const handleScrimClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if (e.target === e.currentTarget) onClose();
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Scrim */}
      <div
        className="fixed inset-0 z-40 bg-black/50"
        onClick={handleScrimClick}
        aria-hidden="true"
      />

      {/* Dialog Panel */}
      <div
        role="dialog"
        aria-modal="true"
        aria-labelledby="settings-dialog-title"
        className="fixed inset-0 z-50 flex items-center justify-center p-4"
      >
        <div
          className="relative w-full bg-white rounded-xl shadow-2xl flex flex-col"
          style={{ maxWidth: "420px", maxHeight: "90vh" }}
        >
          {/* Toast */}
          {toast.visible && (
            <div className="absolute top-3 left-1/2 -translate-x-1/2 z-10 bg-gray-900 text-white text-sm px-4 py-2 rounded-full shadow-lg whitespace-nowrap transition-all">
              {toast.message}
            </div>
          )}

          {/* Scrollable content */}
          <div className="overflow-y-auto flex-1 p-6">
            {/* Header */}
            <DialogHeader title="Settings" onClose={onClose} />

            <div className="space-y-5">
              {/* Currency Section */}
              <section aria-labelledby="currency-section-title">
                <div className="mb-3">
                  <h3
                    id="currency-section-title"
                    className="text-sm font-semibold text-gray-900"
                  >
                    Currency
                  </h3>
                  <p className="text-xs text-gray-500 mt-0.5">
                    Choose your preferred display currency for all transactions.
                  </p>
                </div>
                <CurrencySelector
                  options={CURRENCY_OPTIONS}
                  selectedCurrency={selectedCurrency}
                  onSelect={handleCurrencyChange}
                  label="Default Currency"
                />
              </section>

              <Separator />

              {/* Budget Section */}
              <section aria-labelledby="budget-section-title">
                <div className="mb-3">
                  <h3
                    id="budget-section-title"
                    className="text-sm font-semibold text-gray-900"
                  >
                    Monthly Budget
                  </h3>
                  <p className="text-xs text-gray-500 mt-0.5">
                    Set your default monthly spending limit to track expenses.
                  </p>
                </div>
                <BudgetLimitInput
                  value={budgetValue}
                  onChange={handleBudgetChange}
                  currency={selectedCurrency}
                  label="Monthly Budget Limit"
                />
              </section>

              <Separator />

              {/* Category Manager Section */}
              <section aria-labelledby="categories-section-title">
                <div className="mb-3">
                  <h3
                    id="categories-section-title"
                    className="text-sm font-semibold text-gray-900"
                  >
                    Expense Categories
                  </h3>
                  <p className="text-xs text-gray-500 mt-0.5">
                    Manage your expense categories. Default categories cannot be deleted.
                  </p>
                </div>
                <CategoryManager
                  categories={categories}
                  onDelete={onCategoryDelete}
                  onAdd={onCategoryAdd}
                  addLabel="Add category"
                />
              </section>
            </div>
          </div>

          {/* Footer */}
          <div className="border-t border-gray-100 px-6 py-4 flex items-center justify-between gap-3 bg-gray-50 rounded-b-xl">
            <div className="flex items-center gap-2">
              {saveStatus === "saved" && (
                <span className="text-xs text-green-600 font-medium">✓ Saved</span>
              )}
              {saveStatus === "error" && (
                <span className="text-xs text-red-500 font-medium">Save failed</span>
              )}
            </div>
            <div className="flex items-center gap-2">
              <Button
                variant="outline"
                onClick={onClose}
                className="text-gray-700 border-gray-200 hover:bg-gray-100"
              >
                Cancel
              </Button>
              <Button
                onClick={handleSave}
                disabled={isSaving}
                className="bg-blue-600 hover:bg-blue-700 text-white focus:ring-2 focus:ring-blue-600 focus:ring-offset-2"
              >
                {isSaving ? "Saving…" : "Save Settings"}
              </Button>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

