interface ToastMessage {
  id: number;
  text: string;
  type: "success" | "info";
}

// ─── Main Component ───────────────────────────────────────────────────────────

const SettingsForm: React.FC<SettingsFormProps> = ({
  isOpen,
  onClose,
  settings,
  categories,
  onSettingsChange,
  onCategoryDelete,
  onCategoryAdd,
}) => {
  const [selectedCurrency, setSelectedCurrency] = useState<Currency>(settings.currency);
  const [budgetValue, setBudgetValue] = useState<number>(settings.defaultMonthlyBudget);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [saveStatus, setSaveStatus] = useState<"idle" | "saved" | "error">("idle");

  // Sync props → local state when settings prop changes
  useEffect(() => {
    setSelectedCurrency(settings.currency);
    setBudgetValue(settings.defaultMonthlyBudget);
  }, [settings]);

  // Close on Escape
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [isOpen, onClose]);

  const addToast = useCallback((text: string, type: ToastMessage["type"] = "success") => {
    const id = Date.now();
    setToasts((prev) => [...prev, { id, text, type }]);
    setTimeout(() => setToasts((prev) => prev.filter((t) => t.id !== id)), 3000);
  }, []);

  const handleCurrencyChange = (currency: Currency) => {
    setSelectedCurrency(currency);
    addToast(`Currency changed to ${currency}`, "info");
  };

  const handleSave = async () => {
    setIsSaving(true);
    setSaveStatus("idle");
    try {
      await Promise.all([
        // PUT /api/settings
        fetch("/api/settings", {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            currency: selectedCurrency,
            defaultMonthlyBudget: budgetValue,
          }),
        }),
        // PUT /api/budgets/{month}
        fetch(`/api/budgets/${new Date().toISOString().slice(0, 7)}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ monthlyLimit: budgetValue, currency: selectedCurrency }),
        }),
      ]);
      onSettingsChange({ currency: selectedCurrency, defaultMonthlyBudget: budgetValue });
      setSaveStatus("saved");
      addToast("Settings saved successfully");
    } catch {
      setSaveStatus("error");
      addToast("Failed to save settings", "info");
    } finally {
      setIsSaving(false);
      setTimeout(() => setSaveStatus("idle"), 3000);
    }
  };

  const handleCategoryDelete = async (categoryId: string) => {
    try {
      await fetch(`/api/categories/${categoryId}`, { method: "DELETE" });
      onCategoryDelete(categoryId);
      addToast("Category deleted");
    } catch {
      addToast("Failed to delete category", "info");
    }
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Scrim */}
      <div
        className="fixed inset-0 z-40 bg-black/50"
        onClick={onClose}
        aria-hidden="true"
      />

