        aria-modal="true"
        aria-label="Settings"
        className="fixed inset-0 z-50 flex items-center justify-center p-4"
      >
        <div
          className="relative w-full bg-white rounded-2xl shadow-2xl flex flex-col"
          style={{ maxWidth: "420px" }}
          onClick={(e) => e.stopPropagation()}
        >
          {/* Inner padding wrapper */}
          <div className="p-6 flex flex-col gap-0">
            {/* Header */}
            <DialogHeader title="Settings" onClose={onClose} />

            <Separator className="mb-5" />

            {/* Scrollable content */}
            <div className="flex flex-col gap-5 overflow-y-auto max-h-[60vh] pr-0.5">
              {/* Currency Section */}
              <section aria-labelledby="currency-section-title">
                <div className="mb-3">
                  <h3
                    id="currency-section-title"
                    className="text-sm font-semibold text-gray-900"
                  >
                    Default Currency
                  </h3>
                  <p className="text-xs text-gray-500 mt-0.5">
                    Choose the currency used across your dashboard.
                  </p>
                </div>
                <CurrencySelector
                  options={CURRENCY_OPTIONS}
                  selectedCurrency={selectedCurrency}
                  onSelect={handleCurrencyChange}
                  label="Currency"
                />
              </section>

              <Separator />

              {/* Budget Section */}
              <section aria-labelledby="budget-section-title">
                <div className="mb-3">
                  <h3
                    id="budget-section-title"
                    className="text-sm font-semibold text-gray-900"
                  >
                    Monthly Budget Limit
                  </h3>
                  <p className="text-xs text-gray-500 mt-0.5">
                    Set your default spending limit for each month.
                  </p>
                </div>
                <BudgetLimitInput
                  value={budgetValue}
                  onChange={setBudgetValue}
                  currency={selectedCurrency}
                  label="Budget limit"
                />
              </section>

              <Separator />

              {/* Category Manager Section */}
