import React, { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card } from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import {
  ArrowLeft,
  Settings,
  Plus,
  Home,
  PlusCircle,
  BarChart2,
  RefreshCw,
} from "lucide-react";

// ─── Types ────────────────────────────────────────────────────────────────────

type Frequency = "WEEKLY" | "MONTHLY" | "YEARLY";
type EndDateMode = "NEVER" | "ON_DATE";
type PaymentMethod = "CASH" | "CREDIT" | "DEBIT" | "APPLE_PAY" | "BANK";

interface RecurrenceState {
  isRecurring: boolean;
  frequency: Frequency;
  startDate: string;
  endDateMode: EndDateMode;
  endDate: string | undefined;
}

interface ExpenseFormState {
  amount: string;
  categoryId: string;
  date: string;
  paymentMethod: PaymentMethod | "";
  note: string;
  merchantName: string;
}

// ─── FrequencyChip ────────────────────────────────────────────────────────────

interface FrequencyChipProps {
  label: string;
  value: Frequency;
  isSelected: boolean;
  onClick: (value: Frequency) => void;
}

const FrequencyChip: React.FC<FrequencyChipProps> = ({
  label,
  value,
  isSelected,
  onClick,
}) => (
  <button
    type="button"
    onClick={() => onClick(value)}
    className={[
      "px-4 py-1.5 rounded-full border text-sm font-medium transition-all duration-150 min-h-[36px] focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2",
      isSelected
        ? "bg-blue-100 border-blue-600 text-blue-600"
        : "bg-white border-gray-200 text-gray-700 hover:border-gray-300",
    ].join(" ")}
    aria-pressed={isSelected}
  >
    {label}
  </button>
);

// ─── FrequencyChipSelector ────────────────────────────────────────────────────

interface FrequencyChipSelectorProps {
  value: Frequency;
  onChange: (value: Frequency) => void;
}

const FREQUENCY_OPTIONS: { value: Frequency; label: string }[] = [
  { value: "WEEKLY", label: "Weekly" },
  { value: "MONTHLY", label: "Monthly" },
  { value: "YEARLY", label: "Yearly" },
];

const FrequencyChipSelector: React.FC<FrequencyChipSelectorProps> = ({
  value,
  onChange,
}) => (
  <div className="flex gap-2 flex-wrap">
    {FREQUENCY_OPTIONS.map((opt) => (
      <FrequencyChip
        key={opt.value}
        label={opt.label}
        value={opt.value}
        isSelected={value === opt.value}
        onClick={onChange}
      />
    ))}
  </div>
);

// ─── RadioOption ──────────────────────────────────────────────────────────────

interface RadioOptionProps {
  label: string;
  value: string;
  isSelected: boolean;
  onSelect: () => void;
}

const RadioOption: React.FC<RadioOptionProps> = ({
  label,
  value,
  isSelected,
  onSelect,
}) => (
  <button
    type="button"
    onClick={onSelect}
    className="flex items-center gap-2 min-h-[36px] focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-600 focus-visible:ring-offset-2 rounded"
    aria-checked={isSelected}
    role="radio"
  >
    <div
      className={[
        "w-4 h-4 rounded-full border-2 flex items-center justify-center transition-colors duration-150",
        isSelected ? "border-blue-600" : "border-gray-300",
      ].join(" ")}
    >
      {isSelected && (
        <div className="w-2 h-2 rounded-full bg-blue-600" />
      )}
    </div>
    <span className="text-sm text-gray-700">{label}</span>
  </button>
);

// ─── EndDateRow ───────────────────────────────────────────────────────────────

interface EndDateRowProps {
  endDateMode: EndDateMode;
  endDate: string | undefined;
  startDate: string;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
}

const EndDateRow: React.FC<EndDateRowProps> = ({
  endDateMode,
  endDate,
  startDate,
  onEndDateModeChange,
  onEndDateChange,
}) => (
  <div className="flex flex-col gap-3">
    <span className="text-sm text-gray-500 font-medium">End date</span>
    <div className="flex flex-col gap-2" role="radiogroup" aria-label="End date">
      <RadioOption
        label="Never"
        value="NEVER"
        isSelected={endDateMode === "NEVER"}
        onSelect={() => {
          onEndDateModeChange("NEVER");
          onEndDateChange(undefined);
        }}
      />
      <div className="flex flex-col gap-2">
        <RadioOption
          label="On date"
          value="ON_DATE"
          isSelected={endDateMode === "ON_DATE"}
          onSelect={() => onEndDateModeChange("ON_DATE")}
        />
        {endDateMode === "ON_DATE" && (
          <Input
            type="date"
            value={endDate ?? ""}
            min={startDate}
            placeholder="Select end date"
            onChange={(e) =>
              onEndDateChange(e.target.value || undefined)
            }
            className="ml-6 w-auto border-gray-200 rounded-md text-sm focus:border-blue-600 focus:ring-blue-600 px-3 py-2"
          />
        )}
      </div>
    </div>
  </div>
);

// ─── RecurrenceConfigPanel ────────────────────────────────────────────────────

interface RecurrenceConfigPanelProps {
  isVisible: boolean;
  frequency: Frequency;
  endDateMode: EndDateMode;
  endDate: string | undefined;
  startDate: string;
  onFrequencyChange: (value: Frequency) => void;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
}

const RecurrenceConfigPanel: React.FC<RecurrenceConfigPanelProps> = ({
  isVisible,
  frequency,
  endDateMode,
  endDate,
  startDate,
  onFrequencyChange,
  onEndDateModeChange,
  onEndDateChange,
}) => (
  <div
    className={[
      "overflow-hidden transition-all duration-150 ease-in-out",
      isVisible ? "max-h-96 opacity-100" : "max-h-0 opacity-0 pointer-events-none",
    ].join(" ")}
    aria-hidden={!isVisible}
  >
    <div className="flex flex-col gap-4 pt-4">
      {/* Frequency */}
      <div className="flex flex-col gap-2">
        <span className="text-sm text-gray-500 font-medium">Frequency</span>
        <FrequencyChipSelector value={frequency} onChange={onFrequencyChange} />
      </div>

      {/* End Date */}
      <EndDateRow
        endDateMode={endDateMode}
        endDate={endDate}
        startDate={startDate}
        onEndDateModeChange={onEndDateModeChange}
        onEndDateChange={onEndDateChange}
      />
    </div>
  </div>
);

// ─── RecurrenceConfigSection ──────────────────────────────────────────────────

interface RecurrenceConfigSectionProps {
  isRecurring: boolean;
  frequency: Frequency;
  endDateMode: EndDateMode;
  endDate: string | undefined;
  startDate: string;
  onIsRecurringChange: (value: boolean) => void;
  onFrequencyChange: (value: Frequency) => void;
  onEndDateModeChange: (value: EndDateMode) => void;
  onEndDateChange: (value: string | undefined) => void;
  isEditingSeries?: boolean;
}

const RecurrenceConfigSection: React.FC<RecurrenceConfigSectionProps> = ({
  isRecurring,
  frequency,
  endDateMode,
  endDate,
  startDate,
  onIsRecurringChange,
  onFrequencyChange,
  onEndDateModeChange,
  onEndDateChange,
  isEditingSeries = false,
}) => (
  <div className="flex flex-col gap-4">
    {/* Toggle Row */}
    <div className="flex items-center justify-between">
      <div className="flex items-center gap-2">
        <RefreshCw className="w-4 h-4 text-gray-500" />
        <Label
          htmlFor="recurrence-toggle"
          className="text-sm font-semibold text-gray-900 cursor-pointer"
        >
          Make this recurring
        </Label>
        {isEditingSeries && (
          <Badge variant="secondary" className="text-xs">
            Editing series
          </Badge>
        )}
      </div>
      <Switch
        id="recurrence-toggle"
        checked={isRecurring}
        onCheckedChange={onIsRecurringChange}
        className="data-[state=checked]:bg-blue-600"
        style={{ width: 44, height: 24 }}
      />
    </div>

    {/* Config Panel */}
    <RecurrenceConfigPanel
      isVisible={isRecurring}
      frequency={frequency}
      endDateMode={endDateMode}
      endDate={endDate}
      startDate={startDate}
      onFrequencyChange={onFrequencyChange}
      onEndDateModeChange={onEndDateModeChange}
      onEndDateChange={onEndDateChange}
    />
  </div>
);

// ─── Category Chip ────────────────────────────────────────────────────────────

interface CategoryChipProps {
  label: string;
  emoji: string;
  categoryId: string;
  isSelected: boolean;
  onSelect: (id: string) => void;
}

const CategoryChip: React.FC<CategoryChipProps> = ({
